-- Poems batch 349
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3cd31f0a-3bfa-493e-9624-ab210fdefe13','和通判王定國承議遊竹西  其一','鄒浩','宋','宋诗','song-poetry','','[]','流年忽忽又殘春，策杖郊原肯厭頻。',64,'全唐诗/poet.song.69000.json','["流年忽忽又殘春，策杖郊原肯厭頻。", "往古來今何足校，閒花幽草自争新。", "旋開酒蟻成高會，共解名韁作逸民。", "随處怡然真有味，不須千里憶吳蓴。"]'),
('fc28584d-66ff-452c-ab37-7f832c528525','和通判王定國承議遊竹西  其二','鄒浩','宋','宋诗','song-poetry','','[]','一霎狂飈破曉陰，春光極目幾千尋。',64,'全唐诗/poet.song.69000.json','["一霎狂飈破曉陰，春光極目幾千尋。", "會須勝事追蓮社，更約幽人訪竹林。", "渺渺平田涵白水，蕭蕭蒼檜聒清音。", "鄭虔才大猶遭罵，重愧持杯許脱簪。"]'),
('59242217-8a2b-4f76-a408-04a0a01fa7fd','送胡適道秀才東歸','鄒浩','宋','宋诗','song-poetry','','[]','十年星散忽相逢，寂寞蕪城古頖宮。',64,'全唐诗/poet.song.69000.json','["十年星散忽相逢，寂寞蕪城古頖宮。", "一炷澄泥窺祖要，三巵浮蟻對春叢。", "牢芻豈解留天驥，雲路還聞逐塞鴻。", "蓮社故人如見問，爲言涉世百無功。"]'),
('4a954ec6-c3e9-4734-a4f0-5b6e3a765b28','次韻蔡寛夫解元暮春見懷  其一','鄒浩','宋','宋诗','song-poetry','','[]','九十青陽安在哉，臨風搔首謾遲回。',64,'全唐诗/poet.song.69000.json','["九十青陽安在哉，臨風搔首謾遲回。", "春於我輩非無意，詩必先成爲有才。", "拖架酴醾香破麝，翻階芍藥大逾杯。", "病除更約歸愚子，浮蟻猶堪席地開。"]'),
('65e7c867-6102-4058-ad06-935b0e8b3449','次韻蔡寛夫解元暮春見懷  其二','鄒浩','宋','宋诗','song-poetry','','[]','驚紅簌簌點蒼苔，春去黄鸝唤不回。',64,'全唐诗/poet.song.69000.json','["驚紅簌簌點蒼苔，春去黄鸝唤不回。", "九藏脉參知我病，千人筆掃見君才。", "會須磥砢揮談塵，方悟蜿蜒落酒盃。", "命駕相應憐叔夜，笑顔一月幾能開。"]'),
('97dd324d-1524-4c6f-bd79-b3a0fc234d6f','又倒用前韻','鄒浩','宋','宋诗','song-poetry','','[]','休論花草與樓臺，借得江南叠嶂開。',64,'全唐诗/poet.song.69000.json','["休論花草與樓臺，借得江南叠嶂開。", "縱使春歸無覓處，何妨人樂自持盃。", "棋如孫武推多算，詩似顔淵已竭才。", "早晚竹林修故事，更看君筆燦昭回。"]'),
('efdfc38e-ecac-489f-89d3-b2219602c86a','送及之賢良遊錢塘','鄒浩','宋','宋诗','song-poetry','','[]','屏迹人間二十年，下帷搰搰究陳編。',64,'全唐诗/poet.song.69000.json','["屏迹人間二十年，下帷搰搰究陳編。", "新書曾入老商盼，高弟誰如顔子賢。", "策杖青山元有約，揮金紅藥故無緣。", "豈宜便隱雙溪去，優詔行聞墜日邊。"]'),
('30a834f5-7dbe-43c9-92da-48b74511e089','送俞秀老歸維揚','鄒浩','宋','宋诗','song-poetry','','[]','踏雪驅驅原憲履，御風獵獵老萊衣。',64,'全唐诗/poet.song.69000.json','["踏雪驅驅原憲履，御風獵獵老萊衣。", "情投豈比鍾山出，興盡遠同剡水歸。", "煬帝池邊松蔭遠，維摩室內燭光微。", "携笻促席相羊處，應記當年接下機。"]'),
('ddbb57f8-dec7-4753-8be5-cbb8917053d9','雪中呈秀老原道','鄒浩','宋','宋诗','song-poetry','','[]','引舟西上正隆冬，千里隋堤雪翳空。',32,'全唐诗/poet.song.69000.json','["引舟西上正隆冬，千里隋堤雪翳空。", "恰似常年三月尾，柳花凌亂逐東風。"]'),
('51a9ad5f-3791-4ff1-a5e0-3067322840fb','戲孫揚休','鄒浩','宋','宋诗','song-poetry','','[]','耿耿僧坊寄日邊，晚移窮巷避諠闐。',64,'全唐诗/poet.song.69000.json','["耿耿僧坊寄日邊，晚移窮巷避諠闐。", "羮藜不飽同攻苦，秣馬言歸獨處先。", "木葉已随風力遠，霜輪行作璧形圓。", "衣冠返敝文昌路，何似高堂坦腹眠。"]'),
('5728acef-52e1-4b4d-a2eb-0bfb25d59ec6','簡李子温推官','鄒浩','宋','宋诗','song-poetry','','[]','太冲當日號無兄，苗裔于今更絕倫。',64,'全唐诗/poet.song.69000.json','["太冲當日號無兄，苗裔于今更絕倫。", "力究本原書簏富，唾成珠玉錦嚢新。", "龍門久欲攀高躅，鼎角方欣覘後塵。", "借問竹溪餘地否，狂吟聊伴謫仙人。"]'),
('7f607f9b-111f-4d36-a91d-03c579611187','寄周亷彦','鄒浩','宋','宋诗','song-poetry','','[]','不見冰清幾歲周，乘風舉翮恨無由。',64,'全唐诗/poet.song.69000.json','["不見冰清幾歲周，乘風舉翮恨無由。", "瀕江松竹三秋後，隱几情懷萬事休。", "險阻艱難空蟻闘，東西南北正萍浮。", "與君相好如兄弟，莫惜微言爲置郵。"]'),
('b2db574f-701e-47a2-96d0-7ba87c58447f','風起有感','鄒浩','宋','宋诗','song-poetry','','[]','秋來鬰鬰但炎蒸，一夜狂飈駭四鄰。',64,'全唐诗/poet.song.69000.json','["秋來鬰鬰但炎蒸，一夜狂飈駭四鄰。", "斷送冥鴻尤得勢，留連殘暑更無因。", "鏡中鬢髪雖非故，窗下燈檠漸可親。", "勿似安仁兒女態，由看節物重悲辛。"]'),
('f539fd55-183c-4dac-8972-9784cb9bda75','班超','鄒浩','宋','宋诗','song-poetry','','[]','功名從古病難成，况作天西絕域行。',64,'全唐诗/poet.song.69000.json','["功名從古病難成，况作天西絕域行。", "縦有平陵同落落，其如衛候尚營營。", "殺妻吳起終遭逐，上疏鴻卿不免刑。", "定遠獨能逢聖主，千年萬歲藹嘉聲。"]'),
('0aff9fae-f510-4f0e-85cb-20cd54d56715','次韻崔浚明見贈','鄒浩','宋','宋诗','song-poetry','','[]','誰爲冥行作指南，青燈黄卷久間關。',64,'全唐诗/poet.song.69000.json','["誰爲冥行作指南，青燈黄卷久間關。", "逢君豈測陂千頃，許我時窺豹一斑。", "驥足拘攣雖未展，龍鱗騰踏會須攀。", "如何暗把隋珠擲，欲報殷勤只強顔。"]'),
('afa001a5-aa1f-44c8-bd04-22acf05c190f','将至南京簡應介中  其一','鄒浩','宋','宋诗','song-poetry','','[]','得之平陸我登車，不見羣優孟子誅。',32,'全唐诗/poet.song.69000.json','["得之平陸我登車，不見羣優孟子誅。", "只恐鼻端無好質，歸時依舊腹空虚。"]'),
('3c90e929-622d-4d61-b16a-deb251f0daf4','将至南京簡應介中  其二','鄒浩','宋','宋诗','song-poetry','','[]','幾日風塵困馬蹄，忽瞻孤塔獻雲霓。',32,'全唐诗/poet.song.69000.json','["幾日風塵困馬蹄，忽瞻孤塔獻雲霓。", "雙眸已似清江洗，况入亭城見角犀。"]'),
('a2cb0797-13a6-4c6d-8066-d67f1b23246e','将至南京簡應介中  其三','鄒浩','宋','宋诗','song-poetry','','[]','先生不得醉紅裙，何以留連逆旅人。',32,'全唐诗/poet.song.69000.json','["先生不得醉紅裙，何以留連逆旅人。", "故苑池臺老秋色，頖宮講罷走車輪。"]'),
('f4f307e9-9e77-46d0-89d9-dd3f48102145','将至南京簡應介中  其四','鄒浩','宋','宋诗','song-poetry','','[]','直諒多聞許我親，迷途從此遂知津。',32,'全唐诗/poet.song.69000.json','["直諒多聞許我親，迷途從此遂知津。", "社中忽怪爾來進，曾向睢陽見異人。"]'),
('b9e8f4a9-bbb9-44de-bcae-963e4cf5c11e','九月朔夜聞雨','鄒浩','宋','宋诗','song-poetry','','[]','塵濛蛛網暗東齋，設榻君能待我來。',32,'全唐诗/poet.song.69000.json','["塵濛蛛網暗東齋，設榻君能待我來。", "昨夜梧桐有消息，會須急上宋王臺。"]'),
('1a08a459-e35b-482b-b91f-b633e7399bdf','送曹巨源之南都','鄒浩','宋','宋诗','song-poetry','','[]','高堂且置琴中操，駿馬初馳陌上塵。',32,'全唐诗/poet.song.69000.json','["高堂且置琴中操，駿馬初馳陌上塵。", "無限清風與明月，一時分付屬閒人。"]'),
('b0cf08cc-c9f2-45ca-a757-bc72f96be863','輓石適中  其一','鄒浩','宋','宋诗','song-poetry','','[]','剸犀翻羽早稱奇，亨會難遭但布衣。',64,'全唐诗/poet.song.69000.json','["剸犀翻羽早稱奇，亨會難遭但布衣。", "不使牙籌煩伯仲，果然玉樹照庭闈。", "靈臺久已天昭鍳，奏籍初聞子發揮。", "三世簪纓正無恙，如何遽作百年歸。"]'),
('a45ffcb2-d68a-4920-8731-5fc2ca601d6b','輓石適中  其二','鄒浩','宋','宋诗','song-poetry','','[]','南明山下讀書堂，曾許寒生借燭光。',64,'全唐诗/poet.song.69000.json','["南明山下讀書堂，曾許寒生借燭光。", "高義豈殊親骨肉，令人無復念家鄉。", "那知十載天涯别，忽起三泉薤露傷。", "追恨故時携手處，不能執紼助棺傍。"]'),
('e532608a-a162-4563-bfc7-1fa64b9e4995','和朱仲明見贈聞琴','鄒浩','宋','宋诗','song-poetry','','[]','子期骨髪已埃塵，誰謂知音不復生。',64,'全唐诗/poet.song.69000.json','["子期骨髪已埃塵，誰謂知音不復生。", "觸處折楊争屬和，獨君忘味歎遺聲。", "蓽門寒日正多暇，玉麈高談相與清。", "鶴舉魚沉重惆悵，一樽麥酒薦藜羮。"]'),
('d9521d7c-3ac9-4e2b-a7fb-39c5093b7ff5','次韻趙希元憶處州梅花','鄒浩','宋','宋诗','song-poetry','','[]','萬花頭上占天工，得意開時斗未東。',64,'全唐诗/poet.song.69000.json','["萬花頭上占天工，得意開時斗未東。", "破月麝臍來馥郁，横烟玉樹浄玲瓏。", "暖歸故蘃應欺雪，人在他鄉正御風。", "借問殷勤動詩興，忘機争似鹿皮翁。"]'),
('cf3ed257-24be-4828-8eb7-e2a4f1939829','冬至夜夢中作','鄒浩','宋','宋诗','song-poetry','','[]','爐烟颯颯對團蒲，暮去朝來只自如。',32,'全唐诗/poet.song.69000.json','["爐烟颯颯對團蒲，暮去朝來只自如。", "還見人間好時節，羣陰消盡一陽初。"]'),
('63819421-e739-421a-8f31-e476a8500629','雪中簡次蕭求團茶','鄒浩','宋','宋诗','song-poetry','','[]','竹上松間敲玉花，最宜石鼎薦靈芽。',32,'全唐诗/poet.song.69000.json','["竹上松間敲玉花，最宜石鼎薦靈芽。", "蓬門不識蒼龍璧，借問風流宰相家。"]'),
('a1181841-b1a7-47e7-a175-5cfaac2573ce','和晦之見贈聽琴','鄒浩','宋','宋诗','song-poetry','','[]','忌子當年妙五音，曾令按劍革初心。',64,'全唐诗/poet.song.69000.json','["忌子當年妙五音，曾令按劍革初心。", "昭文重愧難成曲，潘岳胡爲繆見尋。", "在昔絲桐嘗棄置，到今山水自高深。", "何當共造無絃處，莫使淵明擅此琴。"]'),
('5c1008a8-bff9-4062-a559-64040e41d74a','再和晦之','鄒浩','宋','宋诗','song-poetry','','[]','舉世欣欣濮上音，絲桐還寄長卿心。',64,'全唐诗/poet.song.69000.json','["舉世欣欣濮上音，絲桐還寄長卿心。", "知君韶濩思千載，勁節松筠挺幾尋。", "萬籟息時霜劍立，一燈明處夜堂深。", "他年振鐸收遺器，豈愧雲和瑟與琴。"]'),
('5e340259-bc79-44df-bf71-3996667a1f8d','倒用前韻','鄒浩','宋','宋诗','song-poetry','','[]','我有一張琴，窮高更極深。',48,'全唐诗/poet.song.69000.json','["我有一張琴，窮高更極深。", "瓠巴那解鼓，師曠杳難尋。", "寂寂三冬夜，悠悠萬古心。", "衣冠徧天宇，誰爲作知音。"]'),
('2c594f60-6864-4f7b-abc0-bf5bf7967c79','次韻道卿寄同僚','鄒浩','宋','宋诗','song-poetry','','[]','從事休嗟我獨勞，何如對雪詠瀌瀌。',64,'全唐诗/poet.song.69000.json','["從事休嗟我獨勞，何如對雪詠瀌瀌。", "聖賢瀲灔冬來美，朋舊綢繆老不凋。", "仇覧初年猶主簿，田單他日竟屠聊。", "上方側席捜遺逸，未易沅湘作大招。"]'),
('f8658338-7dfc-4d65-8768-f7e1252b26e8','督巨源和詩','鄒浩','宋','宋诗','song-poetry','','[]','詩成七步有家風，底事淹留歲已窮。',32,'全唐诗/poet.song.69000.json','["詩成七步有家風，底事淹留歲已窮。", "應笑枚臯太容易，欲令句似長卿工。"]'),
('98496950-8a27-42c2-a718-4152c348ad62','郊行呈彦祖','鄒浩','宋','宋诗','song-poetry','','[]','遲日初乾雪徑沙，等閒聯騎過田家。',32,'全唐诗/poet.song.69000.json','["遲日初乾雪徑沙，等閒聯騎過田家。", "長官標格風塵外，衰草坡前報晚衙。"]'),
('8a287b20-da8d-4665-89b9-45d281fef927','和彦祖寄次蕭','鄒浩','宋','宋诗','song-poetry','','[]','格外参軍事事嘉，竹窗全是子猷家。',32,'全唐诗/poet.song.69000.json','["格外参軍事事嘉，竹窗全是子猷家。", "清狂上客知何處，恨不同燃柏徑槎。"]'),
('89ae65ed-eff4-4b79-bec4-9324d20d9e68','柬理堂','鄒浩','宋','宋诗','song-poetry','','[]','主人生長綺紈中，標致分明儒者同。',64,'全唐诗/poet.song.69000.json','["主人生長綺紈中，標致分明儒者同。", "結構不因窮鼎俎，棲遲聊欲事磨礱。", "血漫霜劍悲王鳳，坐擁雲鬟笑馬融。", "銘府功勳久牢落，會須騰踏振家風。"]'),
('d4ef6642-099c-40db-86af-3fd1ef06c548','戲社正李子温','鄒浩','宋','宋诗','song-poetry','','[]','紅蓮上客有新篇，不見長安驛使傳。',32,'全唐诗/poet.song.69000.json','["紅蓮上客有新篇，不見長安驛使傳。", "寄語持綱社中老，可憐三百青銅錢。"]'),
('ba47c746-aa01-47a8-8b7c-967ae2ccfb66','寄陽先生','鄒浩','宋','宋诗','song-poetry','','[]','長揖公卿不轉頭，五車圖籍指虔州。',64,'全唐诗/poet.song.69000.json','["長揖公卿不轉頭，五車圖籍指虔州。", "屑榆肯使家風墜，謝幣空令世俗羞。", "弄鳳騎龍誠莫及，壊車殺馬恨無由。", "嵩山出處君知否，似與高人作覆輈。"]'),
('2fd5be9f-9447-4e4e-a3a2-3f1a63001a07','發山口堤上','鄒浩','宋','宋诗','song-poetry','','[]','烟籠官柳柳籠堤，風引澄波細細移。',32,'全唐诗/poet.song.69000.json','["烟籠官柳柳籠堤，風引澄波細細移。", "駿馬不知鞍上意，回頭已是獲麟陂。"]'),
('5b2abb6c-f9a9-4f75-b221-660cd21e4d0f','渡汶河','鄒浩','宋','宋诗','song-poetry','','[]','舊來紙上得河名，今日横過徹底清。',32,'全唐诗/poet.song.69000.json','["舊來紙上得河名，今日横過徹底清。", "浚治早經神禹手，若爲汩汩尚西行。"]'),
('aceaa070-f1bd-4c43-9a8c-c59e70509ea5','過中都王彦章廟','鄒浩','宋','宋诗','song-poetry','','[]','一時多難見忠臣，力擁貔貅扞此城。',64,'全唐诗/poet.song.69000.json','["一時多難見忠臣，力擁貔貅扞此城。", "豈爲聖人曾作宰，由來壮志在留名。", "鐡鎗埋没今何處，廟食追崇事若生。", "功業已經華衮贈，只應長伴斗魁明。"]'),
('31b428c4-58b1-41c7-a5d4-b47e96b615e8','慎奪堂','鄒浩','宋','宋诗','song-poetry','','[]','百錬終成繞指柔，何人勁節擬横秋。',64,'全唐诗/poet.song.69000.json','["百錬終成繞指柔，何人勁節擬横秋。", "目前軒冕自來去，堂上詩書嘗講求。", "風度綺疏香漠漠，月移苔砌竹幽幽。", "将軍此意生平事，不似空言不到頭。"]'),
('39f90bc4-70c0-4a10-a765-e8d21dc2824f','閒軒','鄒浩','宋','宋诗','song-poetry','','[]','結構俯危城，公餘杖履輕。',48,'全唐诗/poet.song.69000.json','["結構俯危城，公餘杖履輕。", "事隨塵自遠，心與水長清。", "隱几魚方樂，開窗雨乍晴。", "憧憧渡頭客，誰會此時情。"]'),
('a6d83d9e-3da2-41e3-97f6-3f5b417d9ff2','王憲湖上分韻得荷字','鄒浩','宋','宋诗','song-poetry','','[]','使星明處是天河，習習輕飈生芰荷。',64,'全唐诗/poet.song.69000.json','["使星明處是天河，習習輕飈生芰荷。", "自有芝蘭隨後乘，更容簪履侍鳴珂。", "未甘城鼓促清賞，聊與汀鷗分素波。", "異日定應如此少，雲雷行欲起龍梭。"]'),
('9c44199e-d249-4dc9-9a0b-899ac22187e7','送王憲赴闕','鄒浩','宋','宋诗','song-poetry','','[]','鳳詔傳天北，輶軒指建章。',144,'全唐诗/poet.song.69000.json','["鳳詔傳天北，輶軒指建章。", "既能思賈誼，何患老馮唐。", "况是高門慶，從來美譽彰。", "靈臺懸寶鏡，峻節凛秋霜。", "庖刃誠難敵，黄陂豈易量。", "承家但清白，報國頗施張。", "属部分氂犬，終朝事錦囊。", "收功殊俗士，知已恃明王。", "此去堪前賀，胡爲獨倍傷。", "昔霑淮水潤，今借德星光。", "折柳故多恨，銜環空不忘。", "他年重望履，應已步巖廊。"]'),
('4d296823-599b-4b7a-ab74-72d760d70017','送王裘仲侍親赴闕','鄒浩','宋','宋诗','song-poetry','','[]','置榻初相得，膏車忽起行。',48,'全唐诗/poet.song.69000.json','["置榻初相得，膏車忽起行。", "秋風無限事，麥酒不勝情。", "原憲何曾病，丘明竟有聲。", "從容湖上語，他日看功成。"]'),
('b871c16a-8869-4439-bd26-97fb07df691d','試日懷世美','鄒浩','宋','宋诗','song-poetry','','[]','挾策剛爲泮水行，暖風遲日試諸生。',32,'全唐诗/poet.song.69000.json','["挾策剛爲泮水行，暖風遲日試諸生。", "姚黄魏紫知何許，獨有楊花撲硯輕。"]'),
('6b8cf9e5-8ea3-4e68-9796-5c635f45109e','戲王寛之  其一','鄒浩','宋','宋诗','song-poetry','','[]','晚來聞說醉黄封，絃管欣欣急雨中。',32,'全唐诗/poet.song.69000.json','["晚來聞說醉黄封，絃管欣欣急雨中。", "應笑西鄰少風味，一爐沉水對梧桐。"]'),
('8ab2c354-e242-4ae1-9045-4b78754b95a6','戲王寛之  其二','鄒浩','宋','宋诗','song-poetry','','[]','墨龍翻海幾朝昏，今日晴陰似欲分。',32,'全唐诗/poet.song.69000.json','["墨龍翻海幾朝昏，今日晴陰似欲分。", "不道穀飛多作蠱，猶敎歌扇遏行雲。"]'),
('2f8fe33a-b463-4c78-9493-4316cca2f4a9','次韻世美簡别乘喜雨','鄒浩','宋','宋诗','song-poetry','','[]','一勺龍泉甫到城，滂沱疑是瀉南溟。',64,'全唐诗/poet.song.69000.json','["一勺龍泉甫到城，滂沱疑是瀉南溟。", "棗心正爲斯民赤，菜色寧憂異日青。", "擊壌田家方自得，擲金詩軸已交形。", "病來無復高陽興，宴喜空煩置醁醽。"]'),
('93ce6742-5d9c-4f83-bcfd-10c306681f31','湖上雜詠  其一','鄒浩','宋','宋诗','song-poetry','','[]','荷葉如錢三月時，幅巾藜杖一追随。',32,'全唐诗/poet.song.69000.json','["荷葉如錢三月時，幅巾藜杖一追随。", "爾來勝事知多少，惟有風標公子知。"]'),
('6381ee13-a270-444c-9033-01d6ba350748','湖上雜詠  其二','鄒浩','宋','宋诗','song-poetry','','[]','何處清風作晚凉，解衣相與面滄浪。',32,'全唐诗/poet.song.69000.json','["何處清風作晚凉，解衣相與面滄浪。", "青萍紫芡令人恨，遮却琉璃萬頃光。"]'),
('efad15d5-14ff-49ba-b728-1814d531828f','湖上雜詠  其三','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','華亭標格本青雲，邂逅西湖秋復春。',32,'全唐诗/poet.song.69000.json','["華亭標格本青雲，邂逅西湖秋復春。", "作意一聲君會否，鵷鸞集處是真人。"]'),
('b2162e69-2e6a-4333-b377-79b42ca52a7b','湖上雜詠  其四','鄒浩','宋','宋诗','song-poetry','','[]','疾病經旬厭藥杯，喜君折簡傍湖來。',32,'全唐诗/poet.song.69000.json','["疾病經旬厭藥杯，喜君折簡傍湖來。", "濃雲幾敗乃翁事，賴有南風爲約開。"]'),
('5149322a-34ab-4630-9d6b-63d769686921','湖上雜詠  其五','鄒浩','宋','宋诗','song-poetry','','[]','濱湖一一敞雕欄，自是黄塵不汝閒。',32,'全唐诗/poet.song.69000.json','["濱湖一一敞雕欄，自是黄塵不汝閒。", "今日舒眉寧易得，未應輕作剡溪還。"]'),
('dc70c560-ec8a-4381-96a7-dbadade45701','湖上雜詠  其六','鄒浩','宋','宋诗','song-poetry','','[]','霜蹄檜楫久途窮，暫喜天時人事同。',32,'全唐诗/poet.song.69000.json','["霜蹄檜楫久途窮，暫喜天時人事同。", "濯熱不須三島去，高談落麈自生風。"]'),
('65032585-4021-4dc5-9020-937f89c265f9','湖上雜詠  其七','鄒浩','宋','宋诗','song-poetry','','[]','嵯峨秀色雨晴時，極目城隅更落暉。',32,'全唐诗/poet.song.69000.json','["嵯峨秀色雨晴時，極目城隅更落暉。", "何必鱸魚動秋意，好携雙屐便言歸。"]'),
('20a458d9-74fc-4162-8c04-7f0af5dd75f4','登樓','鄒浩','宋','宋诗','song-poetry','','[]','蓽門真蟻穴，曠快一登樓。',48,'全唐诗/poet.song.69000.json','["蓽門真蟻穴，曠快一登樓。", "天地投雙睫，詩書落九州。", "欄杆元詰曲，日脚更遲留。", "借問同來客，能同此意不。"]'),
('0cd6c654-8c59-4fbe-9d05-6bc7f7fab4dd','聽泉','鄒浩','宋','宋诗','song-poetry','','[]','天中懸日月，激激正鳴泉。',48,'全唐诗/poet.song.69000.json','["天中懸日月，激激正鳴泉。", "洗耳豈吾事，披襟聊石邊。", "焦桐無雜弄，佩玉有羣仙。", "欲識偃溪語，于今蹄與筌。"]'),
('562de674-f8d4-429f-a0d4-afb59f8ff971','呈同社','鄒浩','宋','宋诗','song-poetry','','[]','太史占星久寂寥，高陽烟月但蓬蒿。',64,'全唐诗/poet.song.69000.json','["太史占星久寂寥，高陽烟月但蓬蒿。", "人才豈是非前日，天意端如待我曹。", "萬古衣冠歸指顧，一時天地入風騷。", "他年南北参商去，知有青編破鬰陶。"]'),
('d1d3055f-da47-4dfe-9adc-d7aa150732bf','馬上  其一','鄒浩','宋','宋诗','song-poetry','','[]','策馬戴殘星，郊原破暑清。',24,'全唐诗/poet.song.69000.json','["策馬戴殘星，郊原破暑清。", "人間千萬事，併入一時情。"]'),
('d67e9b4e-2877-4d0f-aad6-9d644780c34c','馬上  其二','鄒浩','宋','宋诗','song-poetry','','[]','晴空雲物不留形，大塊遙呈一點青。',32,'全唐诗/poet.song.69000.json','["晴空雲物不留形，大塊遙呈一點青。", "聞說嵁巖隱君子，何當北面問黄庭。"]'),
('9ca4fa7d-5a38-4d66-b39e-084b6fd7c473','馬上  其三','鄒浩','宋','宋诗','song-poetry','','[]','孤塚如山官路傍，老農指似是前王。',32,'全唐诗/poet.song.69000.json','["孤塚如山官路傍，老農指似是前王。", "可憐烜赫當年計，牧笛樵歌付夕陽。"]'),
('119036bd-155c-4bd9-bf9d-392fc419165f','追凉','鄒浩','宋','宋诗','song-poetry','','[]','三伏流金石，端居若探湯。',48,'全唐诗/poet.song.69000.json','["三伏流金石，端居若探湯。", "古松搖落照，芒履促追凉。", "天壌知誰似，形骸亦自忘。", "何須北窗下，始解到羲皇。"]'),
('6661becb-ac92-488f-8271-4603047009a9','参寥示簡元規詩用其韻寄之  其一','鄒浩','宋','宋诗','song-poetry','','[]','千巖萬壑久青天，一鉢新從淮上旋。',32,'全唐诗/poet.song.69000.json','["千巖萬壑久青天，一鉢新從淮上旋。", "昨日浮雲今止水，誰知庵內更無邊。"]'),
('9bcd506f-c758-4797-babc-1062f2016fea','参寥示簡元規詩用其韻寄之  其二','鄒浩','宋','宋诗','song-poetry','','[]','人間何嚮不鹽梅，江海元從蟻穴開。',32,'全唐诗/poet.song.69000.json','["人間何嚮不鹽梅，江海元從蟻穴開。", "列戟門庭掃蹤跡，只應飛矢亦潛來。"]'),
('cec20351-4f29-472e-a673-6f20d9d5ad94','次韻參寥訪和靖先生故居','鄒浩','宋','宋诗','song-poetry','','[]','湖邊高節與誰鄰，落落寒松往往皴。',32,'全唐诗/poet.song.69000.json','["湖邊高節與誰鄰，落落寒松往往皴。", "就使衡門已塵土，不妨千古自陽春。"]'),
('92a669bf-32c2-4fb5-8bfd-c2a548e59fb6','關氏四照亭','鄒浩','宋','宋诗','song-poetry','','[]','孤亭縹緲枕烟霞，面面江山不用賒。',32,'全唐诗/poet.song.69000.json','["孤亭縹緲枕烟霞，面面江山不用賒。", "何日乘風指星紀，與君携手逐飛鴉。"]'),
('5cd84ce9-51ee-4c12-88c0-50cd9caa9c09','壽星院觀竹','鄒浩','宋','宋诗','song-poetry','','[]','祗園寂寞聳高材，自有鸞凰接翅來。',32,'全唐诗/poet.song.69000.json','["祗園寂寞聳高材，自有鸞凰接翅來。", "回首壷觴散桃李，日斜風動使人哀。"]'),
('9ec9d117-56db-48c4-b197-176c5ae654b3','送王幼安赴舉','鄒浩','宋','宋诗','song-poetry','','[]','幾年幽徑委榛蕪，此去寒生孰子如。',64,'全唐诗/poet.song.69000.json','["幾年幽徑委榛蕪，此去寒生孰子如。", "筆下奔騰三峽水，胸中突兀五車書。", "豈惟麗賦欺弘正，會使清時識仲舒。", "富貴由來皆骨相，門閭高處莫趦趄。"]'),
('d845a7d9-0471-4c63-b494-3d1de913b240','送二弟赴開封舉','鄒浩','宋','宋诗','song-poetry','','[]','古人捧檄緣親喜，况值秋風一鶚天。',32,'全唐诗/poet.song.69000.json','["古人捧檄緣親喜，况值秋風一鶚天。", "相與摶空謝蓬艾，歸來稱壽綵衣鮮。"]'),
('a9edb4dd-06d1-4063-953c-192de2af0d43','椹澗馬鋪壁間有黄元明詩因次其韻','鄒浩','宋','宋诗','song-poetry','','[]','武當在何許，漠漠西南天。',48,'全唐诗/poet.song.69000.json','["武當在何許，漠漠西南天。", "雷電正多事，道途如去年。", "参差揮麈約，妨廢把書眠。", "破我征鞍恨，清詩猶燦然。"]'),
('f187c9e7-7d5a-4d6a-83e6-65edc2e348e9','純孝墓','鄒浩','宋','宋诗','song-poetry','','[]','禽犢何知尚母懷，黄泉相見豈宜哉。',64,'全唐诗/poet.song.69000.json','["禽犢何知尚母懷，黄泉相見豈宜哉。", "向非雅意一杯去，安得迷心中路迴。", "自古功名隨日月，于今廟貌倚崔嵬。", "可憐肉食趨朝者，糞壌紛紛久已灰。"]'),
('4cb9f911-726f-4b7a-a8a2-0798ed125ef8','仙翁山下遇王由正用驛壁二詩之韻見意  其一','鄒浩','宋','宋诗','song-poetry','','[]','物外風期迹已陳，須知日月去來頻。',32,'全唐诗/poet.song.69000.json','["物外風期迹已陳，須知日月去來頻。", "我今欲换神仙骨，還向山前逢異人。"]'),
('59d15efa-8a61-4577-aed7-d2300f459e09','仙翁山下遇王由正用驛壁二詩之韻見意  其二','鄒浩','宋','宋诗','song-poetry','','[]','烟雨冥冥不肯晴，無因飛步數峰青。',32,'全唐诗/poet.song.69000.json','["烟雨冥冥不肯晴，無因飛步數峰青。", "朅來山下傾談麈，全似江邊語醉醒。"]'),
('d2f14ac9-70ae-47d0-a852-847e11d89a59','阻雨呈由正  其一','鄒浩','宋','宋诗','song-poetry','','[]','秋風吹雨入疏櫺，永夜漫漫雙眼明。',32,'全唐诗/poet.song.69000.json','["秋風吹雨入疏櫺，永夜漫漫雙眼明。", "借問泥塗困行李，何如南畝念西成。"]'),
('f8a57896-1622-421b-baf6-ed0a41f570eb','阻雨呈由正  其二','鄒浩','宋','宋诗','song-poetry','','[]','煉石曾聞補就天，如何滛雨尚綿綿。',32,'全唐诗/poet.song.69000.json','["煉石曾聞補就天，如何滛雨尚綿綿。", "只應知我班荆意，欲使從容夫子前。"]'),
('0b823b0a-5540-4862-828f-7b0154f2bb84','過仙翁山','鄒浩','宋','宋诗','song-poetry','','[]','羣山環拱一山青，曾駐仙翁竟得名。',32,'全唐诗/poet.song.69000.json','["羣山環拱一山青，曾駐仙翁竟得名。", "前日授書非我事，旄頭不耀正休兵。"]'),
('71ae1c89-fc9b-46e8-a126-9f63ac50f4d7','别由正','鄒浩','宋','宋诗','song-poetry','','[]','許汝相望無百里，政聲文譽益驚人。',64,'全唐诗/poet.song.69000.json','["許汝相望無百里，政聲文譽益驚人。", "豈知今日俱長路，重慰平生仰後塵。", "雲澹京山黄鵠舉，風回漢水白鷗馴。", "歸來有約天從否，凖擬冥行細問津。"]'),
('f63fd234-1a9f-4bb0-90f8-803f4a636e0a','穣東驛壁間有詩因次其韻','鄒浩','宋','宋诗','song-poetry','','[]','箠轡驅馳長眼花，更堪風雨作泥沙。',32,'全唐诗/poet.song.69000.json','["箠轡驅馳長眼花，更堪風雨作泥沙。", "郵亭准擬一醉倒，白酒黄雞無處賒。"]'),
('06057d54-f26a-464b-b5c8-342f5ef25495','林堠驛壁間有詩因用其韻','鄒浩','宋','宋诗','song-poetry','','[]','日轉山亭寂寂，夢迷蝴蝶雙雙。',28,'全唐诗/poet.song.69000.json','["日轉山亭寂寂，夢迷蝴蝶雙雙。", "何獨淵明寄傲，吾今亦是南窗。"]'),
('fd51a219-b283-446c-a661-59d3b8c336e1','早行','鄒浩','宋','宋诗','song-poetry','','[]','朝來由氣鋭，前程入馬蹄。',120,'全唐诗/poet.song.69000.json','["朝來由氣鋭，前程入馬蹄。", "天形隨月見，斗柄傍人低。", "路轉纔縈白，沙平豈辨泥。", "露零欺鬢髪，犬吠隔蒿藜。", "恍惚南柯夢，參差逢氏迷。", "比經十里堠，始報一聲雞。", "似脱關中日，如趨圯下蹊。", "脩真空有術，習懶信無梯。", "行李幾時北，武當猶在西。", "誰知貴公子，角枕正清閨。"]'),
('e0083b23-2fc1-497b-9d6a-616259bfb68e','順陽東山下小池','鄒浩','宋','宋诗','song-poetry','','[]','行盡江山知幾重，山前池沼尚殘紅。',32,'全唐诗/poet.song.69000.json','["行盡江山知幾重，山前池沼尚殘紅。", "塵埃滿眼欣相見，駐馬垂楊夾岸風。"]'),
('c7659ac5-a877-450f-abe8-ddeb5378661d','将到均州','鄒浩','宋','宋诗','song-poetry','','[]','武當孤壘插天西，一見都忘渇與饑。',32,'全唐诗/poet.song.69000.json','["武當孤壘插天西，一見都忘渇與饑。", "倦客惟貪早休歇，不知匏繫未成歸。"]'),
('54d9fd60-30c2-4bce-b344-bf162c8397eb','次韻宇文伯脩題清溪驛梅花','鄒浩','宋','宋诗','song-poetry','','[]','驥尾曾容躡後塵，柳花榆莢古河濱。',64,'全唐诗/poet.song.69000.json','["驥尾曾容躡後塵，柳花榆莢古河濱。", "天衢事業已騰世，山驛詩篇知幾春。", "梅蕚故應如異日，風騷仍得慰幽人。", "須知猶是枯株在，早晚吹嘘近紫宸。"]'),
('53af0942-e235-4153-a54b-7e2a2f6c380b','入試院呈同事章顯父推官及監試柴承之朝奉','鄒浩','宋','宋诗','song-poetry','','[]','漢江洶洶不知休，江上譙門鼓角秋。',64,'全唐诗/poet.song.69000.json','["漢江洶洶不知休，江上譙門鼓角秋。", "匹馬崎嶇随國事，同心邂逅得儒流。", "何妨蟋蟀床頭急，况是芭蕉雨脚收。", "别乘端容共蕭散，從今相與傲浮丘。"]'),
('004a34f7-3cd7-4732-a8d3-b4f581dc3fc3','午枕覺懷世美','鄒浩','宋','宋诗','song-poetry','','[]','睡鄉天地肅秋風，日日欣随宰我蹤。',32,'全唐诗/poet.song.69000.json','["睡鄉天地肅秋風，日日欣随宰我蹤。", "靖節有人須命駕，道途何事不相逢。"]'),
('4eb045ae-7b1c-46f1-b9e6-3cfe165d11a4','李元禮墓','鄒浩','宋','宋诗','song-poetry','','[]','幾年模楷掲天中，四海衣冠盡影從。',64,'全唐诗/poet.song.69000.json','["幾年模楷掲天中，四海衣冠盡影從。", "必待名人裁受謁，遂令當世比登龍。", "求通謾負孔融志，執御難追荀爽蹤。", "回首高門正如市，悲風獵獵起長松。"]'),
('a9a251b6-ce27-4d8e-b5d6-c1b5e68017a6','泛漢江  其一','鄒浩','宋','宋诗','song-poetry','','[]','漢江衮衮接天流，百里舟行一轉眸。',64,'全唐诗/poet.song.69000.json','["漢江衮衮接天流，百里舟行一轉眸。", "白浪激風鳴戰鼓，青山迎棹走長虬。", "均陽已斷南柯夢，鄼上還驚宋玉秋。", "南望祖塋能幾驛，王程不得下荆州。"]'),
('e6d91fe7-0e2c-4a5c-8fd8-badaee0c066c','泛漢江  其二','鄒浩','宋','宋诗','song-poetry','','[]','誰家游女戲江濱，纔見舟來競歛身。',32,'全唐诗/poet.song.69000.json','["誰家游女戲江濱，纔見舟來競歛身。", "須信文王風化遠，至今猶自被行人。"]'),
('2cf43773-4e4a-4bd0-8e2e-8537f48935df','泛漢江  其三','鄒浩','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山束長江激箭奔，扁舟衝破白鷗羣。',32,'全唐诗/poet.song.69000.json','["山束長江激箭奔，扁舟衝破白鷗羣。", "故人正在笙篁裏，一枕灘聲誰與分。"]'),
('c7b60ee0-51b8-480c-b447-7d64f68b1076','懷襄陽','鄒浩','宋','宋诗','song-poetry','','[]','寄跡襄陽北，無因弔古人。',48,'全唐诗/poet.song.69000.json','["寄跡襄陽北，無因弔古人。", "卧龍應索寞，堕淚想鱗皴。", "不作龐公客，空回徐庶身。", "風流終自若，他日引車輪。"]'),
('cffa9393-cfed-4c84-a10d-1ba00ea04857','次韻顯父睡起偶成','鄒浩','宋','宋诗','song-poetry','','[]','杜門無復轍聲來，一日剛腸欲九廽。',64,'全唐诗/poet.song.69000.json','["杜門無復轍聲來，一日剛腸欲九廽。", "消遣但能眠白晝，較量猶勝走黄埃。", "霜風却暑通歸路，籬菊要人薦壽杯。", "同我此心君最切，更将幽思託清才。"]'),
('5ed63729-6586-4920-b8e7-230303a018f4','留别顯父且約相見于南陽','鄒浩','宋','宋诗','song-poetry','','[]','風帆催我上輕舟，不得追陪自在遊。',32,'全唐诗/poet.song.69000.json','["風帆催我上輕舟，不得追陪自在遊。", "山路馬蹄新雨霽，早來携手百花洲。"]'),
('fec0dbb9-94d4-440f-a647-8a804cd116e1','次韻監試喜引試有日','鄒浩','宋','宋诗','song-poetry','','[]','朅來凡韻續高張，鳬鶴居然分短長。',64,'全唐诗/poet.song.69000.json','["朅來凡韻續高張，鳬鶴居然分短長。", "鳴鼓未窺才氣勇，懸河先飫古今詳。", "三秋欲半月方好，萬事兼忘心更凉。", "只願真賢起山國，異時端委贊垂裳。"]'),
('217e5711-2b60-40e6-8aac-7b4df8b9d528','湖上聯句','鄒浩','宋','宋诗','song-poetry','','[]','遙岑艤舟見，野思過橋生。',24,'全唐诗/poet.song.69000.json','["遙岑艤舟見，野思過橋生。", "興盡回蘭棹，歸鞍月正明。"]'),
('8e4e0691-163e-4d98-8efb-d1d2065a267f','湖上  其一','鄒浩','宋','宋诗','song-poetry','','[]','等閒來棹釣魚船，鷗鷺相忘亦自然。',32,'全唐诗/poet.song.69000.json','["等閒來棹釣魚船，鷗鷺相忘亦自然。", "多事脩鱗躍波底，一齊鳴翼上青天。"]'),
('5f6c7b37-c956-4160-a3cd-f11b975206c9','湖上  其二','鄒浩','宋','宋诗','song-poetry','','[]','烟含夜色迷修竹，鴈带秋聲落晚沙。',32,'全唐诗/poet.song.69000.json','["烟含夜色迷修竹，鴈带秋聲落晚沙。", "不是胸中有雲夢，只應悽惻滿天涯。"]'),
('2ecc69e1-cd0e-455a-8c0d-0f5188898bca','送薛唐卿赴省試','鄒浩','宋','宋诗','song-poetry','','[]','河東文物久塵埃，之子亭亭鬰有材。',64,'全唐诗/poet.song.69000.json','["河東文物久塵埃，之子亭亭鬰有材。", "已見中天鳴鸑鷟，不應環堵更蒿萊。", "綠衣春色知誰共，青簡風流自此開。", "傾耳西州人快意，玉階曾上直言來。"]'),
('a9345248-b03e-4273-a0be-830087835589','送周茂宗學正赴省試','鄒浩','宋','宋诗','song-poetry','','[]','草衣藿食寄塵編，凛凛聲名玉几前。',64,'全唐诗/poet.song.69000.json','["草衣藿食寄塵編，凛凛聲名玉几前。", "命數曲留成大器，鄉書重上欲華顛。", "一鳴竟與凡禽遠，三獻方知美璞全。", "二十餘年古人志，從今攄發到青天。"]'),
('390b9583-22cc-42d8-8317-0994b45c8936','送周天和學諭以次十一人赴省試','鄒浩','宋','宋诗','song-poetry','','[]','日月交光萬國同，羣英無復嘆途窮。',64,'全唐诗/poet.song.69000.json','["日月交光萬國同，羣英無復嘆途窮。", "長松竟拔徂徠雪，駿馬争馳冀北風。", "黄卷論心窺聖域，青雲携手赴王功。", "歸來協氣充閭里，好是邦人識頖宮。"]'),
('6e4c4e66-c49a-41ae-aa3c-359d979b9718','元夕席上食柑子','鄒浩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','契闊吳門千里，棲遲潁水三年。',28,'全唐诗/poet.song.69000.json','["契闊吳門千里，棲遲潁水三年。", "臈炬光中氣味，洞庭波上風煙。"]'),
('f7374c21-e3b8-440d-898c-e798fa02aa96','簡仲孺','鄒浩','宋','宋诗','song-poetry','','[]','曉來城府春融怡，博陵先生還自西。',32,'全唐诗/poet.song.69000.json','["曉來城府春融怡，博陵先生還自西。", "天時人事已如此，不應璧月空雲霓。"]'),
('c12a81c5-44a2-4e31-8d0d-8400f1b7466f','次韻酬德符湖上春色','鄒浩','宋','宋诗','song-poetry','','[]','乘風曾到水晶宮，春色椎輪日力中。',32,'全唐诗/poet.song.69000.json','["乘風曾到水晶宮，春色椎輪日力中。", "幾處梅花傲殘雪，不隨桃李事輕紅。"]'),
('e9e07e8c-7e0e-4f38-ad01-39d00e30db14','戲史述古多問相','鄒浩','宋','宋诗','song-poetry','','[]','窮當益堅愧枉道，心不勝術思齊賢。',32,'全唐诗/poet.song.69000.json','["窮當益堅愧枉道，心不勝術思齊賢。", "如何東里史夫子，骨相勤勤揮酒錢。"]'),
('f67a63fe-b1d1-4ba7-a295-0ac6fcc701f6','世美約仲孺述之同泛清潩登樓待月分得樓字  其一','鄒浩','宋','宋诗','song-poetry','','[]','風塵作惡敗清遊，杖履無光久自羞。',64,'全唐诗/poet.song.69000.json','["風塵作惡敗清遊，杖履無光久自羞。", "約我晚來尋小艇，與君愁破對高樓。", "山分遠翠凝衣重，月借澄輝撲水浮。", "不是嚴城不容與，徑随雙鶴宿滄州。"]'),
('d44a94a8-57e7-4034-9947-28f6dc63c773','世美約仲孺述之同泛清潩登樓待月分得樓字  其二','鄒浩','宋','宋诗','song-poetry','','[]','采石仙人放小舟，荆州老子上南樓。',32,'全唐诗/poet.song.69000.json','["采石仙人放小舟，荆州老子上南樓。", "平生風度歸遐想，今日還逢第一流。"]'),
('37e6654e-fa9d-485d-993b-c8862733eb69','與仲孺述之世美東禪納凉校韓文世美以韓公召先去  其一','鄒浩','宋','宋诗','song-poetry','','[]','清風多處是精廬，飯罷俱來校異書。',32,'全唐诗/poet.song.69000.json','["清風多處是精廬，飯罷俱來校異書。", "車馬焉能落吾事，未斜桐影且安居。"]'),
('16b9bcb3-bea2-4968-b3df-61c63ac98989','與仲孺述之世美東禪納凉校韓文世美以韓公召先去  其二','鄒浩','宋','宋诗','song-poetry','','[]','紅衣青簡竟多岐，無復尋盟作四夔。',32,'全唐诗/poet.song.69000.json','["紅衣青簡竟多岐，無復尋盟作四夔。", "同見韓公不同趣，城南城北囀黄鸝。"]'),
('493a7520-90d8-4012-9743-da08f8cc4e0c','送杜謷居方城','鄒浩','宋','宋诗','song-poetry','','[]','迺翁鬢髪已秋霜，藥裹仍聞滿北堂。',64,'全唐诗/poet.song.69000.json','["迺翁鬢髪已秋霜，藥裹仍聞滿北堂。", "貧欲釡魚勤子職，分甘足蠒寄他鄉。", "山前黄石空猿鶴，溪上青編屹棟梁。", "想見使親忘我後，借書尋舊日徜徉。"]'),
('2b79bb1b-e791-48ab-8846-22c999582ff4','曉雨枕上有作','鄒浩','宋','宋诗','song-poetry','','[]','震霆幾日動天閽，河漢朝來竟一翻。',64,'全唐诗/poet.song.69000.json','["震霆幾日動天閽，河漢朝來竟一翻。", "頓覺炎歊辭枕簟，只應爽氣滿乾坤。", "雞窗豈但開千卷，雲稼懸知亘九原。", "北事平生最關慮，從今得意遂忘言。"]'),
('3fe551e0-aaeb-4d33-8eec-543b879e7c1e','次韻德符曾家池上四詩  其一','鄒浩','宋','宋诗','song-poetry','','[]','凉雨霏霏肅徑沙，芰荷無數擁烟霞。',32,'全唐诗/poet.song.69000.json','["凉雨霏霏肅徑沙，芰荷無數擁烟霞。", "幽人不受市朝挽，竟日池邊藉落花。"]'),
('9a87af53-768c-47df-825a-89824775563f','次韻德符曾家池上四詩  其二','鄒浩','宋','宋诗','song-poetry','','[]','平生一語事誠忘，鳬鶴不知誰短長。',32,'全唐诗/poet.song.69000.json','["平生一語事誠忘，鳬鶴不知誰短長。", "跬步秋園作殊域，從他白眼嘲帬襠。"]'),
('3ebd4006-8136-4518-beb8-a00671cb40a5','次韻德符曾家池上四詩  其三','鄒浩','宋','宋诗','song-poetry','','[]','庭前葉下風蕭蕭，暑氣不敢憑虚驕。',32,'全唐诗/poet.song.69000.json','["庭前葉下風蕭蕭，暑氣不敢憑虚驕。", "青天碧水與君共，他日謫仙宮錦袍。"]'),
('faa230a6-0f13-4e85-b330-551ee5376170','次韻德符曾家池上四詩  其四','鄒浩','宋','宋诗','song-poetry','','[]','真樂油油波底鱗，相從欵欵波上萍。',32,'全唐诗/poet.song.69000.json','["真樂油油波底鱗，相從欵欵波上萍。", "雁奴燕子社前後，玉樹鮮風吹晚庭。"]'),
('cd9883c1-d4a7-4738-9abc-a27fd9619120','世美寓展江作此簡之  其一','鄒浩','宋','宋诗','song-poetry','','[]','白鷺飛時天宇清，君家琴瑟寄江濱。',32,'全唐诗/poet.song.69000.json','["白鷺飛時天宇清，君家琴瑟寄江濱。", "不愁折柳無多日，且喜荷花有主人。"]'),
('8a3d95d0-0075-459d-8257-31e3ee3cbb3f','世美寓展江作此簡之  其二','鄒浩','宋','宋诗','song-poetry','','[]','翩翩儉府幾西風，更擬真遊渌水中。',32,'全唐诗/poet.song.69000.json','["翩翩儉府幾西風，更擬真遊渌水中。", "秋晚倚欄應記得，全家看盡渚蓮紅。"]'),
('2dd47441-f55d-4fb8-80cd-070bdb595eb6','洗竹','鄒浩','宋','宋诗','song-poetry','','[]','欣欣花草不關心，絕倒宮庭一畝陰。',64,'全唐诗/poet.song.69000.json','["欣欣花草不關心，絕倒宮庭一畝陰。", "夏籜隕風裁幾日，秋筠要月擬千尋。", "携持斤斧從他怪，繚繞欄干著意深。", "全是吳中舊瀟灑，過門應喜伴龍吟。"]'),
('370f56b4-8fe7-4ba4-a774-3384b8051864','寄裘仲','鄒浩','宋','宋诗','song-poetry','','[]','幾度秋陂老芰荷，蓬門不見雁來過。',64,'全唐诗/poet.song.69000.json','["幾度秋陂老芰荷，蓬門不見雁來過。", "照人眉字今何似，得意詩篇日更多。", "事逐風雲空白馬，功隨山嶽尚黄河。", "無因雙眼陪君子，暝立西樓一楚歌。"]'),
('2e3f7b25-1470-4e7d-9b05-9d004e0f68c5','南堂八絕句  其一','鄒浩','宋','宋诗','song-poetry','','[]','聖賢祠畢諸生散，曳履斜陽哦杜詩。',32,'全唐诗/poet.song.69000.json','["聖賢祠畢諸生散，曳履斜陽哦杜詩。", "幽鳥飛來似相好，竹枝深處語多時。"]'),
('794174e6-0c66-4538-a48e-341f0f3f1291','南堂八絕句  其二','鄒浩','宋','宋诗','song-poetry','','[]','桐竹交陰覆廣庭，秋風時與葉争鳴。',32,'全唐诗/poet.song.69000.json','["桐竹交陰覆廣庭，秋風時與葉争鳴。", "可憐一曲明君操，不似高山流水聲。"]'),
('210bbba8-77cc-409e-b266-acdef08c0585','南堂八絕句  其三','鄒浩','宋','宋诗','song-poetry','','[]','長廊耿耿注西東，鼓腹循環返照中。',32,'全唐诗/poet.song.69000.json','["長廊耿耿注西東，鼓腹循環返照中。", "更擬将心寄明月，無端雲葉上晴空。"]'),
('ececfbca-f8f0-440e-8721-4883f08e0a5c','南堂八絕句  其四','鄒浩','宋','宋诗','song-poetry','','[]','盆水如池傍竹根，早期功業在龍孫。',32,'全唐诗/poet.song.69000.json','["盆水如池傍竹根，早期功業在龍孫。", "爾來取飲多奇羽，更得南堂幽趣繁。"]'),
('4afe4ba3-d98a-4eb5-8246-7551a4a33b82','南堂八絕句  其五','鄒浩','宋','宋诗','song-poetry','','[]','窶人何緣有遺啄，一飲聊分秋水清。',32,'全唐诗/poet.song.69000.json','["窶人何緣有遺啄，一飲聊分秋水清。", "貪泉盗泉滿機械，鳥鵲故應知此情。"]'),
('d777d5da-3f2f-4b36-8c02-c3fe8e3317fe','南堂八絕句  其六','鄒浩','宋','宋诗','song-poetry','','[]','風搖疏影落清漪，汎汎魚兒趁晚嬉。',32,'全唐诗/poet.song.69000.json','["風搖疏影落清漪，汎汎魚兒趁晚嬉。", "不是來禽驚不去，窗前從此使人疑。"]'),
('4ae5c697-323c-47b3-b094-d27c1d3fcb0e','南堂八絕句  其七','鄒浩','宋','宋诗','song-poetry','','[]','倦來搘策立階除，深喜官居似隱居。',32,'全唐诗/poet.song.69000.json','["倦來搘策立階除，深喜官居似隱居。", "寒日西流報衙鼓，紛紛清影上圗書。"]'),
('de750c76-37b3-434f-863d-f1403ec8b790','南堂八絕句  其八','鄒浩','宋','宋诗','song-poetry','','[]','綠竹不應忘舊好，黄花還擬結新交。',32,'全唐诗/poet.song.69000.json','["綠竹不應忘舊好，黄花還擬結新交。", "欄邊醉倒非吾事，只愛金英嫓玉梢。"]'),
('b0d3ba0a-6cf7-4641-9fc1-e9093c8411e5','送田承君隱大留山','鄒浩','宋','宋诗','song-poetry','','[]','田郎風節薄清旻，耻踏冥冥車馬塵。',64,'全唐诗/poet.song.69000.json','["田郎風節薄清旻，耻踏冥冥車馬塵。", "遠業不應忘魏闕，高人聊喜得東鄰。", "鹿門隱去曾携子，綿上歸來亦侍親。", "早晚雲飛雨天下，勒移何愧北山神。"]'),
('a6846e46-2023-417f-849d-81119c0ff705','湖上訪世美不遇','鄒浩','宋','宋诗','song-poetry','','[]','夜雨朝晴似蜀天，湖光山色故人邊。',32,'全唐诗/poet.song.69000.json','["夜雨朝晴似蜀天，湖光山色故人邊。", "琵琶不許陪犀麈，聽水亭東一黯然。"]'),
('3a68f742-c92d-414f-a80a-5dbf60389084','月下懷同盟  其一','鄒浩','宋','宋诗','song-poetry','','[]','常時二妙過晴窗，丙夜猶同秋月光。',32,'全唐诗/poet.song.69000.json','["常時二妙過晴窗，丙夜猶同秋月光。", "不分城扉日多事，天南天北又参商。"]'),
('7161489e-0abd-4e52-ac67-464ddc73d342','月下懷同盟  其二','鄒浩','宋','宋诗','song-poetry','','[]','碧天如水駐冰輪，粲粲裁餘一兩星。',32,'全唐诗/poet.song.69000.json','["碧天如水駐冰輪，粲粲裁餘一兩星。", "想見牆東病居士，廢書捐枕步中庭。"]'),
('6bdd8a3e-626a-4831-8590-479e5ce68645','月下懷同盟  其三','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晚雲携雨入陘山，月到西湖萬象閒。',32,'全唐诗/poet.song.69000.json','["晚雲携雨入陘山，月到西湖萬象閒。", "公子歸來泛家宅，只應詩思落人間。"]'),
('4382e256-e3b2-40ab-96d1-a06780c9ffd5','月下懷同盟  其四','鄒浩','宋','宋诗','song-poetry','','[]','睡覺譙門已轉更，小童徐報月重明。',64,'全唐诗/poet.song.69000.json','["睡覺譙門已轉更，小童徐報月重明。", "攬衣起與妻孥共，矯首惟聞鳥鵲驚。", "瀕水杯盤無俗物，隔墻巾屨有真情。", "相從竟日今相望，四者由來不易并。"]'),
('79700a10-b216-420c-8de9-abc03fbd7662','月下懷同盟  其五','鄒浩','宋','宋诗','song-poetry','','[]','一經三五一虧盈，此夕胡然分外明。',64,'全唐诗/poet.song.69000.json','["一經三五一虧盈，此夕胡然分外明。", "金令中分寒暑候，蟾輝獨占古今清。", "樽罍自是常年事，天地何難永夜晴。", "寄語風雲莫無賴，萬方矯首此時情。"]'),
('b2ca537f-e331-47df-97ac-1bba01ed25f3','次韻王彦温邂逅登舟','鄒浩','宋','宋诗','song-poetry','','[]','過盡西城百丈堤，村村雞犬午聲齊。',32,'全唐诗/poet.song.69000.json','["過盡西城百丈堤，村村雞犬午聲齊。", "風前匹馬不回首，知有幽人在竹溪。"]'),
('a0df8b35-b327-4ddd-9d8e-f25519018b81','訪仲弓','鄒浩','宋','宋诗','song-poetry','','[]','凉雨吹絲絡晚空，朅來秋興與君同。',32,'全唐诗/poet.song.69000.json','["凉雨吹絲絡晚空，朅來秋興與君同。", "巽亭鵠立雲霓上，未許山川落眼中。"]'),
('20dead1e-9c13-47d1-aa4c-c5a670a58364','中秋日泛湖雜詩  其一','鄒浩','宋','宋诗','song-poetry','','[]','高柳蘢蓯暝晚烟，拍堤秋水遠連天。',32,'全唐诗/poet.song.69000.json','["高柳蘢蓯暝晚烟，拍堤秋水遠連天。", "恨君不見桃花盛，十里紅波送酒船。"]'),
('25715401-8747-4f49-84bd-e12ff650987e','中秋日泛湖雜詩  其二','鄒浩','宋','宋诗','song-poetry','','[]','賞心自與月俱圓，今夜晴陰莫問天。',32,'全唐诗/poet.song.69000.json','["賞心自與月俱圓，今夜晴陰莫問天。", "秋色向人方有意，不逢星女不迴船。"]'),
('bc40f88d-ffca-4c53-ace5-c26c38c6ddae','中秋日泛湖雜詩  其三','鄒浩','宋','宋诗','song-poetry','','[]','望中白鳥點青烟，秋意交情兩薄天。',32,'全唐诗/poet.song.69000.json','["望中白鳥點青烟，秋意交情兩薄天。", "仙李騎鯨不知處，高吟誰繼岳陽船。"]'),
('25f8d779-91c9-44ec-824c-2243c11dd89c','中秋日泛湖雜詩  其四','鄒浩','宋','宋诗','song-poetry','','[]','晚風知我興飄然，力戰浮雲露遠天。',32,'全唐诗/poet.song.69000.json','["晚風知我興飄然，力戰浮雲露遠天。", "判却明朝官長罵，與君徹曉引金船。"]'),
('3b6375a5-6ed4-4b76-b7f1-b7b0e0e85674','中秋日泛湖雜詩  其五','鄒浩','宋','宋诗','song-poetry','','[]','從來筆力掃千軍，卷舌無聲豈不能。',32,'全唐诗/poet.song.69000.json','["從來筆力掃千軍，卷舌無聲豈不能。", "欲似元戎耀奇策，故令偏帥作先登。"]'),
('8e64534a-cc22-4681-a664-348255258131','中秋日泛湖雜詩  其六','鄒浩','宋','宋诗','song-poetry','','[]','荷花影裏逢君輩，棋子聲中愧我能。',32,'全唐诗/poet.song.69000.json','["荷花影裏逢君輩，棋子聲中愧我能。", "擬上高樓對殷浩，更憑長嘯引孫登。"]'),
('80563f5d-922c-40be-8285-3b2d89f67108','中秋日泛湖雜詩  其七','鄒浩','宋','宋诗','song-poetry','','[]','胡牀兀兀坐忘情，似向曹溪見老能。',32,'全唐诗/poet.song.69000.json','["胡牀兀兀坐忘情，似向曹溪見老能。", "若處樵歌好消息，妙高峰上許人登。"]'),
('cb7932c9-b4f6-4524-b08a-4db7628dab59','中秋日泛湖雜詩  其八','鄒浩','宋','宋诗','song-poetry','','[]','路轉城隅更可憐，盡橋横處響潺湲。',32,'全唐诗/poet.song.69000.json','["路轉城隅更可憐，盡橋横處響潺湲。", "篙人不會凭舟意，徑逐西風過水源。"]'),
('23d75da4-2d3b-47aa-a08e-587c42f4075f','中秋日泛湖雜詩  其九','鄒浩','宋','宋诗','song-poetry','','[]','靈隱山前獨子知，清溪渾似潁川湄。',32,'全唐诗/poet.song.69000.json','["靈隱山前獨子知，清溪渾似潁川湄。", "何當把手東南去，却向山前話此時。"]'),
('3f030ff0-1928-4b46-ad06-9b7bcad4d823','中秋日泛湖雜詩  其一○','鄒浩','宋','宋诗','song-poetry','','[]','士龍擁鼻時一笑，司馬忘機只言好。',32,'全唐诗/poet.song.69000.json','["士龍擁鼻時一笑，司馬忘機只言好。", "野人浪測君子心，應爲狂吟分枯槁。"]'),
('0431ff85-da71-4233-b96e-d9ba1c15be66','中秋日泛湖雜詩  其一一','鄒浩','宋','宋诗','song-poetry','','[]','舟去舟還秋半時，孤花細草雨霏霏。',32,'全唐诗/poet.song.69000.json','["舟去舟還秋半時，孤花細草雨霏霏。", "怪來詩句無清思，不見沙頭雙鶴飛。"]'),
('3ca02c46-ffce-4073-abb7-5717e977410b','中秋日泛湖雜詩  其一二','鄒浩','宋','宋诗','song-poetry','','[]','每将冲韻擬琴高，不值飛鳴心更勞。',32,'全唐诗/poet.song.69000.json','["每将冲韻擬琴高，不值飛鳴心更勞。", "邂逅詩成似招隱，稲花深處舉霜毛。"]'),
('4a75aaf3-1ff1-42e3-9391-04760bacd544','中秋日泛湖雜詩  其一三','鄒浩','宋','宋诗','song-poetry','','[]','誰家脩竹拂雲電，影带晴光漾渌漪。',32,'全唐诗/poet.song.69000.json','["誰家脩竹拂雲電，影带晴光漾渌漪。", "風日無情促歸楫，不教閒客共題詩。"]'),
('64482972-d9bf-400d-b583-7825eb9a7c1a','中秋日泛湖雜詩  其一四','鄒浩','宋','宋诗','song-poetry','','[]','早覺鳴鳩啼木杪，晚來晴日破天顔。',32,'全唐诗/poet.song.69000.json','["早覺鳴鳩啼木杪，晚來晴日破天顔。", "不愁今夜雲遮月，且凭闌干一看山。"]'),
('ed161fff-4b9d-4fbe-bb09-a5bdf1d7c282','中秋日泛湖雜詩  其一五','鄒浩','宋','宋诗','song-poetry','','[]','乍疑絕岸行飛鶩，還誤遊魚出聽琴。',32,'全唐诗/poet.song.69000.json','["乍疑絕岸行飛鶩，還誤遊魚出聽琴。", "公子自隨星斗去，水聲他日是棠陰。"]'),
('9d26f5f8-de6b-4c97-887d-35c01600fbf9','中秋日泛湖雜詩  其一六','鄒浩','宋','宋诗','song-poetry','','[]','濫巾文會出重城，把筆時爲蚯蚓鳴。',32,'全唐诗/poet.song.69000.json','["濫巾文會出重城，把筆時爲蚯蚓鳴。", "日暮歸來理章句，低頭慚愧楮先生。"]'),
('8336bddc-e119-4cbe-a74c-cf8056b08ce1','中秋日泛湖雜詩  其一七','鄒浩','宋','宋诗','song-poetry','','[]','興盡歸來潩水邊，翠陰亭上奏繁絃。',32,'全唐诗/poet.song.69000.json','["興盡歸來潩水邊，翠陰亭上奏繁絃。", "龍媒耳接新聲慣，駐足西風不受鞭。"]'),
('b2c8857e-a373-416d-bb66-262369d2bace','次韻述之','鄒浩','宋','宋诗','song-poetry','','[]','杜陵秋擬問真源，博望親從天上還。',32,'全唐诗/poet.song.69000.json','["杜陵秋擬問真源，博望親從天上還。", "不使清風委平地，斯人今日在陘山。"]'),
('2d7301fe-e2e2-44ec-bd1a-347e3fd8eb28','次韻德符展江懷世美','鄒浩','宋','宋诗','song-poetry','','[]','翩翩風御返瀛洲，清夢還應此地遊。',32,'全唐诗/poet.song.69000.json','["翩翩風御返瀛洲，清夢還應此地遊。", "憑仗雲鴻寄消息，爾來何啻度三秋。"]'),
('1c8741e8-6b61-45cf-b1c6-bfa102902f48','次韻先生湖上有作','鄒浩','宋','宋诗','song-poetry','','[]','霜落西陂晚，追携物外歡。',48,'全唐诗/poet.song.69000.json','["霜落西陂晚，追携物外歡。", "孤芳迎日動，輕浪逐蓮乾。", "魚計從來審，鷗盟未易寒。", "誰知少陵老，愛客似蘇端。"]'),
('667b7413-0ce1-4532-b490-100b5f27827d','湖上','鄒浩','宋','宋诗','song-poetry','','[]','菱盤不復藏秋水，蒲劍猶能戰晚風。',32,'全唐诗/poet.song.69000.json','["菱盤不復藏秋水，蒲劍猶能戰晚風。", "共陟孤高更忘適，紛紛霜葉下晴空。"]'),
('03ecd71c-1707-4d9d-9697-04cdc0247d6a','次韻陳君益見寄','鄒浩','宋','宋诗','song-poetry','','[]','冉冉歲云暮，泠然流水心。',48,'全唐诗/poet.song.69000.json','["冉冉歲云暮，泠然流水心。", "他邦勤短策，今日慰孤斟。", "竹韻凌風遠，花光受月侵。", "毫端落珠琲，三復故情深。"]'),
('51be0693-929f-48ff-83c4-37c7c1e78c8c','次韻羅正之朝散到臨潁見寄','鄒浩','宋','宋诗','song-poetry','','[]','何事委天數，平生嗤李尋。',48,'全唐诗/poet.song.69000.json','["何事委天數，平生嗤李尋。", "同時得君子，如古惜分陰。", "白髪日非故，黄花秋似深。", "誰知千里駕，中有歲寒心。"]'),
('d50d936f-df7b-403f-99d9-108d39fb5408','代書招德符','鄒浩','宋','宋诗','song-poetry','','[]','北風鳴四野，饑鳥下黄昏。',48,'全唐诗/poet.song.69000.json','["北風鳴四野，饑鳥下黄昏。", "寒燭照無寐，孤懷誰與論。", "伊予賦招隱，撫事倍銷魂。", "莫使衡門下，朝來獨負暄。"]'),
('e0f8d35e-697e-48ee-80e7-bf4396165258','偶書','鄒浩','宋','宋诗','song-poetry','','[]','玄鳥未來陽鳥稀，廣庭松竹皆故枝。',32,'全唐诗/poet.song.69000.json','["玄鳥未來陽鳥稀，廣庭松竹皆故枝。", "書邊癡坐送日月，春色過門都不知。"]'),
('518bd1a9-c036-4c97-a048-19b3764664ac','謝馬叔寶惠佛像琴絃','鄒浩','宋','宋诗','song-poetry','','[]','故人知我久忘情，不假苞苴遠寄誠。',64,'全唐诗/poet.song.69000.json','["故人知我久忘情，不假苞苴遠寄誠。", "金範晬容窺往製，絲傳流水得遺聲。", "鄰雞破曉爐邊静，霜月儲清席上横。", "香散曲終誰會意，與君相望一高城。"]'),
('b5113ea0-4854-4686-8b2b-64c9866444be','曾存之以佇雲名庵以待緇流因作此戲之','鄒浩','宋','宋诗','song-poetry','','[]','不見從來庵內人，結茅瀕水更慇懃。',32,'全唐诗/poet.song.69000.json','["不見從來庵內人，結茅瀕水更慇懃。", "雲飛日日滿天地，借問如何能佇雲。"]'),
('2a86a98e-a95e-4182-afcf-da5388c34c95','仲弓見訪同過叔原','鄒浩','宋','宋诗','song-poetry','','[]','幕天雲不動，庭竹晚生寒。',48,'全唐诗/poet.song.69000.json','["幕天雲不動，庭竹晚生寒。", "好事倐假盖，擁爐聊整冠。", "香煤團薄霧，松麈落驚湍。", "思逸何當盡，鄰家有謝安。"]'),
('86d8071e-e209-4553-8fd8-739f4163bea2','次韻述之謝寄蘭','鄒浩','宋','宋诗','song-poetry','','[]','朅來幽韻與時分，雅稱深沉揚子雲。',32,'全唐诗/poet.song.69000.json','["朅來幽韻與時分，雅稱深沉揚子雲。", "記取人間多惡草，一蕕能敗十年薫。"]'),
('e907f692-89de-424a-a69e-30e714537b0e','曾氏北園  其一','鄒浩','宋','宋诗','song-poetry','','[]','浮雲不傍此庵來，竹静幽蘭一笑開。',32,'全唐诗/poet.song.69000.json','["浮雲不傍此庵來，竹静幽蘭一笑開。", "若處鮮鮮解人意，等閒冰破作春雷。"]'),
('36095332-42d1-4983-abf8-9504b95c26ea','曾氏北園  其二','鄒浩','宋','宋诗','song-poetry','','[]','藕花蓮葉弄晴暉，長記君來作好詩。',32,'全唐诗/poet.song.69000.json','["藕花蓮葉弄晴暉，長記君來作好詩。", "我亦池塘興不淺，若爲相望北風時。"]'),
('a23aa514-d33a-4efe-b6ae-0c71fb500cf6','曾氏北園  其三','鄒浩','宋','宋诗','song-poetry','','[]','江禽插頸夢初成，庭樹横烟晚更輕。',32,'全唐诗/poet.song.69000.json','["江禽插頸夢初成，庭樹横烟晚更輕。", "已恨重城落吾事，更堪明月向人生。"]'),
('51a3fdf5-5876-4bba-8c28-c98369c23ace','曾氏北園  其四','鄒浩','宋','宋诗','song-poetry','','[]','蘇郎北闕未尋盟，崔子西山尚掩扃。',32,'全唐诗/poet.song.69000.json','["蘇郎北闕未尋盟，崔子西山尚掩扃。", "矯首空庭問懷抱，天高無路鴈邊青。"]'),
('ae96578f-5243-47dc-9d83-4fc6adc34ba5','曾氏北園  其五','鄒浩','宋','宋诗','song-poetry','','[]','十年不折江南春，亭下雙梅是故人。',32,'全唐诗/poet.song.69000.json','["十年不折江南春，亭下雙梅是故人。", "憑仗開時屬青翼，已判飛雪滿懸鶉。"]'),
('b01ce6fa-adaa-4400-a084-42fff7d25bba','曾氏北園  其六','鄒浩','宋','宋诗','song-poetry','','[]','白蓮香火久凋零，還似樂天今服膺。',32,'全唐诗/poet.song.69000.json','["白蓮香火久凋零，還似樂天今服膺。", "我有一言人不解，請君問取北來僧。"]'),
('d914fbb9-5a7b-4d2b-8f4a-430049094821','種竹','鄒浩','宋','宋诗','song-poetry','','[]','去年今日常種竹，今年此日還添栽。',32,'全唐诗/poet.song.69000.json','["去年今日常種竹，今年此日還添栽。", "豈論傳舍不吾有，但願清陰遺後來。"]'),
('a1e8dc38-28d9-4a9f-81f5-e4dd8146f00b','次韻德符寄世美因以招之','鄒浩','宋','宋诗','song-poetry','','[]','織女牽牛餞我車，歸來籬菊已榮枯。',32,'全唐诗/poet.song.69000.json','["織女牽牛餞我車，歸來籬菊已榮枯。", "韓城夫子舊青眼，肯使東齋屐齒疏。"]'),
('72964575-3ed6-455c-ae18-b479cc849764','次韻承君見寄  其一','鄒浩','宋','宋诗','song-poetry','','[]','紛紛市道久成風，平地青樓作帝宮。',32,'全唐诗/poet.song.69000.json','["紛紛市道久成風，平地青樓作帝宮。", "白玉相看有君子，坐令高議薄冥鴻。"]'),
('b0638df8-0a99-45d2-8fff-afda96cf280a','次韻承君見寄  其二','鄒浩','宋','宋诗','song-poetry','','[]','生平勳業在詩書，黑綬翩翩下蘂珠。',32,'全唐诗/poet.song.69000.json','["生平勳業在詩書，黑綬翩翩下蘂珠。", "漳水功名未爲最，他年丹檻更捐軀。"]'),
('9af6f7a9-4820-4af0-8185-badf59365847','謝承君見訪','鄒浩','宋','宋诗','song-poetry','','[]','龍吟虎嘯嶺雲開，卷罷殘經首重回。',64,'全唐诗/poet.song.69000.json','["龍吟虎嘯嶺雲開，卷罷殘經首重回。", "命駕直因中散去，齎羊不爲護軍來。", "真情破臘融初日，高論先春駭迅雷。", "勉力古人論一報，終慚瓦礫異瓊瑰。"]'),
('33ffae4d-03dc-4322-b2c2-4e11fecdbcfe','次韻劉世德見贈','鄒浩','宋','宋诗','song-poetry','','[]','詩書久與壮心期，邂逅塵埃滿客衣。',64,'全唐诗/poet.song.69000.json','["詩書久與壮心期，邂逅塵埃滿客衣。", "不分壽陵終失步，更憐蘧瑗早知非。", "龍蟠舊水風雷在，玉韞寒山草木輝。", "大抵窮通有時節，莫将吾道羡雄飛。"]'),
('9b942c78-bb89-4d16-8a51-aa0552bca4b9','次韻文仲元日登巽亭  其一','鄒浩','宋','宋诗','song-poetry','','[]','春隨鼓角静浮遊，放浪乾坤百尺樓。',32,'全唐诗/poet.song.69000.json','["春隨鼓角静浮遊，放浪乾坤百尺樓。", "北陌東阡政車馬，一時高興屬清流。"]'),
('e7eeaca3-3cf3-4bae-a6d3-8fdb23f188d3','次韻文仲元日登巽亭  其二','鄒浩','宋','宋诗','song-poetry','','[]','刺字漫來得古城，柳枝桃葉入春情。',32,'全唐诗/poet.song.69000.json','["刺字漫來得古城，柳枝桃葉入春情。", "人間久遲東君到，獨子相投盖始傾。"]'),
('0b7ee2d2-a73f-4f65-962e-96491f790a5e','次韻馬叔寶憶梅','鄒浩','宋','宋诗','song-poetry','','[]','儒冠染盡馬蹄塵，又見年光冉冉新。',64,'全唐诗/poet.song.69000.json','["儒冠染盡馬蹄塵，又見年光冉冉新。", "寄我一枝無驛使，賴君佳句有陽春。", "雪邊孤韻謝安石，風際幽香韓得真。", "何日相携拂衣去，澹烟微月楚江濱。"]'),
('8976cb3e-6741-4992-8686-06bb7b4f7ffe','仲弓意欲協律作此戲之','鄒浩','宋','宋诗','song-poetry','','[]','王郎豪翰落明珠，自合鵷行儼帝居。',32,'全唐诗/poet.song.69000.json','["王郎豪翰落明珠，自合鵷行儼帝居。", "底事奉常思協律，不歸天祿更讐書。"]'),
('2674e943-4205-4787-bf3d-d5272d089e2f','次韻仲孺用前韻寄世美二首  其一','鄒浩','宋','宋诗','song-poetry','','[]','雪霽高陽里，欣欣春意深。',48,'全唐诗/poet.song.69000.json','["雪霽高陽里，欣欣春意深。", "舊遊還入眼，何處復揮金。", "塵表誰南北，杯中失古今。", "重憐非土木，猶自一沉吟。"]'),
('68331347-fdf0-4c04-9db5-f83f0cfbf698','次韻仲孺用前韻寄世美二首  其二','鄒浩','宋','宋诗','song-poetry','','[]','天宇梅邊静，春光破蟻封。',48,'全唐诗/poet.song.69000.json','["天宇梅邊静，春光破蟻封。", "嶺雲猶過鴈，冰浪欲飛龍。", "玉鐙随新約，茅簷祗故容。", "何當卷書去，相與豁塵胸。"]'),
('6666faab-670c-4419-877c-4270040f9051','次韻文仲落梅','鄒浩','宋','宋诗','song-poetry','','[]','前引蒼龍駕，人間春欲光。',48,'全唐诗/poet.song.69000.json','["前引蒼龍駕，人間春欲光。", "遽先鴻滅影，應誤蝶尋香。", "何事雪霜際，不随松檜長。", "無言倚晴日，酌水與君嘗。"]'),
('71217f99-a46f-4739-b808-ef7c7694eafb','次韻仲弓寄德符大受','鄒浩','宋','宋诗','song-poetry','','[]','二子麻衣掩舊春，霏霏眥血灑驚塵。',64,'全唐诗/poet.song.69000.json','["二子麻衣掩舊春，霏霏眥血灑驚塵。", "白雲不雨還遮岫，清潁無心解閲人。", "禍福循環終有數，詩書飽腹未爲貧。", "何當跋馬同君去，蘿月松風慰秃巾。"]'),
('77cdd581-b723-4c2e-8673-7534828dd67e','鄰家集射','鄒浩','宋','宋诗','song-poetry','','[]','墻東金鼓不停聲，知是将軍奕世孫。',32,'全唐诗/poet.song.69000.json','["墻東金鼓不停聲，知是将軍奕世孫。", "莫浪鳴弓向飛鴈，一年一度到中原。"]'),
('0b5f3561-bebc-4aed-a03a-5f451b31f9d3','曾園見梅  其一','鄒浩','宋','宋诗','song-poetry','','[]','濱水娟娟四五枝，不甘柳眼巧相窺。',32,'全唐诗/poet.song.69000.json','["濱水娟娟四五枝，不甘柳眼巧相窺。", "晚來快我江南思，似欲慇懃報小詩。"]'),
('18cd1baf-f37a-49dd-9f43-a262db27f125','曾園見梅  其二','鄒浩','宋','宋诗','song-poetry','','[]','姑射冰肌不黄土，洛陽玉容更青春。',32,'全唐诗/poet.song.69000.json','["姑射冰肌不黄土，洛陽玉容更青春。", "嗅風影日了無語，知我此心能幾人。"]'),
('c2797ba9-c70f-4cf4-a158-3ebc82c33c37','雪中懷述之','鄒浩','宋','宋诗','song-poetry','','[]','不爲梁園賦，因辭潁水濱。',48,'全唐诗/poet.song.69000.json','["不爲梁園賦，因辭潁水濱。", "誰知遇風雪，孤坐耿陽春。", "問路無來轍，携笻匪舊鄰。", "從君一樽酒，猶喜有詩人。"]'),
('f59c654b-3de6-4588-b844-d49a6e57c5b2','招文仲','鄒浩','宋','宋诗','song-poetry','','[]','暉暉晴日動寒灰，書罷衡門爲子開。',32,'全唐诗/poet.song.69000.json','["暉暉晴日動寒灰，書罷衡門爲子開。", "莫似王郎著杯酒，更無茶思竹邊來。"]'),
('dd9570cb-f53e-4e3d-9c4a-13cfd2dc21c4','聞小引呈仲孺文仲','鄒浩','宋','宋诗','song-poetry','','[]','香中日月久無鄰，特地過從兩玉人。',32,'全唐诗/poet.song.69000.json','["香中日月久無鄰，特地過從兩玉人。", "何必開軒視天壤，角聲嘹亮自知春。"]'),
('69bdfabf-6c02-4b27-ab5c-06fd7f0921b7','獨坐','鄒浩','宋','宋诗','song-poetry','','[]','庭下芝蘭秀，堂中簡策清。',24,'全唐诗/poet.song.69000.json','["庭下芝蘭秀，堂中簡策清。", "都緣無嗜好，不是近聲名。"]'),
('0707ed49-9823-4a36-a26d-07d1c9a0a0f7','聞仲弓得籍田令','鄒浩','宋','宋诗','song-poetry','','[]','夏木如雲作晝清，西豪無復岸綸巾。',32,'全唐诗/poet.song.69000.json','["夏木如雲作晝清，西豪無復岸綸巾。", "知君談笑籍田去，又喜長安有故人。"]'),
('e9d24b49-7224-48ae-bb95-0a5472867f8d','對雨','鄒浩','宋','宋诗','song-poetry','','[]','不爲泥融俟燕還，自携秋事入春田。',32,'全唐诗/poet.song.69000.json','["不爲泥融俟燕還，自携秋事入春田。", "人間因得風光好，洗出從來寒食天。"]'),
('939381a0-036c-4891-8435-15e8b2d3d0b6','寒食日諸友見過','鄒浩','宋','宋诗','song-poetry','','[]','燕子聲中藿食寒，北轅同軌得儒冠。',32,'全唐诗/poet.song.69000.json','["燕子聲中藿食寒，北轅同軌得儒冠。", "槐檀新火未曾試，爲覓山泉破小團。"]'),
('f1d3b34e-5f93-4d08-ba40-2bed004f0424','和仲孺前韻約賞展江海棠及簡仲弓述之  其一','鄒浩','宋','宋诗','song-poetry','','[]','西蜀地暖北地寒，長條殿春走衣冠。',32,'全唐诗/poet.song.69000.json','["西蜀地暖北地寒，長條殿春走衣冠。", "江亭巧作故時面，濯濯宮錦花成圑。"]'),
('5d3583a3-18c8-4c7d-8fc1-a29519a0dd1f','和仲孺前韻約賞展江海棠及簡仲弓述之  其二','鄒浩','宋','宋诗','song-poetry','','[]','一日秋陽十日寒，李下多機難整冠。',32,'全唐诗/poet.song.69000.json','["一日秋陽十日寒，李下多機難整冠。", "戴崇彭宣各天性，玉斧何當新月團。"]'),
('53e9ca74-2e62-4e76-a824-55d411c4c0d4','曾園見海棠','鄒浩','宋','宋诗','song-poetry','','[]','海棠簇簇弄繁英，随分相逢眼自青。',32,'全唐诗/poet.song.69000.json','["海棠簇簇弄繁英，随分相逢眼自青。", "一種風流似西蜀，何須心着展江亭。"]'),
('08f24ec5-1c82-4adb-9c1a-f1559c2cd7c9','戲明豫','鄒浩','宋','宋诗','song-poetry','','[]','西幕情真庭駐雲，東幕心機門閉春。',32,'全唐诗/poet.song.69000.json','["西幕情真庭駐雲，東幕心機門閉春。", "無端幽夢落蛇虺，漏洩風光來近鄰。"]'),
('dee776a7-f7eb-484e-b3f8-2c0d7ebaf1d3','代者不以時至失仲孺同行之約愴然作此','鄒浩','宋','宋诗','song-poetry','','[]','平日蓴鱸計，猶随黄犢留。',48,'全唐诗/poet.song.69000.json','["平日蓴鱸計，猶随黄犢留。", "蘇君騐前語，裴子但孤舟。", "隋柳薫風岸，淮山霽月樓。", "故應今好在，爲我一回頭。"]'),
('c9bcc284-0893-4b27-b9d8-dbcdc99ad540','上巳日招仲孺述之','鄒浩','宋','宋诗','song-poetry','','[]','三月三日潁水濱，蘭亭故事頽冠巾。',32,'全唐诗/poet.song.69000.json','["三月三日潁水濱，蘭亭故事頽冠巾。", "與君嗜好酷相似，速來同鱠盤中鱗。"]'),
('1a5232cc-3595-4ade-ac1e-6091ad6b29bf','次韻仲弓馬上','鄒浩','宋','宋诗','song-poetry','','[]','霜蹄遙指日邊飛，猶得春湖一笑期。',32,'全唐诗/poet.song.69000.json','["霜蹄遙指日邊飛，猶得春湖一笑期。", "到此君方動離思，併将懷抱入新詩。"]'),
('77877475-d330-492f-8a1e-f7ae4b869313','次韻君表送仲弓迴有作','鄒浩','宋','宋诗','song-poetry','','[]','北野陰成幄，崇朝得暫休。',48,'全唐诗/poet.song.69000.json','["北野陰成幄，崇朝得暫休。", "班荆無濁酒，交轡有清流。", "風絮閒相逐，晴絲懶自遊。", "吾行亦朝夕，未擬問功裘。"]'),
('98a7429a-1fcf-4a50-8e4c-b29d42c73b21','招仲孺述之同過文仲看酴醾','鄒浩','宋','宋诗','song-poetry','','[]','芝堂公子讀書忙，堂下酴醾晚自香。',32,'全唐诗/poet.song.69000.json','["芝堂公子讀書忙，堂下酴醾晚自香。", "猶喜阿文清興在，擬携雙璧步斜陽。"]'),
('2d994968-1c1b-40bb-8ce9-2a76436ac4b2','次韻謝文仲惠酴醾','鄒浩','宋','宋诗','song-poetry','','[]','遶架應憐不記歸，故分新摘慰棲遲。',32,'全唐诗/poet.song.69000.json','["遶架應憐不記歸，故分新摘慰棲遲。", "慧香妙質無人共，賴有青牋寄我詩。"]'),
('393a274e-4839-4331-b86d-6e9b8601a444','次韻龍陽孔方平秋居見懷','鄒浩','宋','宋诗','song-poetry','','[]','黄落龍山暮，天高霽色澄。',48,'全唐诗/poet.song.69000.json','["黄落龍山暮，天高霽色澄。", "棲巖方自若，吾子亦難能。", "家學潛東國，時文斥茂陵。", "遙知見懷處，詩就耿寒燈。"]'),
('038470ea-a528-4a22-b12f-a5939b5c26a3','次韻和錢塘諸公賞梅十絕  其一','鄒浩','宋','宋诗','song-poetry','','[]','衝寒來訪喜生和，破恨新詩不必多。',32,'全唐诗/poet.song.69000.json','["衝寒來訪喜生和，破恨新詩不必多。", "太皥初還好消息，從今日飲更無何。"]'),
('948eafd0-7be2-4152-b90c-8fb248f9acb1','次韻和錢塘諸公賞梅十絕  其二','鄒浩','宋','宋诗','song-poetry','','[]','瓊英潛解叩靈臺，一見先令雙眼開。',32,'全唐诗/poet.song.69000.json','["瓊英潛解叩靈臺，一見先令雙眼開。", "欲識情緣未忘處，不辭珠履步蒼苔。"]'),
('2029cbb1-b4ca-44b3-87a3-ffce79cef038','次韻和錢塘諸公賞梅十絕  其三','鄒浩','宋','宋诗','song-poetry','','[]','雲山寂寂水回回，幽境非緣世俗開。',32,'全唐诗/poet.song.69000.json','["雲山寂寂水回回，幽境非緣世俗開。", "桃李無言且如此，自然人逐暗香來。"]'),
('436a19fc-5117-4097-9d01-23ba8f39fa50','次韻和錢塘諸公賞梅十絕  其四','鄒浩','宋','宋诗','song-poetry','','[]','江天吹雪不勝繁，南北東西晚更昏。',32,'全唐诗/poet.song.69000.json','["江天吹雪不勝繁，南北東西晚更昏。", "料得時人散車馬，清吟應亦有英魂。"]'),
('d26de75a-89e2-46a2-9fde-d14f0c5b086d','次韻和錢塘諸公賞梅十絕  其五','鄒浩','宋','宋诗','song-poetry','','[]','陳根未作去年花，天宇空明鴈影斜。',32,'全唐诗/poet.song.69000.json','["陳根未作去年花，天宇空明鴈影斜。", "忽上溪橋見顔色，不施朱粉似東家。"]'),
('101d9c1f-0de8-4543-8caa-ef45dbafb0b2','次韻和錢塘諸公賞梅十絕  其六','鄒浩','宋','宋诗','song-poetry','','[]','排闥端令天地開，萬花從此四時催。',32,'全唐诗/poet.song.69000.json','["排闥端令天地開，萬花從此四時催。", "政如匠石椎輪後，始有光華大輅來。"]'),
('7e5ef67b-cd02-43ac-ba76-97759d2b54a2','次韻和錢塘諸公賞梅十絕  其七','鄒浩','宋','宋诗','song-poetry','','[]','東風柝柝動冰泥，素蕚迎春滿故枝。',32,'全唐诗/poet.song.69000.json','["東風柝柝動冰泥，素蕚迎春滿故枝。", "早晚團空熟青實，人間消渇待真醫。"]'),
('37c9dd5c-e5ae-4f51-bfa2-b3e7560c98d8','次韻和錢塘諸公賞梅十絕  其八','鄒浩','宋','宋诗','song-poetry','','[]','蜜蜂蝴蝶未狂飛，螻蟻仍難上凍枝。',32,'全唐诗/poet.song.69000.json','["蜜蜂蝴蝶未狂飛，螻蟻仍難上凍枝。", "惟有青松一千丈，相看曾共歲寒時。"]'),
('63b38422-5df3-42f7-b2dd-e1cf23c652e1','次韻和錢塘諸公賞梅十絕  其九','鄒浩','宋','宋诗','song-poetry','','[]','綽約冰肌故自輕，玉衣玉食更鮮明。',32,'全唐诗/poet.song.69000.json','["綽約冰肌故自輕，玉衣玉食更鮮明。", "無心來此與君遇，莫起他時兒女情。"]'),
('93888078-a3e3-49a4-b495-1ef441ba1be0','次韻和錢塘諸公賞梅十絕  其一○','鄒浩','宋','宋诗','song-poetry','','[]','玉樹森森太傅家，玲瓏徐動曉風斜。',32,'全唐诗/poet.song.69000.json','["玉樹森森太傅家，玲瓏徐動曉風斜。", "可憐刻楮空機事，一葉三年猶未花。"]'),
('24eb69c4-6cdc-4e2a-86fa-803c223f84f7','戲舜俞遊西湖','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖光收盡只芙蕖，决眥飛來白鳥孤。',32,'全唐诗/poet.song.69000.json','["湖光收盡只芙蕖，决眥飛來白鳥孤。", "想見城南葛藤老，又将心境示妻孥。"]'),
('bad63729-281a-431c-9892-4c1c162cadac','贈周仁熟教授','鄒浩','宋','宋诗','song-poetry','','[]','西來黄軸塞虚空，都在圓光一點中。',32,'全唐诗/poet.song.69000.json','["西來黄軸塞虚空，都在圓光一點中。", "陌路勸君高着眼，宗風况即是家風。"]'),
('e4db9511-acd4-41ea-ab20-3e091878dce6','次韻答李希白秀才','鄒浩','宋','宋诗','song-poetry','','[]','數椽茆屋異千間，慚愧君歌行路難。',64,'全唐诗/poet.song.69000.json','["數椽茆屋異千間，慚愧君歌行路難。", "自昔牛羊多列鼎，只今藜藿未盈簞。", "須将嘉木殷勤植，莫把修鱗取次蟠。", "請看齊城不危困，功名豈復有田單。"]'),
('f8ee42a7-c838-4a54-b86d-69bcd9b04903','次韻德符馬上口占','鄒浩','宋','宋诗','song-poetry','','[]','直欲掩關心似水，不知開國面如田。',32,'全唐诗/poet.song.69000.json','["直欲掩關心似水，不知開國面如田。", "相逢一枕秋光裏，疑是先生亦姓邊。"]'),
('962468f8-feb9-485a-983c-7c085223a5c0','春陰','鄒浩','宋','宋诗','song-poetry','','[]','極目三封日易斜，無因重守故庭花。',32,'全唐诗/poet.song.69000.json','["極目三封日易斜，無因重守故庭花。", "春陰又是憐花草，燕子飛來知幾家。"]'),
('b610f4ca-1b25-4fdf-80dd-c816054fc33b','聞鶯','鄒浩','宋','宋诗','song-poetry','','[]','櫻桃初熟露珠輕，客裏光陰曉更清。',32,'全唐诗/poet.song.69000.json','["櫻桃初熟露珠輕，客裏光陰曉更清。", "猶恐先生只歸夢，故携天籟入風聲。"]'),
('077444a2-4425-48e1-a578-6c36b6e3ab38','病卧讀書','鄒浩','宋','宋诗','song-poetry','','[]','山爲屏障草爲裀，黄犢群中早奮身。',32,'全唐诗/poet.song.69000.json','["山爲屏障草爲裀，黄犢群中早奮身。", "骨立詩書亦何有，不如參取坐忘人。"]'),
('516f9a78-f7ef-430c-923d-47e410c289ad','次韻仲弓見答','鄒浩','宋','宋诗','song-poetry','','[]','青衫白馬吏天邊，胸次長年只輞川。',32,'全唐诗/poet.song.69000.json','["青衫白馬吏天邊，胸次長年只輞川。", "我愧無才似裴迪，亦緣春步見新篇。"]'),
('a4880223-6946-4681-8d7e-bf3f751b5c5f','席上呈仲明','鄒浩','宋','宋诗','song-poetry','','[]','誦詩久欲陪蘇焕，載酒誰憐訪子雲。',32,'全唐诗/poet.song.69000.json','["誦詩久欲陪蘇焕，載酒誰憐訪子雲。", "莫道囊空乏供給，鄰家芹菊許人分。"]'),
('cb977067-d62f-4937-9ef0-3bd82e4e9219','次王彦魯韻呈仲弓','鄒浩','宋','宋诗','song-poetry','','[]','城南兼吏隱，草樹水中央。',48,'全唐诗/poet.song.69000.json','["城南兼吏隱，草樹水中央。", "飛鳥有時到，驚塵無處揚。", "留春供燕集，落日借輝光。", "一自烏衣後，風流知幾王。"]'),
('f773d5e4-1ef1-445d-891f-546677d1c071','送郭舜俞再任潁昌','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','穀雨冥冥春盡頭，故人重解去時舟。',32,'全唐诗/poet.song.69000.json','["穀雨冥冥春盡頭，故人重解去時舟。", "西湖好在一百頃，爲我傳聲到白鷗。"]'),
('8c76b653-c302-48de-8d83-7c8403e465fb','初到京謁執政','鄒浩','宋','宋诗','song-poetry','','[]','鄒陽謾說曳長裾，東閣由來禮自殊。',32,'全唐诗/poet.song.69000.json','["鄒陽謾說曳長裾，東閣由來禮自殊。", "負郭田園倘無恙，不如歸去老江湖。"]'),
('a07c81b3-e111-4c60-9e01-44e659281aff','次韻文仲冬夜書懷  其一','鄒浩','宋','宋诗','song-poetry','','[]','抱經何必歎空言，看取東郊舊力田。',32,'全唐诗/poet.song.69000.json','["抱經何必歎空言，看取東郊舊力田。", "藨蓘倘能無落事，太陰居卯定豐年。"]'),
('e1c5b140-304e-4752-ab7c-df30e00984f1','次韻文仲冬夜書懷  其二','鄒浩','宋','宋诗','song-poetry','','[]','長冰迎日動堤塍，堤上人行似獨醒。',32,'全唐诗/poet.song.69000.json','["長冰迎日動堤塍，堤上人行似獨醒。", "只有群鷗疑着在，一時飛舞起寒汀。"]'),
('8382d2eb-f910-4cf8-bf6e-f29fb7c7cad7','次韻文仲冬夜書懷  其三','鄒浩','宋','宋诗','song-poetry','','[]','冷官裘馬怯凌風，咫尺雲窗邈異封。',32,'全唐诗/poet.song.69000.json','["冷官裘馬怯凌風，咫尺雲窗邈異封。", "長憶去年同燕處，竹邊梨栗送殘冬。"]'),
('98545beb-4197-44bb-93d5-ebacfd9146a9','初夏過西苑呈商居平程良弼二年兄','鄒浩','宋','宋诗','song-poetry','','[]','紅香吹盡綠陰垂，恰似當年錫宴時。',32,'全唐诗/poet.song.69000.json','["紅香吹盡綠陰垂，恰似當年錫宴時。", "今日玉津樓下過，午聲依舊囀黄鸝。"]'),
('86908297-6db2-4d79-819b-b36e3bf73de4','次韻蔡天啓寄籍田令','鄒浩','宋','宋诗','song-poetry','','[]','興來雲路欲飛仙，風更吹凉入綺錢。',64,'全唐诗/poet.song.69000.json','["興來雲路欲飛仙，風更吹凉入綺錢。", "豈但烏衣今莫逆，也知白鳥舊相便。", "波随静止荷初展，舟逐閒移楫自眠。", "我亦書邊有餘日，與君同到五湖天。"]'),
('ca25a13c-2176-4479-aa8b-a580bb1c7c83','雨中','鄒浩','宋','宋诗','song-poetry','','[]','五月沉陰久不開，冷風吹雨滿天街。',32,'全唐诗/poet.song.69000.json','["五月沉陰久不開，冷風吹雨滿天街。", "老農且莫愁蠶麥，丞相祈晴已宿齋。"]'),
('98dba763-6647-4a52-93d9-afa8fb7d863e','與存之會相國','鄒浩','宋','宋诗','song-poetry','','[]','雨中竹葉不勝翠，風過榴花元自紅。',32,'全唐诗/poet.song.69000.json','["雨中竹葉不勝翠，風過榴花元自紅。", "門外喧喧正商賈，與君趺坐入真空。"]'),
('54b99373-490f-4878-bc14-bd31785dbeb2','夢閻求仁','鄒浩','宋','宋诗','song-poetry','','[]','朱衣象笏肅賓階，平昔襟懷向我開。',32,'全唐诗/poet.song.69000.json','["朱衣象笏肅賓階，平昔襟懷向我開。", "猶恐孤根自搖蕩，故傳好語夢中來。"]'),
('efee1821-54fb-47b6-b3c6-7c8268e83d83','登建隆回呈俞秀老','鄒浩','宋','宋诗','song-poetry','','[]','痩骨崚嶒聳碧峰，應緣曾住大明東。',64,'全唐诗/poet.song.69000.json','["痩骨崚嶒聳碧峰，應緣曾住大明東。", "道吾埋没今何處，少室分張昔已空。", "殿閣不移秋際影，松篁猶韻曉來風。", "爲人徹困無人解，借問三生龐德翁。"]'),
('c7c47e25-2c18-4370-b3a2-7eaa093c749e','虎丘晚歸呈同遊','鄒浩','宋','宋诗','song-poetry','','[]','虎丘山色最宜秋，山下濺濺亦可舟。',64,'全唐诗/poet.song.69000.json','["虎丘山色最宜秋，山下濺濺亦可舟。", "北去幾年空好夢，東來今日快昏眸。", "邦畿正藹無雙譽，杖履仍逢第一流。", "邂逅高風許追逐，異時應擬峴山頭。"]'),
('fc194b63-1c22-48b3-9633-609b9c1a4f9e','濟明不預虎丘之遊作此寄之','鄒浩','宋','宋诗','song-poetry','','[]','虎據千年一故丘，爾來形勝絕南州。',64,'全唐诗/poet.song.69000.json','["虎據千年一故丘，爾來形勝絕南州。", "池清不礙龍收影，臺迥猶疑石點頭。", "白日青天秋更好，幅巾藜杖曉同遊。", "遙知正擁雙旌坐，直上雲峰一凭樓。"]'),
('8f1f5c96-6aa0-47f7-916f-e61f6cb3f7de','再用前韻答濟明見和','鄒浩','宋','宋诗','song-poetry','','[]','長笑空言謾九丘，更攜餘刃佐方州。',64,'全唐诗/poet.song.69000.json','["長笑空言謾九丘，更攜餘刃佐方州。", "老姦不復潛封內，佳句終然到筆頭。", "秋入江山供遠思，路回猿鶴佇清遊。", "只應未厭斯民樂，還聽鐘鳴十二樓。"]'),
('ff11d429-8508-4339-93df-b2e91b10ad82','次韻和通判梁端夫朝奉曉登峴山有作','鄒浩','宋','宋诗','song-poetry','','[]','天宇霜來峴首高，爽心先寄雪中橈。',64,'全唐诗/poet.song.69000.json','["天宇霜來峴首高，爽心先寄雪中橈。", "早陪勝集方多暇，應念前人不復朝。", "鴈影有時搖莽蒼，江聲終日上岧嶤。", "遙知清絕詩成際，正似寒窗火欲銷。"]'),
('d0cbc5b9-acce-4306-9d06-26a2d583566c','次韻和端夫席上送樗年','鄒浩','宋','宋诗','song-poetry','','[]','過額紛紛競掃眉，此心直與古人期。',64,'全唐诗/poet.song.69000.json','["過額紛紛競掃眉，此心直與古人期。", "三年竝席惟夫子，一笑忘言謝小兒。", "江國舊編塵漠漠，帝鄉新路日遲遲。", "儒冠道在無通塞，莫問高門知不知。"]'),
('67fb445f-c7b5-4f4e-aa57-b83814071795','寄世美','鄒浩','宋','宋诗','song-poetry','','[]','江南秀色滿崔嵬，上得平山入眼來。',32,'全唐诗/poet.song.69000.json','["江南秀色滿崔嵬，上得平山入眼來。", "遙想歸心動朝夕，不應猶待八仙開。"]'),
('fdf89d50-24c8-41ce-90a3-5e39a6377731','謝端夫惠梁因求餘材','鄒浩','宋','宋诗','song-poetry','','[]','破竹誅茆屋數椽，爾來風雨蕩朝昏。',64,'全唐诗/poet.song.69000.json','["破竹誅茆屋數椽，爾來風雨蕩朝昏。", "豈知東閣猶堪廐，若比膠庠不可園。", "蓬蓽已甘聊卒歲，棟梁誰謂入衡門。", "因公起我高堂意，更乞餘材千萬根。"]'),
('9ea7a9fa-db5a-4f7f-a1d2-54aea131c1ee','再用前韻答端夫見和','鄒浩','宋','宋诗','song-poetry','','[]','朝衣暫此擁屏星，長笑他時智慧昏。',64,'全唐诗/poet.song.69000.json','["朝衣暫此擁屏星，長笑他時智慧昏。", "不以誠心尊孔氏，却將吾道奉祇園。", "由來博施能周物，曾是寒生亦叩門。", "只恐堂成待公落，鏡中黄色尚山根。"]'),
('82da45c7-a8d4-4884-8375-5793e0e04d8d','簡襄陽令田世德通直求餘材','鄒浩','宋','宋诗','song-poetry','','[]','百里江天指顧中，大夫真有古人風。',32,'全唐诗/poet.song.69000.json','["百里江天指顧中，大夫真有古人風。", "似聞齋館成功久，應許餘材入泮宮。"]'),
('b978e879-c67e-4b91-8b12-47aef882ddd2','次韻和端夫喜望之祈雪有應','鄒浩','宋','宋诗','song-poetry','','[]','誠意通羣祀，朝來忽已飄。',252,'全唐诗/poet.song.69000.json','["誠意通羣祀，朝來忽已飄。", "六花紛汗漫，千里入均調。", "趙璧光凌日，隋珠暗擲宵。", "老農愁自判，稚子喜來嬌。", "化育知難詰，形容豈易描。", "白鹽聊比擬，黄竹謾謳謠。", "談柄迷修麈，朝衣奪素貂。", "豐穰歸嗣歲，收拾謝枯樵。", "淺露先生履，深齊惠可腰。", "思添韋應物，狂助蓋寛饒。", "民食逃艱粒，宸心定解焦。", "樓高天構玉，池迥地疏瑤。", "爽韻陪松檜，嚴聲陋鼓簫。", "亡羊空道路，失鶴但雲霄。", "撫運年將往，侵人鬢欲凋。", "題輿真健筆，險句壓寒綃。", "重愧非名士，兹焉綴下寮。", "主賓參沔渡，杖履集山椒。", "故事梁園在，風流楚國遙。", "瓊瑰争報復，宇宙一漂搖。", "莫訝春來晚，春來待此消。"]'),
('876ac0d2-a76d-49e1-bdaf-6daedcb1838a','次韻慎微雪','鄒浩','宋','宋诗','song-poetry','','[]','萬物歸根後，端來兆物華。',192,'全唐诗/poet.song.69000.json','["萬物歸根後，端來兆物華。", "仙姿凝鶴氅，雲路擁羊車。", "但喜天時正，寧知帝力加。", "有田皆玉粒，無樹不瓊花。", "浪說朱蹄馬，空餘白首鴉。", "酒邊深薦爽，穽處巧藏窊。", "徑斷回樵斧，波渾倚釣槎。", "高門委金帛，陰壑蜕龍蛇。", "功茂豐年穀，名喧好事茶。", "叢輕頽瓦竹，搖迥動籤牙。", "蝶冷殘初夢，蜂寒閟兩衙。", "殷勤非俗韻，瀟灑是生涯。", "火變人窺異，軍潛夜肅譁。", "暗香迷綻蘂，新築路平沙。", "寸食方從寄，扁舟未可拏。", "只應清興在，猶似子猷家。"]'),
('a10bf108-0427-4432-8454-a08e7a237784','次韻和慎微雪夜飲歸','鄒浩','宋','宋诗','song-poetry','','[]','籃輿還自斗邊城，雪夜乾坤分外清。',32,'全唐诗/poet.song.69000.json','["籃輿還自斗邊城，雪夜乾坤分外清。", "我爲捐書徑眠去，寒光猶助一窗明。"]'),
('9fbcf0ae-eba9-4f92-87d7-56dcb2245228','招潁昌曾存之','鄒浩','宋','宋诗','song-poetry','','[]','荆山漢水雪邊春，滿眼風流見古人。',64,'全唐诗/poet.song.69000.json','["荆山漢水雪邊春，滿眼風流見古人。", "領略此心誰與盡，從容高義勢難親。", "静搖菴影竹如昨，清弄池光梅欲新。", "知子相忘忘未得，禪床推倒就車輪。"]'),
('a17439aa-a1be-4b78-b3f0-e017fb3614f2','延慶山中呈田世德','鄒浩','宋','宋诗','song-poetry','','[]','雲擁招提自一家，僧前百鳥正銜花。',32,'全唐诗/poet.song.69000.json','["雲擁招提自一家，僧前百鳥正銜花。", "長官不怕驚飛去，猶向山頭放晚衙。"]'),
('4094206e-0296-4d71-9801-d7b0760b2113','簡仲益求紙帳','鄒浩','宋','宋诗','song-poetry','','[]','紅錦暖籠樽酒後，絳紗輕覆簡書前。',32,'全唐诗/poet.song.69000.json','["紅錦暖籠樽酒後，絳紗輕覆簡書前。", "懸知紙帳君無用，斥與邊韶助晝眠。"]'),
('2831f1ad-30d5-48e8-876d-fab90dfcbe59','仲益以帳來且有就榻眠之句復次韻與之','鄒浩','宋','宋诗','song-poetry','','[]','茆屋初成亦可憐，更懸青帳小窗前。',32,'全唐诗/poet.song.69000.json','["茆屋初成亦可憐，更懸青帳小窗前。", "不嫌索寞無春夢，解使君心合眼眠。"]'),
('609af9e4-7698-469a-a73e-3d8b3606ef6b','元夕過唐潛亨  其一','鄒浩','宋','宋诗','song-poetry','','[]','乾坤爲室月爲燈，今夕先生眼倍青。',32,'全唐诗/poet.song.69000.json','["乾坤爲室月爲燈，今夕先生眼倍青。", "笑盡筌蹄聊把手，不知何處是中庭。"]'),
('fef849fe-17ee-4835-9dc8-0963b819d911','元夕過唐潛亨  其二','鄒浩','宋','宋诗','song-poetry','','[]','藏拙堂深不浪開，夜光容我卷書來。',32,'全唐诗/poet.song.69000.json','["藏拙堂深不浪開，夜光容我卷書來。", "梅花傲雪初無語，斗柄催春忽自回。"]'),
('6bdc39aa-d717-4ee0-85d7-2d1fefa51a02','元夕過唐潛亨  其三','鄒浩','宋','宋诗','song-poetry','','[]','參禪不學龐居士，得句猶如孟浩然。',32,'全唐诗/poet.song.69000.json','["參禪不學龐居士，得句猶如孟浩然。", "要識從來用心處，閴無車馬到門前。"]'),
('bff3d9c6-83be-4c70-9d6b-ae7ff78271bd','送谷隱呈同行諸公','鄒浩','宋','宋诗','song-poetry','','[]','窈窕峰巒藏寶刹，峥嶸樓閣倚晴天。',32,'全唐诗/poet.song.69000.json','["窈窕峰巒藏寶刹，峥嶸樓閣倚晴天。", "我來不問東西寺，徑就僧堂借榻眠。"]'),
('fa67c955-1a3b-4b1e-ae01-45a38cd06941','仲益欲歸作此留之','鄒浩','宋','宋诗','song-poetry','','[]','關西關北漸芳菲，曉馬凌春入翠微。',32,'全唐诗/poet.song.69000.json','["關西關北漸芳菲，曉馬凌春入翠微。", "山向吾曹正多思，不應攬轡屡言歸。"]'),
('d87359a7-40d6-46c2-a4b3-32cc21651343','次韻答端夫約春遊','鄒浩','宋','宋诗','song-poetry','','[]','分如松柏老相看，桃李風前共歲寒。',32,'全唐诗/poet.song.69000.json','["分如松柏老相看，桃李風前共歲寒。", "只恐功名挽公去，一春能得幾遊盤。"]'),
('4a94c0ea-991a-4119-a3d4-be07b8d50c44','次韻答仲益見簡','鄒浩','宋','宋诗','song-poetry','','[]','鏡裏年華鬢未蒼，春山且喜漸芬芳。',32,'全唐诗/poet.song.69000.json','["鏡裏年華鬢未蒼，春山且喜漸芬芳。", "功名富貴時來耳，底事靈臺著廟堂。"]'),
('bcbada39-8f10-4298-b068-6db262354f05','次韻和潛亨雪  其一','鄒浩','宋','宋诗','song-poetry','','[]','暖律稽遲太史占，風前猶復弄威嚴。',64,'全唐诗/poet.song.69000.json','["暖律稽遲太史占，風前猶復弄威嚴。", "不妨豪客成樽俎，重使斯民困米鹽。", "但見青峰皆玉筍，豈知白屋是茆簷。", "何人隱入羣羊去，應笑痴兒認角尖。"]'),
('b1cc95d0-a936-4728-8e6c-77bd3f981ae0','次韻和潛亨雪  其二','鄒浩','宋','宋诗','song-poetry','','[]','朝來一色換紛華，眩眼端如醉後車。',64,'全唐诗/poet.song.69000.json','["朝來一色換紛華，眩眼端如醉後車。", "豈待三年方楮葉，雖非八月亦蘆花。", "李邊照曜河南日，柳外繽紛靖節家。", "欲上雲巖訪禪老，路迷空想舉長叉。"]'),
('c39d0ae3-6c6f-4496-b7a3-a8d1180acdff','謁武侯道中  其一','鄒浩','宋','宋诗','song-poetry','','[]','萬株桑柘擁江城，中有梅花獨自清。',32,'全唐诗/poet.song.69000.json','["萬株桑柘擁江城，中有梅花獨自清。", "不近樽罍免攀折，會須結實助和羮。"]'),
('bd50f9ef-c2ce-4b46-acda-cb9d944fcb98','謁武侯道中  其二','鄒浩','宋','宋诗','song-poetry','','[]','先生龍卧此山丘，宇宙曾經幾運籌。',32,'全唐诗/poet.song.69000.json','["先生龍卧此山丘，宇宙曾經幾運籌。", "一自英雄三顧後，至今車馬不曾休。"]'),
('ee6ad4d8-d02c-4ebc-ba25-f1606040aa19','謁武侯道中  其三','鄒浩','宋','宋诗','song-poetry','','[]','萬山山上塔擎天，萬山山下碑沉淵。',32,'全唐诗/poet.song.69000.json','["萬山山上塔擎天，萬山山下碑沉淵。", "天光淵影曉相入，一碧萬里青春前。"]'),
('8e48277f-3aba-4386-ba6d-212f531e3898','謁武侯道中  其四','鄒浩','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','晚雨霏霏江上來，長江水色蒲萄醅。',32,'全唐诗/poet.song.69000.json','["晚雨霏霏江上來，長江水色蒲萄醅。", "鸕鷀鶬鴰得意處，凌風蕩槳從東回。"]'),
('a76bac2d-7085-49a1-b290-c91eb61b3dc6','謁武侯道中  其五','鄒浩','宋','宋诗','song-poetry','','[]','萬山横出波面浮，山前舟楫凌飛鷗。',32,'全唐诗/poet.song.69000.json','["萬山横出波面浮，山前舟楫凌飛鷗。", "遙看塔廟带殘日，蓬萊方丈金鼇頭。"]'),
('a6752800-8f22-4fff-95da-9e24b6690ef2','送香潛亨','鄒浩','宋','宋诗','song-poetry','','[]','炙背軒楹日轉時，博山爐頂駐遊絲。',32,'全唐诗/poet.song.69000.json','["炙背軒楹日轉時，博山爐頂駐遊絲。", "先生妙與此心契，憑仗清香一解頤。"]'),
('c2b11000-25a2-495e-a48c-3cfc4ebe096a','次韻答謝公靖節推將至襄陽見寄  其一','鄒浩','宋','宋诗','song-poetry','','[]','不見紫芝今幾年，朅來眉宇照山川。',32,'全唐诗/poet.song.69000.json','["不見紫芝今幾年，朅來眉宇照山川。", "關南關北風流在，猶得時時一舉鞭。"]'),
('449f5c10-d902-4a79-b99d-fb3c8720dbe2','次韻答謝公靖節推將至襄陽見寄  其二','鄒浩','宋','宋诗','song-poetry','','[]','賓主相忘沔水濱，高風誰與向來親。',64,'全唐诗/poet.song.69000.json','["賓主相忘沔水濱，高風誰與向來親。", "君能雞黍酬初諾，我亦虀鹽得此春。", "桃李無言方永日，江山有路正宜人。", "直須弄鳳騎龍去，莫使身爲可畏身。"]'),
('fe0da39c-fd58-4763-b926-0891c9da5f46','送墨潛亨','鄒浩','宋','宋诗','song-poetry','','[]','少室峰前松插天，棟梁餘力煥青編。',32,'全唐诗/poet.song.69000.json','["少室峰前松插天，棟梁餘力煥青編。", "東齋政欲捐書坐，往助子雲成太玄。"]'),
('d33f9ad9-5529-4546-8317-cb8e690769f7','送李拱之秀才還唐州','鄒浩','宋','宋诗','song-poetry','','[]','真淡先生早杜門，三香亭上自乾坤。',64,'全唐诗/poet.song.69000.json','["真淡先生早杜門，三香亭上自乾坤。", "人間巧舌猶蠭起，子獨摳衣識道尊。", "幾日凱風吹戶牖，只今歸路指丘園。", "將分索我微言贈，欲贈微言無可言。"]'),
('c84156fd-e247-4fac-9961-28ab209522fd','送居政禪者遊廬阜','鄒浩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','拄杖横擔得自由，冷雲飛雪下南州。',32,'全唐诗/poet.song.69000.json','["拄杖横擔得自由，冷雲飛雪下南州。", "殷勤要識廬山面，五老峰前一舉頭。"]'),
('e74064d8-eb91-4810-86ef-7816d6bc037c','六月六日城外馬上呈世德  其一','鄒浩','宋','宋诗','song-poetry','','[]','峴山脚下江水生，普寧寺前舟楫行。',32,'全唐诗/poet.song.69000.json','["峴山脚下江水生，普寧寺前舟楫行。", "細民無錢不得渡，老幼相持愁歎聲。"]'),
('9f5d8132-0b82-40d2-b45b-8bd46d32443d','六月六日城外馬上呈世德  其二','鄒浩','宋','宋诗','song-poetry','','[]','虎頭鳳麓連長堤，隨山刊木路可爲。',32,'全唐诗/poet.song.69000.json','["虎頭鳳麓連長堤，隨山刊木路可爲。", "長官仁政及物遠，一時力役民忘疲。"]'),
('292e834a-338a-4c2d-8f2c-6792ad2196a8','仲益遽塞便門作此戲之','鄒浩','宋','宋诗','song-poetry','','[]','閉門不啻似泄柳，排闥何由如舞陽。',32,'全唐诗/poet.song.69000.json','["閉門不啻似泄柳，排闥何由如舞陽。", "憐君肝膽便楚越，使我南北成參商。"]'),
('e9bb2b1f-f5c1-4978-8222-82e638086f70','謝潛亨惠芸香紫桃','鄒浩','宋','宋诗','song-poetry','','[]','暑窗已覺書生蠧，饑腹還驚雨後雷。',32,'全唐诗/poet.song.69000.json','["暑窗已覺書生蠧，饑腹還驚雨後雷。", "珍重先生解人意，芸香桃實一時來。"]'),
('33e80392-9934-4f2f-b225-33e4eb8cbb14','聞存之遊京師且邸報達官有薦之者','鄒浩','宋','宋诗','song-poetry','','[]','昨來不肯聽朝雞，乞得真宮即日歸。',64,'全唐诗/poet.song.69000.json','["昨來不肯聽朝雞，乞得真宮即日歸。", "老衲蒲團閒共倚，少師玉麈醉同揮。", "誰知捷徑嵩山在，未覺心馳魏闕非。", "綠鴨陂中釣竿手，只應從此叩黄扉。"]'),
('d93face1-28d8-4bbc-a648-a79eb9aadcea','次韻和師稷清明懷鄉之什  其一','鄒浩','宋','宋诗','song-poetry','','[]','掃盡人間冰雪寒，魚龍鱗甲動斒斕。',32,'全唐诗/poet.song.69000.json','["掃盡人間冰雪寒，魚龍鱗甲動斒斕。", "向來協氣無蹤跡，從此氤氲滿世還。"]'),
('19640f43-f4b9-4adb-84fb-06fc0d266bff','次韻和師稷清明懷鄉之什  其二','鄒浩','宋','宋诗','song-poetry','','[]','眼裏飛蠅日夜侵，對時寧復壯年心。',32,'全唐诗/poet.song.69000.json','["眼裏飛蠅日夜侵，對時寧復壯年心。", "故人把手知難遇，强起禪冠插舊簪。"]'),
('70beb999-9c2e-4300-81db-b4331123e50a','次韻和師稷清明懷鄉之什  其三','鄒浩','宋','宋诗','song-poetry','','[]','天路幽禽暖頡頏，芝蘭抽砌葉初長。',32,'全唐诗/poet.song.69000.json','["天路幽禽暖頡頏，芝蘭抽砌葉初長。", "自憐骨立風光裏，勉向原頭泣奉嘗。"]'),
('1a2128e5-fc8b-4596-9821-be1f6d2e612b','次韻和師稷清明懷鄉之什  其四','鄒浩','宋','宋诗','song-poetry','','[]','春聲入鼓曉鼕鼕，春色盈花晚更紅。',32,'全唐诗/poet.song.69000.json','["春聲入鼓曉鼕鼕，春色盈花晚更紅。", "陶冶東君了無意，一時分付與晴風。"]'),
('5d87569f-2ac4-4214-9195-1e52f9991d11','次韻和師稷清明懷鄉之什  其五','鄒浩','宋','宋诗','song-poetry','','[]','冥心無物契毘耶，觸處俱爲剡水涯。',32,'全唐诗/poet.song.69000.json','["冥心無物契毘耶，觸處俱爲剡水涯。", "却怪年來被春惱，逢人不覺歎浮家。"]'),
('d4d97269-f852-4601-b686-28bdfc2b2b48','次韻和師稷清明懷鄉之什  其六','鄒浩','宋','宋诗','song-poetry','','[]','青鞋布襪水雲鄉，勝踐曾同物外忙。',32,'全唐诗/poet.song.69000.json','["青鞋布襪水雲鄉，勝踐曾同物外忙。", "欲寄沃州雙涙去，松陰高冢是星郎。"]'),
('bcd4b8e1-f282-4762-9a10-29c2650b3aa3','次韻和師稷清明懷鄉之什  其七','鄒浩','宋','宋诗','song-poetry','','[]','南明山下枕清流，胸次塵無一點留。',32,'全唐诗/poet.song.69000.json','["南明山下枕清流，胸次塵無一點留。", "只恐少微黄色動，終然來作濟川舟。"]'),
('06ae9ad3-2cb7-4194-b2cb-574705464c91','次韻和師稷清明懷鄉之什  其八','鄒浩','宋','宋诗','song-poetry','','[]','高水籠軒翠作行，枕書閒聽雨浪浪。',32,'全唐诗/poet.song.69000.json','["高水籠軒翠作行，枕書閒聽雨浪浪。", "别來一念終難滅，猶得追論几席傍。"]'),
('f31c194b-f31f-4fac-81dd-4f8c84b74141','次韻和師稷清明懷鄉之什  其九','鄒浩','宋','宋诗','song-poetry','','[]','觀象懸知歲有成，通宵格澤照天明。',32,'全唐诗/poet.song.69000.json','["觀象懸知歲有成，通宵格澤照天明。", "餘生飯飽無它事，坐看紛紛萬物情。"]'),
('8f0f9a63-97e7-4c06-b862-c795411ff79f','次韻和師稷清明懷鄉之什  其一○','鄒浩','宋','宋诗','song-poetry','','[]','三元甲子幾回旋，前日滄溟今甫田。',32,'全唐诗/poet.song.69000.json','["三元甲子幾回旋，前日滄溟今甫田。", "惟有交情似春壽，蟠桃花裏自年年。"]'),
('d1b32c76-061e-49aa-8ae9-b23854a72c73','次韻和永守丁葆光大夫對雪','鄒浩','宋','宋诗','song-poetry','','[]','幾日江雲凝不流，欲將勝事一齊收。',64,'全唐诗/poet.song.69000.json','["幾日江雲凝不流，欲將勝事一齊收。", "乾坤破夜端爲晝，草木留春不復秋。", "黄竹作歌君得意，素娥行酒我消愁。", "須知身世塵埃盡，直到廣寒宮裏遊。"]'),
('7ad96cfd-db51-4e00-ad9b-7a002e593895','次韻和葆光晚望','鄒浩','宋','宋诗','song-poetry','','[]','雪晴新興與春俱，脱略司空城旦書。',64,'全唐诗/poet.song.69000.json','["雪晴新興與春俱，脱略司空城旦書。", "衡嶽带雲回玉輦，楚江浮日動金魚。", "故人情遠欣相遇，夢境時來信所如。", "北闕遙瞻念圖報，恩深猶在免誅鋤。"]'),
('8a9a7d26-6fbe-40cf-b6fc-fc851034615b','登岳陽樓','鄒浩','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','岳陽樓上望重湖，混合乾坤入太虚。',32,'全唐诗/poet.song.69000.json','["岳陽樓上望重湖，混合乾坤入太虚。", "若比恩波未爲闊，此身猶得曳長裾。"]'),
('fb1621f9-d46a-4cac-b515-0c36053254f8','瀟湘道中  其一','鄒浩','宋','宋诗','song-poetry','','[]','清湘浮影動漣漪，寒日收光下翠微。',32,'全唐诗/poet.song.69000.json','["清湘浮影動漣漪，寒日收光下翠微。", "回首君親正無奈，幽禽俄叫不如歸。"]'),
('027c2225-488a-40a6-b193-af0a7aa2dcca','瀟湘道中  其二','鄒浩','宋','宋诗','song-poetry','','[]','極目瀟湘漾碧瀾，萬峰插水巧彎環。',32,'全唐诗/poet.song.69000.json','["極目瀟湘漾碧瀾，萬峰插水巧彎環。", "我來日日忘饑坐，却愛真山似假山。"]'),
('49eb9de5-f487-448b-9402-a748c40704f9','瀟湘道中  其三','鄒浩','宋','宋诗','song-poetry','','[]','萬死猶輕罪有餘，恩容循省但流居。',32,'全唐诗/poet.song.69000.json','["萬死猶輕罪有餘，恩容循省但流居。", "瀟湘二水相逢處，無復波濤今自如。"]'),
