('464393db-67fc-4480-87e5-409fbec7e4fe','題仁老所畫枕屏  其三','鄒浩','宋','宋诗','song-poetry','','[]','古堰横空舟楫回，曹娥江上候潮來。',32,'全唐诗/poet.song.69000.json','["古堰横空舟楫回，曹娥江上候潮來。", "全家彌月寒光裏，日日鮮鱗醉潑醅。"]'),
('289a2663-ab18-446d-883b-12d321aad35e','題仁老所畫枕屏  其四','鄒浩','宋','宋诗','song-poetry','','[]','天華寺前維小舟，僧窗軒豁留清眸。',32,'全唐诗/poet.song.69000.json','["天華寺前維小舟，僧窗軒豁留清眸。", "平湖秋霽浄如鏡，時復輕輕飛白鷗。"]'),
('00f43cd9-3f05-4a49-831a-047852ba1acc','題仁老所畫枕屏  其五','鄒浩','宋','宋诗','song-poetry','','[]','身在九疑麓，門當二水流。',24,'全唐诗/poet.song.69000.json','["身在九疑麓，門當二水流。", "誰知剡中勝，朝夕助嬉遊。"]'),
('78e98fca-16a3-4126-b6e4-7792f65b2883','柄生日','鄒浩','宋','宋诗','song-poetry','','[]','南極星中見老人，祥光垂照喜生春。',32,'全唐诗/poet.song.69000.json','["南極星中見老人，祥光垂照喜生春。", "身如龜鶴心如石，進德功夫常日新。"]'),
('79aeecb8-e310-4bbc-aef3-521f950c870b','示愚溪守道山主','鄒浩','宋','宋诗','song-poetry','','[]','叉手前來問我禪，我無言句與人傳。',32,'全唐诗/poet.song.69000.json','["叉手前來問我禪，我無言句與人傳。", "一盃茶罷抽身起，笑指長松直上天。"]'),
('dc7076f4-e978-4b58-9b3f-4fe21c5cc2dc','次韻和李餘慶','鄒浩','宋','宋诗','song-poetry','','[]','三分春色一分空，莫負花前酒滿鍾。',32,'全唐诗/poet.song.69000.json','["三分春色一分空，莫負花前酒滿鍾。", "醉裏是非渾忘却，任它禪客自分宗。"]'),
('dfd3eabd-8b69-4ef5-bb45-c0bac2703a36','題仙居閣','鄒浩','宋','宋诗','song-poetry','','[]','心鏡圓明照不窮，晉公元自寶青銅。',32,'全唐诗/poet.song.69000.json','["心鏡圓明照不窮，晉公元自寶青銅。", "真人外景雖能睹，争識希夷造化功。"]'),
('4cd99413-8bed-490b-bc90-e0a157931ca0','霞老於雲會堂後開小軒爲以覽勝名之因示短句','鄒浩','宋','宋诗','song-poetry','','[]','瀟湘之勝渺無窮，盡入西軒一覽中。',32,'全唐诗/poet.song.69000.json','["瀟湘之勝渺無窮，盡入西軒一覽中。", "須信高山巧方便，爲人别自有家風。"]'),
('d5067285-a468-46f3-bda2-b0daa9809c15','西鄰葛長源司錄到','鄒浩','宋','宋诗','song-poetry','','[]','鄰舍南來不得書，口傳消息到吾廬。',32,'全唐诗/poet.song.69000.json','["鄰舍南來不得書，口傳消息到吾廬。", "白雲入望無休歇，何日斑衣奉版輿。"]'),
('9e6490e6-7bf1-4da7-9741-10f89a6aa5d4','鴉鳴','鄒浩','宋','宋诗','song-poetry','','[]','老鴉聲裏度朝昏，凶吉由來我不分。',32,'全唐诗/poet.song.69000.json','["老鴉聲裏度朝昏，凶吉由來我不分。", "惟有淵明心莫逆，一函經罷醉醺醺。"]'),
('c79cfbe0-dda7-4761-ba36-853e1b0f7021','偶書','鄒浩','宋','宋诗','song-poetry','','[]','長折松枝爲麈尾，圓刳杉樹作茅菴。',32,'全唐诗/poet.song.69000.json','["長折松枝爲麈尾，圓刳杉樹作茅菴。", "本來面目無人識，却許江山静處參。"]'),
('bdf1f8d4-534a-40f6-a97b-285350e9ed70','望澹山','鄒浩','宋','宋诗','song-poetry','','[]','澹山形勢冠零陵，咫尺拘攣去未能。',32,'全唐诗/poet.song.69000.json','["澹山形勢冠零陵，咫尺拘攣去未能。", "悵望煙霞今阻隔，尚期歸路一來登。"]'),
('a44a99ea-020f-4076-ac58-913e92728a74','移居昭州  其一','鄒浩','宋','宋诗','song-poetry','','[]','廣南東西四十州，瘴癘莫與新昭侔。',32,'全唐诗/poet.song.69000.json','["廣南東西四十州，瘴癘莫與新昭侔。", "我身多病亦知免，陛下仁同天地流。"]'),
('735d5424-ef26-44ac-9015-71541cfa5b02','移居昭州  其二','鄒浩','宋','宋诗','song-poetry','','[]','日日聞人說桂州，桂州朝夕遂經由。',32,'全唐诗/poet.song.69000.json','["日日聞人說桂州，桂州朝夕遂經由。", "自憐罪大當踰嶺，深荷皇恩不遠投。"]'),
('d9289ab8-2dc9-404c-93d9-b4c7d931affe','移居昭州  其三','鄒浩','宋','宋诗','song-poetry','','[]','忠孝從來不兩全，兩無忠孝倍堪憐。',32,'全唐诗/poet.song.69000.json','["忠孝從來不兩全，兩無忠孝倍堪憐。", "自新有路君恩重，猶冀它時不愧天。"]'),
('f9d91d53-821d-430a-b35e-ea2634b6fcd3','覽鏡','鄒浩','宋','宋诗','song-poetry','','[]','覽鏡朝來心自知，鼻端色動有光輝。',32,'全唐诗/poet.song.69000.json','["覽鏡朝來心自知，鼻端色動有光輝。", "鄉邦回首見歸路，已覺歡欣生綵衣。"]'),
('936657f9-fd38-48ed-835d-a096b528f8d6','陳滿堂','鄒浩','宋','宋诗','song-poetry','','[]','滿堂當日亦飛昇，金筍無根不復生。',32,'全唐诗/poet.song.69000.json','["滿堂當日亦飛昇，金筍無根不復生。", "惟有明皇留輦處，至今雲霧半山横。"]'),
('8b12fe08-98d5-4797-aeb5-2d47a8bb1b35','灘聲  其一','鄒浩','宋','宋诗','song-poetry','','[]','長灘斗折轉城隅，激浪飛聲晝夜俱。',64,'全唐诗/poet.song.69000.json','["長灘斗折轉城隅，激浪飛聲晝夜俱。", "猛訝龍驤带雷雨，緩疑仙會集笙竽。", "吟風古木那能和，弄影幽禽只自娱。", "我已無心到天籟，憑欄聊爲一踟蹰。"]'),
('7a5bb964-33fe-46fc-8b28-921cfa88b037','灘聲  其二','鄒浩','宋','宋诗','song-poetry','','[]','洗耳何須潁水清，滛哇滌去有灘聲。',64,'全唐诗/poet.song.69000.json','["洗耳何須潁水清，滛哇滌去有灘聲。", "宮商别奏天然曲，淡薄追還物外情。", "聊與沙鷗均至樂，謾同漁父引餘觥。", "箇中一拍誰人會，長嘯歸來煙霧生。"]'),
('a8ca1dce-b8c5-4662-b14c-7ea2cb7187ef','聞州學補試','鄒浩','宋','宋诗','song-poetry','','[]','辟廱泮水舊先生，十五餘年經自横。',32,'全唐诗/poet.song.69000.json','["辟廱泮水舊先生，十五餘年經自横。", "今日傳聞試多士，尚疑身復任權衡。"]'),
('805117d4-b9d4-4f4b-bd92-0781bed2bed6','懷詹成老','鄒浩','宋','宋诗','song-poetry','','[]','胸中雲夢向來寛，妙入微塵心更安。',64,'全唐诗/poet.song.69000.json','["胸中雲夢向來寛，妙入微塵心更安。", "天北梧桐正鳴鳳，江東枳棘尚棲鸞。", "淵明可是忘三徑，下惠猶能仕小官。", "何日相從坐金粟，静聽飛雪灑琅玕。"]'),
('857d6f5f-e3a6-4aea-87bf-2732b758f136','懷霍子侔','鄒浩','宋','宋诗','song-poetry','','[]','平時咳唾落珠璣，未掌絲綸亦數奇。',64,'全唐诗/poet.song.69000.json','["平時咳唾落珠璣，未掌絲綸亦數奇。", "遠去天官空帳幄，中分淮水動旌旗。", "圜扉蕩滌民知免，列位搜揚士不遺。", "報國功成有餘日，也應回首念流離。"]'),
('7315f48e-aeae-44a4-8667-bbb1fd6fc0aa','懷何伯震','鄒浩','宋','宋诗','song-poetry','','[]','我别家時君在牀，後來南北兩相忘。',64,'全唐诗/poet.song.69000.json','["我别家時君在牀，後來南北兩相忘。", "直饒伏枕到新歲，也勝投身居瘴鄉。", "孤節未嘗交世俗，清貧何以度星霜。", "皇天默相誰窺得，看取它年吾道光。"]'),
('d70bc42f-a204-424f-ad7c-3f36c0db4651','懷張晉卿','鄒浩','宋','宋诗','song-poetry','','[]','年少東鄰新親家，奮然鱗鬛脱泥沙。',64,'全唐诗/poet.song.69000.json','["年少東鄰新親家，奮然鱗鬛脱泥沙。", "傳聞昨者數時弊，想見邇來雙鬢華。", "局上光陰聊鬭馬，盃中意氣莫生蛇。", "江鱸已過河魨出，准擬從君烹荻芽。"]'),
('dab22649-78c5-4ac3-8b60-85b1ab9595a8','懷黄光暉','鄒浩','宋','宋诗','song-poetry','','[]','遠託同門寄好音，夫君不改歲寒心。',64,'全唐诗/poet.song.69000.json','["遠託同門寄好音，夫君不改歲寒心。", "因思明月共千里，亦似家書抵萬金。", "美玉會開和氏璞，高山猶袐伯牙琴。", "真人訓誥知無爽，快我它時朋盍簪。"]'),
('cd164734-017b-48b1-bf08-3365785cc8a3','招澤老','鄒浩','宋','宋诗','song-poetry','','[]','門向山城静處開，更無一點舊塵埃。',32,'全唐诗/poet.song.69000.json','["門向山城静處開，更無一點舊塵埃。", "葛藤尚憶龍溪老，拄杖横擔便可來。"]'),
('aa4fd2e1-b97d-45f6-aca0-f1a59d2d80bd','道傍婦','鄒浩','宋','宋诗','song-poetry','','[]','長插雙釵低繫裙，手持青繖步如雲。',32,'全唐诗/poet.song.69000.json','["長插雙釵低繫裙，手持青繖步如雲。", "忽然退傍芭蕉立，元是前頭逢伯君。"]'),
('b23de376-1514-450a-b5ba-62d208284089','懷至明弟','鄒浩','宋','宋诗','song-poetry','','[]','青衫雖已被天恩，蹩躠難趨猶杜門。',64,'全唐诗/poet.song.69000.json','["青衫雖已被天恩，蹩躠難趨猶杜門。", "分手於今十箇月，寄書何事一無言。", "但勤藥餌寛吾母，休費心神接乃昆。", "我罪湔除歸有路，綵衣相與應篪塤。"]'),
('0a18c12e-e8e0-42f4-af76-a44afa160193','懷至遠弟','鄒浩','宋','宋诗','song-poetry','','[]','機警如君亦可人，經營門戶不因循。',64,'全唐诗/poet.song.69000.json','["機警如君亦可人，經營門戶不因循。", "須知孝友是爲政，莫歎功名難奮身。", "北塔杉松培萬本，東臯禾黍列千囷。", "爾兄倍覺歸來好，百事無爲只奉親。"]'),
('1e76b620-6fca-41e4-8cf4-6e5a3c6e688b','懷承天岑老','鄒浩','宋','宋诗','song-poetry','','[]','記得承天老古錐，呵呵拍手幾人知。',64,'全唐诗/poet.song.69000.json','["記得承天老古錐，呵呵拍手幾人知。", "年來飽飯應無數，門外小橋真可爲。", "浙右普瞻圓照塔，室中高掛建降師。", "我身雖竄心如昨，落筆猶能揮寺碑。"]'),
('f660dd3d-f348-43d4-9ddd-35cbc6b92f0c','夢秦少游','鄒浩','宋','宋诗','song-poetry','','[]','淮海維揚第一流，三關齊透萬緣休。',64,'全唐诗/poet.song.69000.json','["淮海維揚第一流，三關齊透萬緣休。", "真心豈復隨灰劫，遺骨終然寄橘州。", "専爲流通深歎賞，莫相鈍置豁愁憂。", "覺來欲語無人聽，屋角熒熒空斗牛。"]'),
('56c7c08c-7275-4c3c-b641-2a69cc1b8c69','聞放歸田','鄒浩','宋','宋诗','song-poetry','','[]','天地曾無一物遺，孤臣今許返庭闈。',64,'全唐诗/poet.song.69000.json','["天地曾無一物遺，孤臣今許返庭闈。", "黄茅瘴裏抽身出，青草湖邊鼓棹歸。", "衣錦還鄉難並比，承顔稱壽倍光輝。", "恩深骨肉何由報，空有精誠貫紫微。"]'),
('248bee6b-2ba1-4089-9c52-71b399dbd48d','寄曾敷文','鄒浩','宋','宋诗','song-poetry','','[]','誰道衡陽鴈即回，也傳書向嶺南來。',64,'全唐诗/poet.song.69000.json','["誰道衡陽鴈即回，也傳書向嶺南來。", "故人得報皇恩至，約我同歸青眼開。", "爽有江湖清暑氣，豁無塵土溷靈臺。", "功曹法掾相隨處，邂逅追蹤真快哉。"]'),
('0b5eead5-f319-4183-ab92-baba4d3c0bd3','贈湘西琳老','鄒浩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','八年之中三往迴，道人一意金石開。',64,'全唐诗/poet.song.69000.json','["八年之中三往迴，道人一意金石開。", "非干桑梓有分好，自是針芥無嫌猜。", "焚香說了四句偈，把手直上千尺臺。", "洞庭青草不我隔，東吳可歸歸去來。"]'),
('5045c45b-e133-4efb-b285-d6c372a63413','聞霍仁仲唱名第一','鄒浩','宋','宋诗','song-poetry','','[]','吾鄉魁選久蕭條，深喜高才偶聖朝。',64,'全唐诗/poet.song.69000.json','["吾鄉魁選久蕭條，深喜高才偶聖朝。", "天子六龍飛紫極，狀元一鶚奮丹霄。", "拜親此日榮誰及，報國他時事更超。", "四海讙然重改觀，常州真是出英標。"]'),
('e3e00853-ab21-4514-802d-863914a2236e','喜歸','鄒浩','宋','宋诗','song-poetry','','[]','日日思歸今得歸，朝衣不着着斑衣。',32,'全唐诗/poet.song.69000.json','["日日思歸今得歸，朝衣不着着斑衣。", "誰人得似鄒居士，跳出輪回無是非。"]'),
('2b997219-bbe9-462f-806f-f37568fdad37','喜雨','鄒浩','宋','宋诗','song-poetry','','[]','不雨人憂旱，晨興忽沛然。',48,'全唐诗/poet.song.69000.json','["不雨人憂旱，晨興忽沛然。", "早禾欣長王，炎瘴敢留連。", "氣象還豐歲，歌謠動樂川。", "皇恩亦如此，特放我歸田。"]'),
('f18465f7-faf8-424a-ba7f-e18688df3f9d','將歸先寄道鄉','鄒浩','宋','宋诗','song-poetry','','[]','自作中都吏，道鄉難更居。',48,'全唐诗/poet.song.69000.json','["自作中都吏，道鄉難更居。", "今予返田里，就爾樂琴書。", "閉戶温生席，開窗涼滿裾。", "年來通物理，得計在淵魚。"]'),
('e100a0f4-e0ba-42f3-8dfd-a33016e1a6e4','川漲','鄒浩','宋','宋诗','song-poetry','','[]','昨朝清露石，今日漲汀灣。',48,'全唐诗/poet.song.69000.json','["昨朝清露石，今日漲汀灣。", "翕受無邊水，流來有衆山。", "魚龍隨浪躍，鷗鷺掠波還。", "因念盈虛數，高樓一破顔。"]'),
('16b7ecdd-743a-4810-84cf-0ee54bfcbc0a','山禽','鄒浩','宋','宋诗','song-poetry','','[]','何處飛來傍隱居，就中聲與衆禽殊。',32,'全唐诗/poet.song.69000.json','["何處飛來傍隱居，就中聲與衆禽殊。", "長拖緩轉嬌無力，一似汴孫吹畫烏。"]'),
('523e6497-68a1-449b-befb-273b0f871e93','憑欄','鄒浩','宋','宋诗','song-poetry','','[]','朝天坊裏朝天客，北去朝天已賜環。',32,'全唐诗/poet.song.69000.json','["朝天坊裏朝天客，北去朝天已賜環。", "從此昭平夢不到，賸憑欄檻看青山。"]'),
('3f478502-00c2-49be-be4e-ce9850aa6f34','修仁茶  其一','鄒浩','宋','宋诗','song-poetry','','[]','味如橄欖久方回，初苦終甘要得知。',32,'全唐诗/poet.song.69000.json','["味如橄欖久方回，初苦終甘要得知。", "不但炎荒能已疾，携歸北地亦相宜。"]'),
('ab9389ce-3e5e-42bf-bfd4-b4bb539cd5a0','修仁茶  其二','鄒浩','宋','宋诗','song-poetry','','[]','嶺南州縣接湖南，處處烹煎極口談。',32,'全唐诗/poet.song.69000.json','["嶺南州縣接湖南，處處烹煎極口談。", "北苑春芽雖絕品，不能消鬲禦煙嵐。"]'),
('8e89fbc3-6982-4e93-8b4e-dbcdf11216d7','修仁茶  其三','鄒浩','宋','宋诗','song-poetry','','[]','龍鳳新團出帝家，南人不顧自煎茶。',32,'全唐诗/poet.song.69000.json','["龍鳳新團出帝家，南人不顧自煎茶。", "夜光明月真投暗，悵望長安天一涯。"]'),
('af66987b-2c7f-4cbe-8354-1c47c6e7aa81','得家書','鄒浩','宋','宋诗','song-poetry','','[]','烏鵲每來簷外集，蛛絲時向眼邊明。',32,'全唐诗/poet.song.69000.json','["烏鵲每來簷外集，蛛絲時向眼邊明。", "心知有喜尋歸路，今日音書果見迎。"]'),
('a1a4c94c-31ea-40d9-973d-c6b1bf0a7a75','又得敷文書','鄒浩','宋','宋诗','song-poetry','','[]','一封黄勑下天關，嶺表湖南釋舊跧。',64,'全唐诗/poet.song.69000.json','["一封黄勑下天關，嶺表湖南釋舊跧。", "吏部回頭真可笑，拾遺作伴竟同還。", "張公洞裏花流水，揚子江邊雪滿山。", "更約家居多暇日，相從莫遣鬢毛斑。"]'),
('c4dec058-7755-4348-a0ab-ad937de3c871','懷成老','鄒浩','宋','宋诗','song-poetry','','[]','樂平主簿詹成老，平樂流人鄒至完。',64,'全唐诗/poet.song.69000.json','["樂平主簿詹成老，平樂流人鄒至完。", "莫逆於心心古道，不知其異異時官。", "一觴一詠風光勝，無咎無譽世界寛。", "北陌東阡好歸去，幅巾藜杖永相安。"]'),
('9593b7e6-f1f3-496c-badf-f1e1b711f29b','寄葛長源','鄒浩','宋','宋诗','song-poetry','','[]','平樂舂陵地接連，嶺南嶺北異風煙。',64,'全唐诗/poet.song.69000.json','["平樂舂陵地接連，嶺南嶺北異風煙。", "罪分輕重當如此，坐阻聲容空自憐。", "天上恩書來有日，湖邊歸路約同船。", "東門取醉鄰居耳，已辦金魚當酒錢。"]'),
('0ba9294f-1629-44ea-a29b-95b7e0b308be','静閲堂','鄒浩','宋','宋诗','song-poetry','','[]','左轄諸郎朝散君，頃年於此岸綸巾。',64,'全唐诗/poet.song.69000.json','["左轄諸郎朝散君，頃年於此岸綸巾。", "誰知還是風炎日，我亦來爲堂上人。", "菡蓞波澄端自倚，桄榔煙静幾番新。", "静中閲盡榮枯事，獨愛龍山萬古春。"]'),
('ff9d0656-562c-48ac-8f47-2085d1b2c2a9','山禽','鄒浩','宋','宋诗','song-poetry','','[]','異色殊形不可名，飛來飛去亦多情。',32,'全唐诗/poet.song.69000.json','["異色殊形不可名，飛來飛去亦多情。", "只應知我歸期近，故傍書帷送好聲。"]'),
('724fa70f-6c8a-4ba7-b363-1e39a2091765','晚步','鄒浩','宋','宋诗','song-poetry','','[]','緩步隨山徑，横前得野塘。',48,'全唐诗/poet.song.69000.json','["緩步隨山徑，横前得野塘。", "倚風荷展玉，带日鷺翹霜。", "霧歛都無瘴，天晴却自涼。", "搘笻愜新興，疑已到江鄉。"]'),
('9fb36072-590e-4e28-9ef5-859f1464db1c','記夢','鄒浩','宋','宋诗','song-poetry','','[]','廊廟知心獨此公，夜來魂夢忽相通。',32,'全唐诗/poet.song.69000.json','["廊廟知心獨此公，夜來魂夢忽相通。", "密言新命非虚語，所以流傳四海中。"]'),
('f2aafea8-076d-4cb3-846d-719c6a5bda1e','寄瑩中','鄒浩','宋','宋诗','song-poetry','','[]','天道無私果是非，斯人如鳳中人機。',64,'全唐诗/poet.song.69000.json','["天道無私果是非，斯人如鳳中人機。", "雄驚一矢從南落，雌領諸雛向北飛。", "且與龜龍爲伴侣，未應螻蟻損毛衣。", "吾皇致理肩虞舜，會見翺翔下德輝。"]'),
('376ac9f5-6bf3-4877-bf2c-b506ac2a6855','讀丘濬寺丞天繪亭記','鄒浩','宋','宋诗','song-poetry','','[]','襟懷落落富經綸，造命奇窮道不伸。',64,'全唐诗/poet.song.69000.json','["襟懷落落富經綸，造命奇窮道不伸。", "詩以百篇天上獻，身爲萬里幕中賓。", "每聽故老談風節，尚有遺文照水濱。", "聞說神遊已無礙，想經山頂亦逡巡。"]'),
('7e6eeebd-ada6-4cf8-ad2d-16b54f032117','讀龍圖梅公瘴說','鄒浩','宋','宋诗','song-poetry','','[]','市門隱去不知年，蔽芾甘棠蔭樂川。',64,'全唐诗/poet.song.69000.json','["市門隱去不知年，蔽芾甘棠蔭樂川。", "五瘴作時雖不染，一篇留誡指其然。", "直須鏤版人皆與，庶使綿區病可痊。", "更有奇方公未說，上醫醫國許心傳。"]'),
('5743f404-b3ec-4264-972d-ab2536f5db64','追感董敦逸夢授侍郎','鄒浩','宋','宋诗','song-poetry','','[]','臺陟蓮花見舊篇，追惟平昔倍凄然。',64,'全唐诗/poet.song.69000.json','["臺陟蓮花見舊篇，追惟平昔倍凄然。", "初爲百里青衫短，晚按連城白髮鮮。", "東省聯裾驚昨夢，南宮分袂忽新阡。", "使公雖老猶無恙，只恐投荒更我先。"]'),
('42bfcd0e-dfff-43a6-b824-d78c28d31534','寄零陵令朱君陟彦明推官','鄒浩','宋','宋诗','song-poetry','','[]','前時遞角惟憂速，今日郵筒只恐遲。',32,'全唐诗/poet.song.69000.json','["前時遞角惟憂速，今日郵筒只恐遲。", "書到零陵長官處，掀然一笑有誰知。"]'),
('20b939f6-3403-480c-b391-390cdfad1529','偶書','鄒浩','宋','宋诗','song-poetry','','[]','莫把形骸礙此心，此心真體杳難尋。',64,'全唐诗/poet.song.69000.json','["莫把形骸礙此心，此心真體杳難尋。", "太虚僅此一漚發，方寸能容萬象沉。", "無佛無人誰是我，不來不去妙常今。", "更須知有全提在，拄杖從横雲霧深。"]'),
('90bb1887-7875-4d28-9c87-26931f48559c','母氏安康郡太君生日三十韻','鄒浩','宋','宋诗','song-poetry','','[]','朱明初啟節，分卦屬純乾。',288,'全唐诗/poet.song.69000.json','["朱明初啟節，分卦屬純乾。", "善積名門久，祥開淑質賢。", "柔儀應月呂，和氣集薫絃。", "奕世儒風藹，持家禮法傳。", "乘龍來配德，采藻助承先。", "姑耄勤朝乳，功餘繹舊編。", "卜鄰嚴子教，截髮盛賓筵。", "萱草欣多豫，鳲鳩詠不偏。", "鄉閭師肅穆，坤道信完全。", "自輟齊眉奉，尤於內典専。", "三車窺至喻，一笑悟真筌。", "榮辱忘區别，優游任衆緣。", "居常遵坦路，方寸湛澄淵。", "浩也端愚陋，身兮數仆顛。", "范滂蒙訓敕，夢得念慈憐。", "放逐清湘外，覉縻蒼桂邊。", "遙知今日燕，想見瑞爐煙。", "弟姪紛爲壽，親朋儼造前。", "焚香控南斗，極目望東阡。", "鸞鶴翔仙嶺，龜魚動樂川。", "安康符郡號，昌熾賦詩篇。", "計已聞消息，惟新獲洗湔。", "賜環叨霈澤，衣綵即歸田。", "省定深如志，生成實荷天。"]'),
('a55d81a6-bd3e-4e38-9d4f-52441881dda0','寄蓬菜并示柄','鄒浩','宋','宋诗','song-poetry','','[]','皇帝如天極至公，恩光來自大明宮。',64,'全唐诗/poet.song.69000.json','["皇帝如天極至公，恩光來自大明宮。", "歸田實遂平生志，與汝難忘造化功。", "料得安康無限喜，信知理數莫能窮。", "吾今只候文書到，便挈囊衣迎北風。"]'),
('2e8cb804-4aa2-4e5b-86ce-97cd71dcfeb1','桂花','鄒浩','宋','宋诗','song-poetry','','[]','丹桂從來未發花，今年花發衆驚嗟。',64,'全唐诗/poet.song.69000.json','["丹桂從來未發花，今年花發衆驚嗟。", "盈盈簇蓋真珠細，片片籠車美玉斜。", "閶闔携香燻席綺，嫦娥流影動窗紗。", "乾坤着意欣逢遇，收得風光向北誇。"]'),
('e545e0c3-a427-46c1-aade-59babe766ce3','螢火','鄒浩','宋','宋诗','song-poetry','','[]','未解捐書常讀書，只緣炎瘴簡編疏。',32,'全唐诗/poet.song.69000.json','["未解捐書常讀書，只緣炎瘴簡編疏。", "夜深螢火猶相勉，無數飛光照閤居。"]'),
('db594013-d07c-4d1e-8e64-5f91d6637b5f','廣南四時攝養括子','鄒浩','宋','宋诗','song-poetry','','[]','仁者存心故不同，四時括子廣西東。',32,'全唐诗/poet.song.69000.json','["仁者存心故不同，四時括子廣西東。", "蒙恩歸去雖無用，留作韋弦戒我躬。"]'),
('1e2e98e9-723e-4b71-867d-3875f28a601d','覽鏡','鄒浩','宋','宋诗','song-poetry','','[]','三竄湖南與嶺南，生涯破蕩孰能堪。',32,'全唐诗/poet.song.69000.json','["三竄湖南與嶺南，生涯破蕩孰能堪。", "歸田莫慮饑寒迫，眼下新來有卧蠶。"]'),
('9dc8ce3e-375a-40cc-87fc-bdd87a30d785','追涼晚步邂逅張雲卿王文輔王子正三進士同行','鄒浩','宋','宋诗','song-poetry','','[]','巷僻門多掩，雞豚散不收。',48,'全唐诗/poet.song.69000.json','["巷僻門多掩，雞豚散不收。", "後先携衆士，笑語入汀洲。", "太尉廟前面，冠芝亭上頭。", "曠然無障礙，誰羨爾公侯。"]'),
('9485fe0d-b5f8-4a1c-9247-b1cbc1a6f5bb','過張雲卿所居','鄒浩','宋','宋诗','song-poetry','','[]','發石誅茅古道邊，儒家清占静中天。',64,'全唐诗/poet.song.69000.json','["發石誅茅古道邊，儒家清占静中天。", "數番雨水添塘水，滿目紅蓮間白蓮。", "望處蒼龍蟠遠嶽，坐來朱鷺舞祥烟。", "我心本在風塵表，偶此相羊更豁然。"]'),
('6c056137-d1fe-4a4e-aa0c-a3a0c366393c','讀莊子  其一','鄒浩','宋','宋诗','song-poetry','','[]','形影相隨向此居，柴門終日掩清虚。',32,'全唐诗/poet.song.69000.json','["形影相隨向此居，柴門終日掩清虚。", "誰知盤礴高堂上，自與南華遊物初。"]'),
('43f578a9-6d42-486b-91cc-b593105d2114','讀莊子  其二','鄒浩','宋','宋诗','song-poetry','','[]','萬物同爲一體真，體真誰復見陳新。',32,'全唐诗/poet.song.69000.json','["萬物同爲一體真，體真誰復見陳新。", "今吾故我强名耳，莫逆於心得此人。"]'),
('45433855-0454-480b-9fea-748e8eea4a6e','喜聞瑩中同預歸田之數','鄒浩','宋','宋诗','song-poetry','','[]','簡在天心世所知，賜環欣與我同歸。',64,'全唐诗/poet.song.69000.json','["簡在天心世所知，賜環欣與我同歸。", "耦耕曩已神先受，追路今休詠式微。", "洗脚上船無昨夢，舉頭見日有祥輝。", "扶搖本自南溟起，只恐難淹九萬飛。"]'),
('511b394e-794f-42a3-9963-8a1b02df58e7','栩栩軒','鄒浩','宋','宋诗','song-poetry','','[]','不知覺夢不知憂，物與心冥事事休。',32,'全唐诗/poet.song.69000.json','["不知覺夢不知憂，物與心冥事事休。", "此是道人真境界，西家分得亦同遊。"]'),
('00af6e74-43ca-4146-9fec-05d083021fc6','夢曾存之見過  其一','鄒浩','宋','宋诗','song-poetry','','[]','疋馬來過笑且言，廉州象郡亦同還。',32,'全唐诗/poet.song.69000.json','["疋馬來過笑且言，廉州象郡亦同還。", "今朝敕了明朝下，盡是君王獨斷間。"]'),
('119a66b0-d049-43a3-a775-a7d355e81e13','夢曾存之見過  其二','鄒浩','宋','宋诗','song-poetry','','[]','衡陽深賴帝憐之，論者雖多不遠移。',32,'全唐诗/poet.song.69000.json','["衡陽深賴帝憐之，論者雖多不遠移。", "一日一書誰管得，人生傾倒在相知。"]'),
('e835c003-30b8-4651-a556-8d65193d1c7c','聞歸田之命懷同廢諸公','鄒浩','宋','宋诗','song-poetry','','[]','同時廢逐十餘人，我是丹書第一名。',64,'全唐诗/poet.song.69000.json','["同時廢逐十餘人，我是丹書第一名。", "方向嶺邊思往咎，忽蒙天上許歸耕。", "諸公想亦茅連茹，此日宜皆水濯纓。", "覆載恩深力圖報，從今尤在罄精誠。"]'),
('746216ac-132f-4cfe-b0f0-719133b8c384','池上','鄒浩','宋','宋诗','song-poetry','','[]','荷花荷葉滿池塘，柄柄搖風作晚涼。',32,'全唐诗/poet.song.69000.json','["荷花荷葉滿池塘，柄柄搖風作晚涼。", "忽憶新開湖裏過，遶船終日送清香。"]'),
('9ea1606c-4104-4ce7-b606-21d0f9262243','留題天繪亭','鄒浩','宋','宋诗','song-poetry','','[]','杖屨追隨陟杳冥，無邊勝景集孤亭。',64,'全唐诗/poet.song.69000.json','["杖屨追隨陟杳冥，無邊勝景集孤亭。", "解衣自若誰爲史，造物難窮巧賦形。", "展拓二儀成縞素，均調一氣作丹青。", "會將斷取山川手，卷入中州挂戶庭。"]'),
('027cd952-35ca-455e-b674-7d66421f5a69','山鶘','鄒浩','宋','宋诗','song-poetry','','[]','大如青菜小如烏，色亦蒼然二者俱。',64,'全唐诗/poet.song.69000.json','["大如青菜小如烏，色亦蒼然二者俱。", "嗣歲不惟催布穀，可人尤是勸提壺。", "巧兼琴弄端誰使，追得年光賴爾呼。", "萱草堂高欣屬耳，筠籠隨我入東吳。"]'),
('775df939-0769-431e-b23b-3a28d2687535','遣感','鄒浩','宋','宋诗','song-poetry','','[]','我命還須我自推，細微休更問蓍龜。',32,'全唐诗/poet.song.69000.json','["我命還須我自推，細微休更問蓍龜。", "枯莖朽骨猶能兆，豈有靈臺不了知。"]'),
('836aa9d7-1a53-4208-87ba-6b2660fe85e2','鷾鴯','鄒浩','宋','宋诗','song-poetry','','[]','畏人常是襲人間，人不能傷自往還。',32,'全唐诗/poet.song.69000.json','["畏人常是襲人間，人不能傷自往還。", "争似鸞凰在寥廓，更無塵慮杳難攀。"]'),
('517d475e-39f8-45b5-850e-b57dd45acb78','觀赦文','鄒浩','宋','宋诗','song-poetry','','[]','吾皇恭己奉三無，大赦敷天孰向隅。',32,'全唐诗/poet.song.69000.json','["吾皇恭己奉三無，大赦敷天孰向隅。", "自顧歸田夙遭遇，與人同慶倍歡呼。"]'),
('39ad2b6e-8c79-48fe-95ae-38569d107d0a','留别元老','鄒浩','宋','宋诗','song-poetry','','[]','不因投竄抵昭平，争得相逢一笑親。',64,'全唐诗/poet.song.69000.json','["不因投竄抵昭平，争得相逢一笑親。", "塵裏妙空居士室，琴邊聊見宰官身。", "周顒尚以妻爲累，元亮惟知隱是真。", "莫逆于心更何語，撥開船子過牢津。"]'),
('f0681137-7984-42dc-8429-51876e86a68f','偶書','鄒浩','宋','宋诗','song-poetry','','[]','去年端午尚京居，骨肉團欒奉板輿。',32,'全唐诗/poet.song.69000.json','["去年端午尚京居，骨肉團欒奉板輿。", "今日菖蒲還薦酒，猶於嶺表待文書。"]'),
('0b87584a-7bb5-4987-b9f2-0297da3c0f75','重午王文輔送米食張雲卿送新酒來因成絕句','鄒浩','宋','宋诗','song-poetry','','[]','水糰糉子恰登門，白酒持來更滿樽。',32,'全唐诗/poet.song.69000.json','["水糰糉子恰登門，白酒持來更滿樽。", "節物人情總堪醉，况歸田里已承恩。"]'),
('87fbebaa-8576-4b39-8a8e-3e7d5b52e3e4','競渡','鄒浩','宋','宋诗','song-poetry','','[]','坊村一處一龍船，擘浪飛橈鬭欲先。',32,'全唐诗/poet.song.69000.json','["坊村一處一龍船，擘浪飛橈鬭欲先。", "要識晚來誰勝捷，但聽歌吹鼓聲喧。"]'),
('ab261e73-0aee-49fc-baf5-0991e7665cab','寄俞清老','鄒浩','宋','宋诗','song-poetry','','[]','卧龍前約竟悠悠，依舊淮南笑不休。',64,'全唐诗/poet.song.69000.json','["卧龍前約竟悠悠，依舊淮南笑不休。", "落髮出家成往事，從僧還俗愜新謀。", "未嘗異也誰燕越，相與呼之任馬牛。", "一滴曹溪好消息，爲君船子下揚州。"]'),
('a7c04d2f-6468-4842-a7bf-f5ef8c6128dc','夢立求軒名以其面蓮池十許頃名之曰妙喜軒','鄒浩','宋','宋诗','song-poetry','','[]','蓮華千葉滿前開，斷取應從妙喜來。',64,'全唐诗/poet.song.69000.json','["蓮華千葉滿前開，斷取應從妙喜來。", "色带日光飛縹緲，香乘風力轉徘徊。", "休尋物外菴羅果，且進池邊鸚鵡杯。", "一笑真能契無染，不妨遊戲挾霆雷。"]'),
('62550e2c-fe4c-45b9-ab34-9108a45279b4','偶書','鄒浩','宋','宋诗','song-poetry','','[]','白晝談禪木上座，清宵同夢竹夫人。',32,'全唐诗/poet.song.69000.json','["白晝談禪木上座，清宵同夢竹夫人。", "此心莫逆仙宮下，一片乾坤特地新。"]'),
('ca5c32f2-4ac9-42e3-a2b7-38a89ad822df','王道人云彦和得報有歸田之命','鄒浩','宋','宋诗','song-poetry','','[]','道人新自象州來，殿院從容得屢陪。',32,'全唐诗/poet.song.69000.json','["道人新自象州來，殿院從容得屢陪。", "坐上拆書歸有日，愁容忽作笑顔開。"]'),
('d192e93d-d065-400a-b2cb-cb0fc06ab1a3','醉者','鄒浩','宋','宋诗','song-poetry','','[]','至化無私被遠方，漁樵誰不似顛狂。',32,'全唐诗/poet.song.69000.json','["至化無私被遠方，漁樵誰不似顛狂。", "得錢沽酒争酬酢，執手高歌入醉鄉。"]'),
('efcc38c0-8982-4aa5-a848-2611d899ab3a','商丘','鄒浩','宋','宋诗','song-poetry','','[]','視人所不窺，修人所不爲。',24,'全唐诗/poet.song.69000.json','["視人所不窺，修人所不爲。", "奉以無愧怍，商丘是吾師。"]'),
('617a806a-c51c-4731-9cd6-234cfc3b6319','勉祖道修子美祠堂','鄒浩','宋','宋诗','song-poetry','','[]','工部云亡幾百年，精誠如在有遺編。',64,'全唐诗/poet.song.69000.json','["工部云亡幾百年，精誠如在有遺編。", "筆追六義回千古，名薄三光亘九天。", "師法周流寰海內，祠堂落寞楚江邊。", "長官風化尊賢急，想見丹青復煥然。"]'),
('ae3d3c3a-500d-4a6b-bd61-abf3b5d5edc7','追思去歲今日出京有作','鄒浩','宋','宋诗','song-poetry','','[]','解船東下出都門，倐已彌年詎可論。',32,'全唐诗/poet.song.69000.json','["解船東下出都門，倐已彌年詎可論。", "聖主只應憐舊物，歸歟朝夕被深恩。"]'),
('4e54e78a-795f-4bff-91d2-500a6cddbc3a','讀易','鄒浩','宋','宋诗','song-poetry','','[]','時時飛雨作清涼，六月南方似北方。',32,'全唐诗/poet.song.69000.json','["時時飛雨作清涼，六月南方似北方。", "閣上獨居無一事，韋編聊復到羲皇。"]'),
('616a19dc-c749-44bd-97c7-2a25b20950c0','偶書','鄒浩','宋','宋诗','song-poetry','','[]','白髮倚門無限情，江湖渺渺秋欲生。',32,'全唐诗/poet.song.69000.json','["白髮倚門無限情，江湖渺渺秋欲生。", "回船捩柁見歸路，天道無私憐汝誠。"]'),
('f248d3f1-5835-4715-b47a-6fe9427cf387','王氏閣舊名拾青郡守王藻以余寓居易名來仙','鄒浩','宋','宋诗','song-poetry','','[]','仙宮嶺下來仙閣，太守更名爲我來。',32,'全唐诗/poet.song.69000.json','["仙宮嶺下來仙閣，太守更名爲我來。", "來既有時歸有日，泠然從此御風回。"]'),
('a8ae4594-0b58-4d88-a20c-941f51007894','偶書  其一','鄒浩','宋','宋诗','song-poetry','','[]','形影相隨甫半年，皇恩今日放歸田。',32,'全唐诗/poet.song.69000.json','["形影相隨甫半年，皇恩今日放歸田。", "回頭一夢驚初覺，敢把窮通更問天。"]'),
('f299415e-e076-4069-bc8c-0b0e9345c008','偶書  其二','鄒浩','宋','宋诗','song-poetry','','[]','阻奉晨昏寧孝子，竄投荒遠豈忠臣。',32,'全唐诗/poet.song.69000.json','["阻奉晨昏寧孝子，竄投荒遠豈忠臣。", "今朝恩放歸田去，留得遺蹤警後人。"]'),
('d426470f-2e49-49e1-9675-3975e8f1495a','喜書','鄒浩','宋','宋诗','song-poetry','','[]','水北摘禾將欲了，水南發瘴已皆安。',32,'全唐诗/poet.song.69000.json','["水北摘禾將欲了，水南發瘴已皆安。", "憣然回指瀟湘去，感激天恩分外寛。"]'),
('5539dd21-6c3c-4c3c-94d5-01f2678f80e7','記夢','鄒浩','宋','宋诗','song-poetry','','[]','卜筮俱言七月嘉，夜來魂夢更高華。',32,'全唐诗/poet.song.69000.json','["卜筮俱言七月嘉，夜來魂夢更高華。", "此生豈復公卿望，惟喜斑衣早到家。"]'),
('9a57cd47-8c78-40be-8b52-96554f4f6cd2','聞仲殊長老化去甚異','鄒浩','宋','宋诗','song-poetry','','[]','逆行天莫測，雉作瀆中經。',48,'全唐诗/poet.song.69000.json','["逆行天莫測，雉作瀆中經。", "漚滅風前質，蓮開火後形。", "鉢盂殘蜜白，爐竈冷煙清。", "空有誰家曲，人間得細聽。"]'),
('5a1db3a1-a46b-4e09-b8f5-a8c40f43c7ba','感懷','鄒浩','宋','宋诗','song-poetry','','[]','去年今日别庭闈，回首庭闈未得歸。',32,'全唐诗/poet.song.69000.json','["去年今日别庭闈，回首庭闈未得歸。", "天道人心會相契，歸歟行即被恩輝。"]'),
('36502100-0c01-4013-9ab0-4ef4a240df9d','追懷去年今日舟離潤州有作','鄒浩','宋','宋诗','song-poetry','','[]','颿出丹陽恰一年，江湖陳跡慨茫然。',32,'全唐诗/poet.song.69000.json','["颿出丹陽恰一年，江湖陳跡慨茫然。", "明明歸路留雙目，只候恩書下九天。"]'),
('f4cc0b82-ace9-4be2-a608-34cdac260152','自歎','鄒浩','宋','宋诗','song-poetry','','[]','好學顔淵怒不遷，犯而不校古稱賢。',32,'全唐诗/poet.song.69000.json','["好學顔淵怒不遷，犯而不校古稱賢。", "伊予物觸心猶動，空撫陳編倍赧然。"]'),
('7b021401-66a3-4b19-a698-f6ea6f039dfa','主人忽來夾徑修籬','鄒浩','宋','宋诗','song-poetry','','[]','疏籬詰曲巧依山，洞徹柴門氣象還。',32,'全唐诗/poet.song.69000.json','["疏籬詰曲巧依山，洞徹柴門氣象還。", "恩釋覉留應有日，故先通路指鄉關。"]'),
('192cd83e-cc52-49c7-9690-91ce7e448343','大風累日不止','鄒浩','宋','宋诗','song-poetry','','[]','昭平八月稻禾風，吹盡浮雲露碧空。',32,'全唐诗/poet.song.69000.json','["昭平八月稻禾風，吹盡浮雲露碧空。", "日月從今無障礙，光明照我入天中。"]'),
('c94ef380-a482-4801-967c-e4a14f1122f6','贈萬胡主簿','釋懷古','宋','宋诗','song-poetry','','[]','廉可繼懸魚，官清術有餘。',48,'全唐诗/poet.song.7000.json','["廉可繼懸魚，官清術有餘。", "民田侵廢苑，公署似閑居。", "草長通囹圄，花飛落簿書。", "見君松操直，經考只如初。"]'),
('1c5d6c96-8eef-45e6-bc76-b987f26989dd','爛柯山二首  其一','釋懷古','宋','宋诗','song-poetry','','[]','仙家輕歲月，浮世重光陰。',48,'全唐诗/poet.song.7000.json','["仙家輕歲月，浮世重光陰。", "白髪有先後，青山無古今。", "局終柯已爛，塵散海尤深。", "若覓長生路，煙霞無處尋。"]'),
('f3e7cdfd-6ffa-426c-bcba-8f5116069dab','爛柯山二首  其二','釋懷古','宋','宋诗','song-poetry','','[]','王質爛柯事，傳聞不在疑。',48,'全唐诗/poet.song.7000.json','["王質爛柯事，傳聞不在疑。", "百年容易客，一局等閑棋。", "此著有誰見，無言祇自知。", "石橋南畔路，依舊日斜暉。"]'),
('53815354-1b39-4c47-b4bf-3dceb1a3cb29','句','釋懷古','宋','宋诗','song-poetry','','[]','霧開離草迥，風逆到花遲。',12,'全唐诗/poet.song.7000.json','["霧開離草迥，風逆到花遲。"]'),
('f0bb371d-7157-47e0-81e5-75cf59904738','存目','釋懷古','宋','宋诗','song-poetry','','[]','詩題：居天柱山首句：四野豁家庭。',16,'全唐诗/poet.song.7000.json','["詩題：居天柱山首句：四野豁家庭。"]'),
('97d30ede-32b2-4290-b898-8f214b6c650a','詩一首','吳黔','宋','宋诗','song-poetry','','[]','故國海雲端，歸寧便整鞍。',48,'全唐诗/poet.song.7000.json','["故國海雲端，歸寧便整鞍。", "里榮身上蒨，省罷手中蘭。", "燒急平蕪廣，風悲古木寒。", "謝公山色在，朝夕共誰觀。"]'),
('d26e994f-81ab-4d53-928e-e2c0bb87a579','送何輅歸錢塘兼簡辯端','釋智仁','宋','宋诗','song-poetry','','[]','家指西陵外，滄波去幾程。',48,'全唐诗/poet.song.7000.json','["家指西陵外，滄波去幾程。", "獨行山雪下，孤泊夜潮生。", "問路寒林迥，移舟宿雁驚。", "到逢天竺客，爲話別來情。"]'),
('bf28e65d-5e88-449a-aeb5-6e960b2baa7f','留題雲門寺','釋智仁','宋','宋诗','song-poetry','','[]','秦峰千古寺，豈易得躋攀。',48,'全唐诗/poet.song.7000.json','["秦峰千古寺，豈易得躋攀。", "一夢幾回到，片心長此閑。", "溪光涵石壁，秋色露松關。", "靜室孤禪後，寒鐘夜滿山。"]'),
('34c3d2ac-a9e4-4122-b8df-859e8c8bb22e','暮冬旅宿寄趙秀才','釋智仁','宋','宋诗','song-poetry','','[]','旅宿荒涼甚，幽懷可自寬。',48,'全唐诗/poet.song.7000.json','["旅宿荒涼甚，幽懷可自寬。", "風窗燈易滅，雪屋夜增寒。", "空迥鴻聲急，更餘旅夢殘。", "卻思君舊隱，欲到恨飛難。"]'),
('1dd2421c-ae05-419b-9fff-3a267612551e','句  其一','釋智仁','宋','宋诗','song-poetry','','[]','寒聲病葉落，曉色凍雲開。',12,'全唐诗/poet.song.7000.json','["寒聲病葉落，曉色凍雲開。"]'),
('fc097d56-eb85-451b-ae67-c74837e710bd','句  其二','釋智仁','宋','宋诗','song-poetry','','[]','路遙無去伴，山疊有啼猿。',12,'全唐诗/poet.song.7000.json','["路遙無去伴，山疊有啼猿。"]'),
('95caaceb-0779-49b2-adcb-cb9e0e75267d','句  其三','釋智仁','宋','宋诗','song-poetry','','[]','行客莫輕瑕璧謗，立人懷抱自分明。',16,'全唐诗/poet.song.7000.json','["行客莫輕瑕璧謗，立人懷抱自分明。"]'),
('0c57362d-4c7e-434a-92cd-8a373185604c','平水神祠歌','陳賡','宋','宋诗','song-poetry','','[]','黄河如絲導崑崙，萬里南下突禹門。',258,'全唐诗/poet.song.7000.json','["黄河如絲導崑崙，萬里南下突禹門。", "支流潛行天地底，派作八道如霆奔。", "吾聞川真嶽靈有真宰，況乃利澤開洪源。", "龍神窟宅瞰平野，千古廟貌何雄尊。", "深林含蓄雷雨潤，冷殿似带波濤痕。", "我來南州走塵坌，執熱未濯憂思煩。", "試斟百冽洗肝肺，一勺注腹清且燉。", "悠然晞風坐東廡，倏見繪畫如飛騫。", "仙宮華裾乘朱軒，旗纛掩藹蛟伏轅。", "雷公電母踏煙霧，天吳海若驅鼉黿。", "何時借取霹靂手，倒挽銀漢清乾坤。", "廟前老翁顧我語，孺子未易排天閽。", "何爲高論乃如此，一笑春風滿面溫。", "是時三月遊人繁，男女雜遝簫鼓喧。", "騫茭沈玉笑靈貺，割牲釃酒傳巫言。", "巫言恍惚廟扉闔，拜手上馬山煙昏。"]'),
('07418c5a-c5de-4fea-b04c-00db9c5210e6','詩一首','韓退','宋','宋诗','song-poetry','','[]','山人跨雪精，上便不論程。',24,'全唐诗/poet.song.7000.json','["山人跨雪精，上便不論程。", "嗅地打不動，笑天休始行。"]'),
('40bd7237-9b8e-4fe3-aa0f-2888244eda5a','游泰山靈巖寺','滕涉','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','山半舊招提，捫蘿躡石梯。',120,'全唐诗/poet.song.7000.json','["山半舊招提，捫蘿躡石梯。", "佳名標四絕，勝境出三齊。", "殿古煙霞窟，庭深檜柏蹊。", "嶽靈分地界，雲險接天倪。", "香篆清風褭，松廊翠巘低。", "飛塵無路入，幽鳥隔巖啼。", "破夢泉聲急，飄涼竹韻凄。", "微陽生頂上，殘月落峰西。", "暫到猶塵慮，長居信覺迷。", "致君功業就，向此卜幽棲。"]'),
('54390206-0cbb-4c43-8b62-9de48d81a6d8','題釣臺','張保雝','宋','宋诗','song-poetry','','[]','漢包六合網英豪，一箇冥鴻惜羽毛。',32,'全唐诗/poet.song.7000.json','["漢包六合網英豪，一箇冥鴻惜羽毛。", "世祖功臣三十二，雲臺何似釣臺高。"]'),
('48a7d0d4-b94c-450d-a905-9407c76ff95e','送僧歸護國寺','馮元','宋','宋诗','song-poetry','','[]','南宗開士共推賢，語默忘機合自然。',64,'全唐诗/poet.song.7000.json','["南宗開士共推賢，語默忘機合自然。", "上國經游雲出岫，故山歸去鶴沖天。", "艤舟卻指靈溪岸，烹茗還資瀑布泉。", "宴坐草堂諸念息，只應餘習在詩篇。"]'),
('841c6620-f495-432a-be00-464d8eff46de','詩贈晚學李君  其一','邢仙老','宋','宋诗','song-poetry','','[]','虚皇天詔下仙家，不久星横借客槎。',64,'全唐诗/poet.song.7000.json','["虚皇天詔下仙家，不久星横借客槎。", "壁上風雲三尺劍，林前龍虎一爐砂。", "行乘海嶼千年鶴，坐折壺中四季花。", "爲愛陰符問玄義，更隨驪海入烟霞。"]'),
('1e00a01d-8498-4aa9-b51d-c7e3370e48ba','詩贈晚學李君  其二','邢仙老','宋','宋诗','song-poetry','','[]','久掩山齋看古經，但矜猿鶴事高情。',64,'全唐诗/poet.song.7000.json','["久掩山齋看古經，但矜猿鶴事高情。", "爐中且喜丹砂死，巖下近聞朱草生。", "堪鄙塵寰馳妄理，莫敎流俗聽希聲。", "清溪有路無人識，獨弄滄浪一濯纓。"]'),
('b1ed2dfa-d227-4410-9190-025ff8d3b0f4','詩贈晚學李君  其三','邢仙老','宋','宋诗','song-poetry','','[]','詰曲川原幾里深，偶尋巖壑在前林。',64,'全唐诗/poet.song.7000.json','["詰曲川原幾里深，偶尋巖壑在前林。", "長懷萬古典墳樂，果稱幾年泉石心。", "將看道經延白日，偷收巖藥化黄金。", "山中所訪逍遙客，爲報白雲深處尋。"]'),
('f7f6b2cc-186e-4e15-a290-e676544bd781','詩贈晚學李君  其四','邢仙老','宋','宋诗','song-poetry','','[]','人稀境盡絕塵埃，野客尋源或到來。',64,'全唐诗/poet.song.7000.json','["人稀境盡絕塵埃，野客尋源或到來。", "怪石結成真洞府，亂山堆就假樓臺。", "久窮至理難期老，獨放真機學未該。", "得共山翁話虚寂，不妨巖下且徘徊。"]'),
('57d59b40-de08-45fa-a359-b5c94cd9491b','詩贈晚學李君  其五','邢仙老','宋','宋诗','song-poetry','','[]','翠微堆裏隱雲烟，石縛藤蘿小洞天。',64,'全唐诗/poet.song.7000.json','["翠微堆裏隱雲烟，石縛藤蘿小洞天。", "常篆丹符驅木魅，毎呼山鬼汲溪泉。", "養成玉座千年石，煉過河車九轉鉛。", "記得潛虚真伴侣，出門争贈買山錢。"]'),
('666c01c9-975c-49bf-a5e8-0078ddd9b04c','詩贈晚學李君  其六','邢仙老','宋','宋诗','song-poetry','','[]','秋景澄清物象希，山家沈寂俗難齊。',64,'全唐诗/poet.song.7000.json','["秋景澄清物象希，山家沈寂俗難齊。", "常聽嶺瀑連雲瀉，時有林猿隔岫啼。", "月黑笈明靈武動，夜寒囊破蹇驢嘶。", "此身已脫人間世，贏得烟蘿自在題。"]'),
('fdd0346f-c99f-431b-b03c-d661543391da','詩贈晚學李君  其七','邢仙老','宋','宋诗','song-poetry','','[]','丹雄初伏櫃方靈，萬里蓬壺第一程。',64,'全唐诗/poet.song.7000.json','["丹雄初伏櫃方靈，萬里蓬壺第一程。", "神室下封添夜火，金砂新浴煉真形。", "稚川篋裏藏丹訣，鴻寶方中檢藥名。", "既得仙人小龍虎，便尋根本到長生。"]'),
('1a3c0c8b-b0f1-4516-b2c9-dd466ba24013','詩贈晚學李君  其八','邢仙老','宋','宋诗','song-poetry','','[]','旋滴巖頭石裏泉，研硃將點洞靈篇。',64,'全唐诗/poet.song.7000.json','["旋滴巖頭石裏泉，研硃將點洞靈篇。", "只看壁外數千卷，勝走人間三百年。", "何事投心求妙友，便須窮力到真仙。", "竹間松逕逍遙境，雅使仙翁恣意眠。"]'),
('edb536c2-cb7c-4070-92d6-1a3b80500b90','詩贈晚學李君  其九','邢仙老','宋','宋诗','song-poetry','','[]','眼前龍虎實紛紜，說破丹砂世莫聞。',64,'全唐诗/poet.song.7000.json','["眼前龍虎實紛紜，說破丹砂世莫聞。", "故脫衣冠尋舊隱，便將猿鶴入深雲。", "閒編野錄前朝事，静校仙經古篆文。", "滿腹分明惟是識，塵寰誰認紫陽君。"]'),
('558aa311-068b-4a3c-a3bc-aed4d0db9de0','詩贈晚學李君  其一○','邢仙老','宋','宋诗','song-poetry','','[]','無言隱几閉松扃，萬古襟懷獨自靈。',64,'全唐诗/poet.song.7000.json','["無言隱几閉松扃，萬古襟懷獨自靈。", "點筆時研三卷篆，彈冠嘗動一簪星。", "青童去撅南山木，野客來尋北帝經。", "天道不須窺牖見，滿門山岳自青青。"]'),
('005386be-ecb5-4447-8f8c-9731e45353c5','詩贈晚學李君  其一一','邢仙老','宋','宋诗','song-poetry','','[]','山家何物是知音，也勝人間枉用心。',64,'全唐诗/poet.song.7000.json','["山家何物是知音，也勝人間枉用心。", "學就萬年龜喘息，習成千歲鶴呻吟。", "沖和久養靈通獸，關節常調不死禽。", "獨對翠微誰更問，鼎分三足伴光陰。"]'),
('e9a589fc-8936-4f39-bc93-a67f7bbd4be9','詩贈晚學李君  其一二','邢仙老','宋','宋诗','song-poetry','','[]','世事功名不足論，好乘年少入真門。',64,'全唐诗/poet.song.7000.json','["世事功名不足論，好乘年少入真門。", "渾如一夢莊仙蝶，況是千年柱史文。", "須向黄庭分內外，不交周易秘乾坤。", "他年陵谷還遷變，家住蓬瀛我尚存。"]'),
('863b5ce9-e5b7-47b1-a716-114b0d78a07e','詩贈晚學李君  其一三','邢仙老','宋','宋诗','song-poetry','','[]','日轉蓬窗影漸移，羅浮舊隱到多時。',32,'全唐诗/poet.song.7000.json','["日轉蓬窗影漸移，羅浮舊隱到多時。", "瀛洲伴侣無消息，風撼巖前紫桂枝。"]'),
('6a12e54c-b70c-4507-837d-92584abd1bec','秋夜','郭昭著','宋','宋诗','song-poetry','','[]','秋空澹澹天無極，東望平林凈如拭。',64,'全唐诗/poet.song.7000.json','["秋空澹澹天無極，東望平林凈如拭。", "清光倒湧冰輪寒，山河吸作玻璃色。", "主人對此欲凌風，瑤光浮白珍珠紅。", "留連中夜不知倦，酣歌驚動蛇龍宮。"]'),
('20879667-b5c2-4147-a266-4b56fde15ed6','塞上曲','郭昭著','宋','宋诗','song-poetry','','[]','胡馬秋肥塞草黄，彎弧直擬犯漁陽。',32,'全唐诗/poet.song.7000.json','["胡馬秋肥塞草黄，彎弧直擬犯漁陽。", "歸鞭卻避弓閭水，知是嫖姚舊戰場。"]'),
('411f8e12-dc96-4444-8745-6dd90b2c9e69','登立魚峰','覃慶元','宋','宋诗','song-poetry','','[]','載酒聽鶯語，春風到處吹。',24,'全唐诗/poet.song.7000.json','["載酒聽鶯語，春風到處吹。", "魚峰如有約，蠟屐正相宜。"]'),
('22d48383-c2e8-4ae0-a9e2-dc7274a17a6c','贈黄孫二處士','張及','宋','宋诗','song-poetry','','[]','二公高節厭喧卑，同寄蕭宮共展眉。',64,'全唐诗/poet.song.7000.json','["二公高節厭喧卑，同寄蕭宮共展眉。", "玉樹冰壺齊品格，野雲臯鶴本追隨。", "泉流指下何人賞，嶽峭毫端祇自知。", "綣戀賢侯美風教，故山歸去尚遲遲。"]'),
('1a6519cf-a4ae-4870-972c-178343d9c643','贈杜鼎昇','張及','宋','宋诗','song-poetry','','[]','家本樊川老蜀都，世家冠劍豈寒儒。',64,'全唐诗/poet.song.7000.json','["家本樊川老蜀都，世家冠劍豈寒儒。", "年耕尚可儲三載，酒戰猶能敵百夫。", "僻愛舜琴湘水弄，每懸孫畫醉仙圖。", "孟光笑語長相逐，喚作梁鴻得也無。"]'),
('61be1c7c-618e-4c4b-9062-64349bd83366','夢中作','張君房','宋','宋诗','song-poetry','','[]','亭尤逢夜竹，不識自知音。',24,'全唐诗/poet.song.7000.json','["亭尤逢夜竹，不識自知音。", "朦朧望明月，終得拂青塵。"]'),
('0d727282-1adc-4a37-ab7b-e3a6080a70f9','雨中望蓬萊山','張君房','宋','宋诗','song-poetry','','[]','重簾垂密雨，孤夢隔秋宮。',48,'全唐诗/poet.song.7000.json','["重簾垂密雨，孤夢隔秋宮。", "紅爐九華暗，香消芳思融。", "仙忻望不及，鶴信遣誰通。", "但云許玉斧，寧知張巨公。"]'),
('4bbf14e5-1fb2-4ff8-a55d-cb38d2c671f3','句','令狐揆','宋','宋诗','song-poetry','','[]','借書離近郭，冒雪渡寒溪。',12,'全唐诗/poet.song.7000.json','["借書離近郭，冒雪渡寒溪。"]'),
('2d97546d-13f5-4b65-ab54-9d5b5604b882','青溪晚霽','吳漣','宋','宋诗','song-poetry','','[]','天晚雨初霽，隔溪聞碓舂。',48,'全唐诗/poet.song.7000.json','["天晚雨初霽，隔溪聞碓舂。", "山僧歸夜月，幽鳥落長松。", "風靜砧聲急，花欹露氣重。", "良宵思沅芷，尊酒話從容。"]'),
('e43644f6-f316-4d18-9611-0c8944e896fc','送梵才上人歸天台','徐舜俞','宋','宋诗','song-poetry','','[]','芳袍麟殿賜蒲茸，道勝年來謁慵。',63,'全唐诗/poet.song.7000.json','["芳袍麟殿賜蒲茸，道勝年來謁慵。", "貝葉罷翻雙鳳闕，石房歸掩五芝峰。", "朝賢遠乞裁詩稿，海客爭傳出定容。", "後代何人續僧史，好將安遠比高蹤。"]'),
('ab4e1953-03a6-4147-8232-0e31b684c063','句','江任','宋','宋诗','song-poetry','','[]','珠盤臨路泣，斗印入鄉提。',12,'全唐诗/poet.song.7000.json','["珠盤臨路泣，斗印入鄉提。"]'),
('31979840-98b7-4d0a-aaab-ffc561b90b72','等法院','江白','宋','宋诗','song-poetry','','[]','滿路煙花畫不成，棲桐佳致古流名。',65,'全唐诗/poet.song.7000.json','["滿路煙花畫不成，棲桐佳致古流名。", "院鄰翠障千尋碧，門抗寒溪一带清。", "晝影亂本來遮暑氣，晚涼疏雨送秋聲。", "我來到多慵回首，倚檻吟看海月生。"]'),
('ee704df1-7835-4b53-adef-ac1751083e62','送梅昌言出鎮太原','黄覺','宋','宋诗','song-poetry','','[]','五馬雍容出鎮時，都人爭看好風儀。',96,'全唐诗/poet.song.7000.json','["五馬雍容出鎮時，都人爭看好風儀。", "文章一代喧高價，忠直三朝受聖知。", "帳下軍容生劍戟，門前行色擁旌旗。", "雲籠古戍黄榆暗，雪滿長郊白草衰。", "出去暫開貔虎幕，歸來須占鳳皇池。", "鬢間未有一莖白，陶鑄蒼生固不遲。"]'),
('8527e95e-86a6-40cb-bd33-a5614a691839','句','黄覺','宋','宋诗','song-poetry','','[]','床頭曆日無多字，屈指明年七十三。',16,'全唐诗/poet.song.7000.json','["床頭曆日無多字，屈指明年七十三。"]'),
('760b9383-495c-41e3-9ce1-d0b339f80ce7','使華亭','翁緯','宋','宋诗','song-poetry','','[]','走清奔碧日潺湲，勢與晴江遠接連。',64,'全唐诗/poet.song.7000.json','["走清奔碧日潺湲，勢與晴江遠接連。", "沙草碧侵驅馬路，岸花紅濕釣魚船。", "煙生遠店收寒雨，風起高梧咽暮蟬。", "徐氏舊居人識否，渡南溪下白雲邊。"]'),
('90f8d20f-55fc-490e-9fb4-4cca5e748205','送張無夢歸天台','陳既濟','宋','宋诗','song-poetry','','[]','暫到京城住，辭堯返舊廬。',48,'全唐诗/poet.song.7000.json','["暫到京城住，辭堯返舊廬。", "身耽泉石樂，心向利名疏。", "鶴靜來華表，雲閑出太虛。", "錢塘應過日，秋水滿紅蕖。"]'),
('fd13ecaa-57e9-44bf-b8eb-9044954ffa27','游洞霄','范寬之','宋','宋诗','song-poetry','','[]','征輪偷暇款琳宮，洞水浮花二月中。',32,'全唐诗/poet.song.7000.json','["征輪偷暇款琳宮，洞水浮花二月中。", "塵慮坐清歸意懶，渙襟高詠紫霄風。"]'),
('4a5b28a8-aa02-44fd-a7da-1aecdb8621fc','句  其一','袁抗','宋','宋诗','song-poetry','','[]','許鄉松老神仙遠，葛井丹成日月長。',16,'全唐诗/poet.song.7000.json','["許鄉松老神仙遠，葛井丹成日月長。"]'),
('1696e7ae-4c08-470e-8911-1f319f3c639a','句  其二','袁抗','宋','宋诗','song-poetry','','[]','壓江揖翠鎮庚方，一带藍光屬豫章。',16,'全唐诗/poet.song.7000.json','["壓江揖翠鎮庚方，一带藍光屬豫章。"]'),
('5c9be135-d9b5-4b66-bf8f-d93ce232d6cb','送僧歸護國寺','張師德','宋','宋诗','song-poetry','','[]','喜陪人傑論三乘，巖室經年鎖翠稜。',64,'全唐诗/poet.song.7000.json','["喜陪人傑論三乘，巖室經年鎖翠稜。", "六代有師傳法印，萬緣無象監心燈。", "赤城道遠明霞畫，瀑布聲寒月照冰。", "迹似孤雲縻不得，清秋歸興杖蠻藤。"]'),
('5fcae4f9-3280-488d-b695-ae26b66f0dcc','老兒詩亦五十韻','張師錫','宋','宋诗','song-poetry','','[]','鬢髮盡皤然，眉分白雪鮮。',288,'全唐诗/poet.song.7000.json','["鬢髮盡皤然，眉分白雪鮮。", "週遮延客話，傴僂抱孫憐。", "無病常供粥，非寒亦衣綿。", "假溫衾擁背，借力仗搘肩。", "貌比三峰客，年過四皓仙。", "喚方離枕上，扶始到門前。", "毎愛烹山茗，常嫌飣石蓮。", "耳聾如塞纊，眼暗似籠烟。", "宴坐羸憑几，乘騎困嚲鞭。", "頭搖如轉旋，唇動若抽牽。", "骨冷愁離火，牙疼怯漱泉。", "形骸將就木，嚢槖尚貪錢。", "膠睫乾眵綴，黏髭冷涕懸。", "披裘腰懶繫，濯手袖慵揎。", "擡舉衣頻喚，扶持藥屢煎。", "坐多茵易破，行少履難穿。", "喜婢裁裙布，嗔妻買粉鈿。", "房教深下幕，牀遣厚鋪氈。", "琴聽憐三樂，圖張笑七賢。", "看嫌經字小，敲磬喜聲圓。", "食罷羹流袂，杯餘酒带涎。", "樂來須遣罷，醫到久相延。", "裹帽縱横掠，梳頭取次纒。", "長吁思往事，多感聽哀絃。"]'),
('4ff21362-8c40-4924-8281-97d567e0dd38','喜子及第','張師錫','宋','宋诗','song-poetry','','[]','御榜今朝至，見名心始安。',48,'全唐诗/poet.song.7000.json','["御榜今朝至，見名心始安。", "爾能俱中第，吾遂可休官。", "賀客留連飲，家書反覆看。", "世科誰不繼，得慰二親難。"]'),
('19d68b9e-3c0f-4c12-b5b1-4590b583c297','送程給事知越州','張師顔','宋','宋诗','song-poetry','','[]','才臣新命輟卿聯，漕挽于今委重官。',64,'全唐诗/poet.song.7000.json','["才臣新命輟卿聯，漕挽于今委重官。", "一道去蠲民疾苦，重江甯恤路艱難。", "行舟使節威聲遠，祖帳都門暑氣殘。", "奏課佇聞居上等，歸來恩異聳羣觀。"]'),
('449b5884-b0e0-414a-9309-8822f0ad68fd','書壁','釋谷泉','宋','宋诗','song-poetry','','[]','余此芭蕉庵，幽居堆雲處。',52,'全唐诗/poet.song.7000.json','["余此芭蕉庵，幽居堆雲處。", "般般異境未暇數，且看矮松三四樹。", "寒來燒枯杉，饑食大紫芋。", "而今拋之去，不知誰來住。"]'),
('2859ffe8-d928-47c7-9ca2-36c54fad3f79','偈','釋谷泉','宋','宋诗','song-poetry','','[]','今期甚好雪，紛紛如秋月。',24,'全唐诗/poet.song.7000.json','["今期甚好雪，紛紛如秋月。", "文殊不出頭，普賢呈醜拙。"]'),
('7765dbf7-4829-4f67-bfd7-a52d27cd556a','贈古調奴','釋谷泉','宋','宋诗','song-poetry','','[]','我有山童名古調，不誦經，不禮祖。',48,'全唐诗/poet.song.7000.json','["我有山童名古調，不誦經，不禮祖。", "解搬榾柮禦冬寒，隨分衣裳破不補。", "會栽蔬，能種芋，千山萬山去無懼。"]'),
('7fa4d7de-b974-4345-97c4-fc25e94bbc45','省慈明禪師還而作偈','釋谷泉','宋','宋诗','song-poetry','','[]','相別而今又半年，不知誰共對談禪。',32,'全唐诗/poet.song.7000.json','["相別而今又半年，不知誰共對談禪。", "一般秀色湘山裏，汝自匡徒我自眠。"]'),
('38461336-9683-431f-9442-9b17d222e0e4','有詣常寧拜舍利塔者以偈贈之','釋谷泉','宋','宋诗','song-poetry','','[]','諸禪結伴遊玉塔，靈蹤勝境將心劄。',96,'全唐诗/poet.song.7000.json','["諸禪結伴遊玉塔，靈蹤勝境將心劄。", "歸來舉似春如何，何似狂僧無縫塔。", "無縫塔，最難邈，豈同白玉受人踏。", "五湖四海盡雲奔，踏破幾多茥與靸。", "無縫塔，甚匼匝，若遇同人方始答。", "忽然展手借樣看，便與攔腮鼓一搭。"]'),
('737a0cca-17a2-4c59-8a88-7a36b0d6a6fa','偈','釋谷泉','宋','宋诗','song-poetry','','[]','今朝六月六，谷泉被氣𡎺。',24,'全唐诗/poet.song.7000.json','["今朝六月六，谷泉被氣𡎺。", "不是上天堂，便是入地獄。"]'),
('faec1cc8-d20f-475c-af7e-3a38a9fc14db','擬洛下分題 松石琴薦','釋智圓','宋','宋诗','song-poetry','','[]','松石爲琴薦，鱗皴狀頗奇。',48,'全唐诗/poet.song.7000.json','["松石爲琴薦，鱗皴狀頗奇。", "補天雖變質，映澗尚含滋。", "靜砌和煙立，虛堂带蘚移。", "最宜彈別鶴，況有舊棲枝。"]'),
('8b6c70ae-5bb0-4394-ac0b-01974e2f7585','擬洛下分題 茯苓人','釋智圓','宋','宋诗','song-poetry','','[]','本自松根得，名因象物彰。',48,'全唐诗/poet.song.7000.json','["本自松根得，名因象物彰。", "爲醫君可信，除疾我偏良。", "濟衆應藏用，捐軀必自強。", "無勞問蹤跡，名字在仙方。"]'),
('4aaf9d3e-fa06-48dd-a151-ab9f2c940338','擬洛下分題 遞詩筒','釋智圓','宋','宋诗','song-poetry','','[]','元白舊裁製，規模傳至今。',48,'全唐诗/poet.song.7000.json','["元白舊裁製，規模傳至今。", "凌霜重高節，容物貴虛心。", "豈倦關河遠，寧辯雨雪深。", "雅言如見託，終爲報知音。"]'),
('65dea48b-e8f5-427a-bb1a-1de4c9799fa0','擬洛下分題 文石酒杯','釋智圓','宋','宋诗','song-poetry','','[]','良匠鑿頑璞，爲杯異彩存。',48,'全唐诗/poet.song.7000.json','["良匠鑿頑璞，爲杯異彩存。", "雲蒸猶有潤，蘚駮已無痕。", "靜愛如冰潔，閑憐似玉溫。", "野民便古質，長把近漥罇。"]'),
('09f75267-b8ee-495b-a6dd-f6c1917c318c','友人元敏示以三題乃賡而和之 挑燈杖','釋智圓','宋','宋诗','song-poetry','','[]','裁製削青筠，纖纖狀可珍。',48,'全唐诗/poet.song.7000.json','["裁製削青筠，纖纖狀可珍。", "助燈雖有力，舉用實由人。", "破暗如無怠，資明敢顧身。", "窗間儻勤學，終夕願相親。"]'),
('0476b7e7-27c0-46fe-9267-3eda38128cca','友人元敏示以三題乃賡而和之 刮字刀','釋智圓','宋','宋诗','song-poetry','','[]','質本精剛化，鋒鋩豈易羣。',48,'全唐诗/poet.song.7000.json','["質本精剛化，鋒鋩豈易羣。", "未曾傷正典，長爲鏟訛文。", "類與鉛刀異，名將彩筆分。", "刪書及定禮，曾忝立奇勛。"]'),
('1f51836a-a6d7-42a3-a4c2-356483e18efe','友人元敏示以三題乃賡而和之 試金石','釋智圓','宋','宋诗','song-poetry','','[]','真僞立可辨，貞姿號試金。',48,'全唐诗/poet.song.7000.json','["真僞立可辨，貞姿號試金。", "雖無褒貶口，似有是非心。", "採取山溪遠，緘藏篋笥深。", "鑛人如未訣，終日自相尋。"]'),
('089f27f5-9dd8-4033-9530-866cd21a400a','燭蛾誡','釋智圓','宋','宋诗','song-poetry','','[]','有蟲名燭蛾，翱翔近燈火。',48,'全唐诗/poet.song.7000.json','["有蟲名燭蛾，翱翔近燈火。", "舉手再三遮，彼意終不可。", "驅去復飛來，防護更勞我。", "汝無縱所見，自取燋肌禍。"]'),
('034521c8-79ed-4ad5-8187-9c4559702b74','挽歌詞三首  其一','釋智圓','宋','宋诗','song-poetry','','[]','平生宗釋復宗儒，竭慮研精四體枯。',32,'全唐诗/poet.song.7000.json','["平生宗釋復宗儒，竭慮研精四體枯。", "莫待歸全寂無語，始知諸法本來無。"]'),
('72dd649b-e878-443f-bcfe-699c15f48e36','挽歌詞三首  其二','釋智圓','宋','宋诗','song-poetry','','[]','蕭蕭墓後千竿竹，鬰鬰墳前一樹松。',32,'全唐诗/poet.song.7000.json','["蕭蕭墓後千竿竹，鬰鬰墳前一樹松。", "此處不須兄弟哭，自然相對起悲風。"]'),
('73cd6b1d-c8a4-40af-bc27-f6c2abf38a33','挽歌詞三首  其三','釋智圓','宋','宋诗','song-poetry','','[]','莫談生滅與無生，謾把心神與物爭。',32,'全唐诗/poet.song.7000.json','["莫談生滅與無生，謾把心神與物爭。", "陶器一藏松樹下，綠苔芳草任縱橫。"]'),
('3ad3777f-2d72-4c2d-b188-309188045dda','瑪瑙坡四詠  其一','釋智圓','宋','宋诗','song-poetry','','[]','瑪瑙坡前樹，春來亦著華。',24,'全唐诗/poet.song.7000.json','["瑪瑙坡前樹，春來亦著華。", "雨晴煙乍斂，濃艷鬬朝霞。"]'),
('7d264b83-0f80-48e0-95b7-f5d2a27e8ca9','瑪瑙坡四詠  其二','釋智圓','宋','宋诗','song-poetry','','[]','瑪瑙坡前水，泠泠夏亦寒。',24,'全唐诗/poet.song.7000.json','["瑪瑙坡前水，泠泠夏亦寒。", "夜深明月上，珠顆落冰盤。"]'),
('dabe2453-0091-4c04-9c68-2a1ff3e4ab62','瑪瑙坡四詠  其三','釋智圓','宋','宋诗','song-poetry','','[]','瑪瑙坡前路，秋宵獨倚筇。',24,'全唐诗/poet.song.7000.json','["瑪瑙坡前路，秋宵獨倚筇。", "草深藏鬼火，苔老絕人蹤。"]'),
('94f1c844-9de6-4e89-a844-1390437f46c3','瑪瑙坡四詠  其四','釋智圓','宋','宋诗','song-poetry','','[]','瑪瑙坡前石，堅貞可補天。',24,'全唐诗/poet.song.7000.json','["瑪瑙坡前石，堅貞可補天。", "女媧何處去，冷落沒寒煙。"]'),
('067a2a15-c88d-496b-8452-9038f3f9e743','送惟鳳師歸四明','釋智圓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','未識鳳師面，早熟鳳師名。',288,'全唐诗/poet.song.7000.json','["未識鳳師面，早熟鳳師名。", "毓靈本岷峨，弱冠遊神京。", "出處忌非類，交結皆名卿。", "高談駭衆聽，雅唱歸羣英。", "曩歲來淛陽，相逢水心亭。", "論懷道且同，對坐眼彌青。", "尋幽泛輕舟，待月步閑庭。", "翌日倏分攜，南北各如萍。", "我尋住孤山，師亦往東明。", "人間一爲別，天上七周星。", "江湖既相望，喣沫安足評。", "今年春之暮，草堂花飄零。", "睡起乍憑欄，竹外聞人聲。", "忽報鳳師至，屣履出相迎。", "借問胡爲來，告我以其誠。", "度支司外計，夕拜臨茲城。", "二賢俱我舊，故得尋其盟。", "夏來西湖西，爲鄰樂幽貞。", "朝登隱君堂，暮叩中庸扃。", "引望雲山遙，銷暑竹風清。", "論詩貴無邪，體道極無形。", "倏忽時節移，秋風拂簷楹。", "趨裝俄告別，鄞江指歸程。", "適來既無事，適去豈關情。"]'),
('fd18de31-b955-4097-85b5-2a39312cf369','試筆','釋智圓','宋','宋诗','song-poetry','','[]','城市居無分，山林住有緣。',96,'全唐诗/poet.song.7000.json','["城市居無分，山林住有緣。", "語慚甘似薺，道貴直如弦。", "兀兀吟終日，羸羸病過年。", "靜招湖畔鶴，閑泛雪中船。", "散悶雖無酒，怡情喜有禪。", "鬢根霜任點，心迹火休然。", "冷淡將誰合，消搖且自憐。", "閑來窗下坐，試筆偶成篇。"]'),
('d3eef45e-d26b-4e8c-87ee-5078708f763d','讀史','釋智圓','宋','宋诗','song-poetry','','[]','我愛包胥哭，一哭救楚國。',168,'全唐诗/poet.song.7000.json','["我愛包胥哭，一哭救楚國。", "事君盡其忠，垂名千世則。", "我愛魯連笑，一笑卻秦軍。", "折衝罇俎間，流芳至今聞。", "我愛伯夷仁，揖讓持其身。", "餓列首陽下，恥事干戈君。", "後世闚竊輩，故非姬發倫。", "內藏篡弒謀，外躡武王塵。", "伯夷若不去，名教胡以伸。", "後人非三賢，細碎何足云。", "哭嘆祿位卑，笑喜膏粱珍。", "山林亦寒餓，行怪非求仁。", "留心寡兼濟，所謀惟一身。", "撫書想三賢，清風千古振。"]'),
('97db6efc-eb32-4b94-80d8-6e8b9be1af37','雪西施','釋智圓','宋','宋诗','song-poetry','','[]','范蠡無西施，胡以破吳國。',72,'全唐诗/poet.song.7000.json','["范蠡無西施，胡以破吳國。", "吳王輕社稷，爲惑傾城色。", "夫差強變弱，勾踐雌成雄。", "豈惟陶朱策，實賴西施容。", "西施語復賢，褒貶何昏蒙。", "便說傾吳罪，都忘霸越功。"]'),
('1764207f-818a-4d14-96e5-aaf7d3e68814','思君子歌','釋智圓','宋','宋诗','song-poetry','','[]','小人足諂媚，君子無猜忌。',104,'全唐诗/poet.song.7000.json','["小人足諂媚，君子無猜忌。", "開口揄揚皆聖賢，滿腹包藏盡仁義。", "修辭復古振淳風，折檻觸鱗彰直氣。", "善世既不伐，遯世亦無悶。", "自同流俗混光塵，不與常人鬬分寸。", "展矣斯人欲見之，一夕輾轉九迴思。", "終日躊躇無所遇，颯颯西風木葉衰。"]'),
('06cd0a79-9d1f-448b-af0b-849d4caa2a65','海上五山歌','釋智圓','宋','宋诗','song-poetry','','[]','五山峨峨聳海心，海波上下隨升沉。',112,'全唐诗/poet.song.7000.json','["五山峨峨聳海心，海波上下隨升沉。", "羣仙同往訴天帝，巨鼇十五受天制。", "一一巨鼇戴一山，一交三萬六千歲。", "無何龍伯約六鼇，兩山從此溺波濤。", "羣仙播遷作遊客，上帝憑怒誅龍伯。", "因知快樂非長久，三界元空何所有。", "莫於蝸角鬬雄豪，海上仙山尚摧朽。"]'),
('2bdd016b-2e44-4ec0-a6b7-6046ad9aa71f','陋巷歌贈友生','釋智圓','宋','宋诗','song-poetry','','[]','噫顔子兮居陋巷，身雖羸兮道彌壯。',153,'全唐诗/poet.song.7000.json','["噫顔子兮居陋巷，身雖羸兮道彌壯。", "商受兮有皇都，位雖尊兮名獨二八。", "朝恣瑤臺之樂兮，暮遭黄鉞之誅。", "是知不義之富貴如浮雲兮，惟道德爲性命之要樞。", "海濱有士兮慕顔子，心重朝聞兮輕夕死。", "紛紛糖粃兮視雄豪，凜凜冰霜兮潔行止。", "蓽門寂寞何瑣瑣，執卷忍饑終日坐。", "楊雄免遭甄豐戮，朱建終罹辟陽禍。", "射羣高墉會有時，於君無可無不可。"]'),
('8ff870da-898e-4f1e-91ca-5500d943df44','慎交歌','釋智圓','宋','宋诗','song-poetry','','[]','莫言青松青，有時亦摧折。',88,'全唐诗/poet.song.7000.json','["莫言青松青，有時亦摧折。", "莫言圓月明，有時亦虧缺。", "莫逆論心素，刎頸定交結。", "年髪未及衰，交情已消歇。", "俄因競分寸，忽爾成楚越。", "愛之欲其生，惡之欲其死。", "識欲松枯及月虧，請看陳餘與張耳。"]'),
('e634f6ab-a024-4a3d-a471-030f3bf7c8ef','古琴詩','釋智圓','宋','宋诗','song-poetry','','[]','良工採嶧桐，斵爲綠綺琴。',84,'全唐诗/poet.song.7000.json','["良工採嶧桐，斵爲綠綺琴。", "一奏還淳風，再奏和人心。", "君子不暫去，所貴禁奢淫。", "後世惑鄭聲，此道遂陸沈。", "朱絲鼠潛齧，金徽塵暗侵。", "冷落橫閑窗，棄置歲已深。", "安得師襄彈，重聞大古音。"]'),
('6d4db856-5424-4d7e-ba53-a931e5fe4cf0','吳山廟詩','釋智圓','宋','宋诗','song-poetry','','[]','君子尚權變，權變貴合道。',132,'全唐诗/poet.song.7000.json','["君子尚權變，權變貴合道。", "子胥薦專諸，子光專非好。", "父讎共戴天，乞師恨不早。", "子光既得志，入郢事征討。", "報父既鞭尺，諫王仍殺身。", "孝子節方全，忠臣道且新。", "馳名天地間，豈是悠悠人。", "青史書盛烈，血食旌遺塵。", "廟堂耀晨曦，廟木荂陽春。", "往來無知俗，焚香勤禱祝。", "忠孝不敢行，神兮寧降福。"]'),
('8731a654-ae07-47cf-9849-2ccaf36141e2','讀韓文詩','釋智圓','宋','宋诗','song-poetry','','[]','女媧鍊五石，能補青天缺。',180,'全唐诗/poet.song.7000.json','["女媧鍊五石，能補青天缺。", "共工觸不周，能令地維絕。", "楊孟既云沒，儒風幾殘滅。", "妖辭惑常聽，淫文蠹正說。", "南朝尚徐庾，唐興重盧駱。", "雕篆鬬呈巧，仁義咸遺落。", "王霸道不明，煙花心所託。", "文不可終否，天生韓吏部。", "叱僞俾歸真，鞭今使復古。", "異端維既絕，儒宗缺皆補。", "高文七百篇，炳若日月懸。", "力扶姬孔道，手持文章權。", "來者知尊儒，孰不由茲焉。", "我生好古風，服讀長灑蒙。", "何必唐一經，文道方可崇。"]'),
('55ca75db-bd61-49d9-b50c-4b6ace1d9201','山居招友人詩','釋智圓','宋','宋诗','song-poetry','','[]','結宇平湖濱，放意且閑逸。',192,'全唐诗/poet.song.7000.json','["結宇平湖濱，放意且閑逸。", "陵峰時採藥，服餌蠲故疾。", "藜藿可供餐，茆茨可容膝。", "浮生貴適性，何須次奢佚。", "清景況在目，萬事安能恤。", "水天爭冷落，林巒共盤鬰。", "有時泛舟歸，閑門曬殘日。", "徑荒人迹絕，庭靜精怪出。", "春羹漾紫蓴，冬盤列黄橘。", "坎井亦已樂，尺蠖誰云屈。", "外境莫我惑，貞心長抱一。", "涅槃終極典，虛堂每談述。", "不顧知者希，庶欲己無失。", "齊物鄙莊周，見性師妙吉。", "翛然混生佛，湛爾無虛實。", "知音來不來，時時掃幽室。"]'),
('00754b5d-c3fc-446d-97af-4698818cd675','貽葉秀才詩','釋智圓','宋','宋诗','song-poetry','','[]','松柏異衆木，歲寒陵嚴霜。',216,'全唐诗/poet.song.7000.json','["松柏異衆木，歲寒陵嚴霜。", "蘭茝異衆草，林深發幽香。", "須知君子道，不爲窮困傷。", "須知君子言，唯爲仁義彰。", "夫君真儒者，言行何優長。", "文宗軻兼雄，志嫉墨與楊。", "攘袂叱浮僞，百感生剛腸。", "峨冠事禮容，羣小畏矜莊。", "去年遊霅溪，相逢秋氣涼。", "傾蓋既如舊，寄宿林間房。", "開懷黜二霸，議道歸三王。", "月席屢更僕，風軒時飄霜。", "相遇分既洽，相別情彌傷。", "今年住孤山，夫君又來杭。", "泛舟頻相尋，道舊皆夕陽。", "君惟儒家流，才術況汪洋。", "終期正禮樂，勿事和塵光。", "青雲即奮飛，庶見儒風揚。"]'),
('1d4ecac4-30b3-4953-bde3-f21cf40e2444','贈簡上人詩','釋智圓','宋','宋诗','song-poetry','','[]','常人隱林泉，反爲名利縈。',84,'全唐诗/poet.song.7000.json','["常人隱林泉，反爲名利縈。", "志士處闤闠，杳有江湖情。", "有客務高潔，禪房閉重城。", "閑門無俗迹，壞壁饒蟲聲。", "臥落春砌花，吟盡霜蟾明。", "道希君子知，貧任時人輕。", "秉操期不渝，長保孤松貞。"]'),
('7dc4c26c-61a9-4265-9a2a-e46de794de87','述韓柳詩','釋智圓','宋','宋诗','song-poetry','','[]','退之排釋氏，子厚多能仁。',132,'全唐诗/poet.song.7000.json','["退之排釋氏，子厚多能仁。", "韓柳既道同，好惡安得倫。", "一斥一以贊，俱令儒道伸。", "柳州碑曹溪，言釋還儒淳。", "吏部讀墨子，謂墨與儒鄰。", "吾知墨兼愛，此釋何疏親。", "許墨則許釋，明若仰穹旻。", "去就亦已異，其旨由來均。", "後生學韓文，於釋長狺狺。", "未知韓子道，先學韓子嗔。", "忘本以競末，今古空勞神。"]'),
('93dc93db-c5c8-4c7a-9ac9-97b48f1ac7e4','孤山詩二首  其一','釋智圓','宋','宋诗','song-poetry','','[]','峭拔湖心起，湖心四望通。',144,'全唐诗/poet.song.7000.json','["峭拔湖心起，湖心四望通。", "盤根入巨浸，疊翠點寒空。", "勢迥侔蓬島，層危敵閬風。", "僧樓籠淡霧，雁塔礙飛鴻。", "曉井金沙粲，晴坡瑪瑙紅。", "噴雲春雨外，照影夕波中。", "野蔓垂枯柏，疏鐘匝梵宮。", "閑泉澄極頂，幽徑入深叢。", "古迹談皆異，秋屏寫未同。", "樂遊非俗客，靜望屬漁翁。", "買去知無價，棲來思豈窮。", "翻嗟市朝裏，塵土日濛濛。"]'),
('a38f73f8-4e87-452a-9187-f3c1769c149d','孤山詩二首  其二','釋智圓','宋','宋诗','song-poetry','','[]','勢與羣峰絕，崔嵬幾倦登。',48,'全唐诗/poet.song.7000.json','["勢與羣峰絕，崔嵬幾倦登。", "波澄涵倒影，雲盡露危稜。", "景象全勝畫，林泉半屬僧。", "何人憑郡閣，西望翠層層。"]'),
('223198de-3767-44ee-9eff-de88df62bfd9','暮秋書齋述懷寄守能師','釋智圓','宋','宋诗','song-poetry','','[]','杜門無俗交，塵事任浩浩。',120,'全唐诗/poet.song.7000.json','["杜門無俗交，塵事任浩浩。", "空齋學佛外，六經恣論討。", "仁義志不移，貧病誰相惱。", "天命唯我樂，百神非吾禱。", "爲文宗孔孟，開談黜莊老。", "諛諂音聲惡，寂寥滋味好。", "褰帷愁緒絕，憑欄寒氣早。", "雁影沈遠空，蟲鳴咽衰草。", "伊余何爲者，力擬行正道。", "願揚君子風，澆浮一除掃。"]'),
('d6a29885-e9e3-4894-98b6-d4c330e7f3dd','贈詩僧保暹師','釋智圓','宋','宋诗','song-poetry','','[]','天文懸日月，地文麗山川。',156,'全唐诗/poet.song.7000.json','["天文懸日月，地文麗山川。", "人文粲六經，四術詩其先。", "仲尼既云刪，炳然列風雅。", "厥旨幽且微，受之唯子夏。", "邈矣千百年，時有知詩者。", "卓爾保暹師，生于宋天下。", "內明卜商道，外減騷人價。", "鑿彼淳粹源，清辭競流瀉。", "放意尚幽遠，立言忌妖蟲。", "旨哉天目集，四海爭傳寫。", "上以裨王化，下以正人倫。", "驅邪俾歸正，驅澆使還淳。", "天未喪斯文，清風千古振。"]'),
('677b7184-25ac-4f07-b44e-f4e47bca186e','贈趙璞','釋智圓','宋','宋诗','song-poetry','','[]','世態任悠悠，正人無諂求。',48,'全唐诗/poet.song.7000.json','["世態任悠悠，正人無諂求。", "古柏凌寒霜，皓月當高秋。", "心將周孔師，是遠楊墨游。", "涇濁與渭清，由來自分流。"]'),
('c7d3c2e2-87b4-46af-ac91-297c9ec2e037','經武康小山法瑤師舊居','釋智圓','宋','宋诗','song-poetry','','[]','至道不可狀，至理杳無名。',84,'全唐诗/poet.song.7000.json','["至道不可狀，至理杳無名。", "萬彙喪其源，出沒何營營。", "忽焉生法瑤，研慮還淳精。", "立言宗能仁，百也馳休聲。", "我來訪舊居，景物如有情。", "閑庭慘樹色，空山咽猿鳴。", "斯人今也亡，孤棹尋歸程。"]'),
('44d5c962-cae6-4889-8ff0-32c504aa5a0c','西施篇','釋智圓','宋','宋诗','song-poetry','','[]','採蓮越溪上，皆謂尋常女。',48,'全唐诗/poet.song.7000.json','["採蓮越溪上，皆謂尋常女。", "正位吳中宮，衆口方傳美。", "視聽猒歌舞，衣裳賤羅綺。", "賢哉鄰家人，昔年知學嚬。"]'),
('f56cd2a7-79f3-49f6-b41b-348718827b2c','寓興','釋智圓','宋','宋诗','song-poetry','','[]','鄭聲淫復蕩，魯受齊人歸。',60,'全唐诗/poet.song.7000.json','["鄭聲淫復蕩，魯受齊人歸。", "古樂和且正，翻使文侯睡。", "佞言耳樂聞，直道心翻忌。", "唯知任所好，何曾顧顛墜。", "古樂與鄭聲，邪正宜留意。"]'),
('fcb172a1-82f5-4067-b507-70dd997c8858','山中自敘','釋智圓','宋','宋诗','song-poetry','','[]','閉門業文翰，誰謂溪山陋。',72,'全唐诗/poet.song.7000.json','["閉門業文翰，誰謂溪山陋。", "閑臥貴道肥，誰謂形容瘦。", "斯言欲無玷，內省庶不疚。", "深識淺江海，寬量窄宇宙。", "鄰女少學嚬，海夫多逐臭。", "時來松下坐，清風滿懷袖。"]'),
('06b7619b-f385-4fac-b769-703a99915dfa','莫言春日長','釋智圓','宋','宋诗','song-poetry','','[]','莫言春日長，一坐又西暮。',48,'全唐诗/poet.song.7000.json','["莫言春日長，一坐又西暮。", "衆芳榮復落，萬事新成故。", "臨川久興嗟，藏舟孰云固。", "蕭然蕩斯慮，空門有歸路。"]'),
('d323a40e-46a8-4994-9b12-57ffd0ee266b','講堂書事','釋智圓','宋','宋诗','song-poetry','','[]','早翫台衡宗，佛理既研精。',84,'全唐诗/poet.song.7000.json','["早翫台衡宗，佛理既研精。", "晚讀周孔書，人倫由著明。", "達本與飾躬，志在求同聲。", "擊蒙雖云勞，來學苦無成。", "楊雄玄尚白，仲尼道不行。", "青山夢中歸，華髪年來生。", "唯當照真空，萬事從營營。"]'),
('6d72368a-248e-4884-bb17-840258bd8161','勉隱者','釋智圓','宋','宋诗','song-poetry','','[]','潺潺澗中水，不入貪夫耳。',72,'全唐诗/poet.song.7000.json','["潺潺澗中水，不入貪夫耳。", "茫茫陌上塵，不霑靜者身。", "靜者貴寡欲，貪夫常患貧。", "躁進陷邪佞，潔己廢大倫。", "況當文明時，草澤羅賢人。", "行道尚中庸，蠖屈宜求伸。"]'),
('c22b5d4b-6c23-46f2-ace7-dd7da9dab65f','鑑','釋智圓','宋','宋诗','song-poetry','','[]','佳人磨拭頻，常恐塵埃侵。',36,'全唐诗/poet.song.7000.json','["佳人磨拭頻，常恐塵埃侵。", "皎皎夜月明，澄澄秋泉深。", "徒分妍醜容，不鑒是非心。"]'),
('cb9c90fe-a63c-4533-a7c6-19bed55c3c52','山中行','釋智圓','宋','宋诗','song-poetry','','[]','苒苒巖上雲，潺潺澗中水。',24,'全唐诗/poet.song.7000.json','["苒苒巖上雲，潺潺澗中水。", "山鳥如喚人，喃喃深林裏。"]'),
('198f0796-25a8-4055-8a3f-db6d36090e0a','送僧','釋智圓','宋','宋诗','song-poetry','','[]','秋風吹行衣，舊山逍遙歸。',36,'全唐诗/poet.song.7000.json','["秋風吹行衣，舊山逍遙歸。", "齋盂滌空潭，古磬敲殘暉。", "須知高靜懷，杳與塵俗違。"]'),
('e9a8b1ae-7917-4ba9-94cf-391b794cb294','答行簡上人書','釋智圓','宋','宋诗','song-poetry','','[]','偶依溪上居，三見改時候。',96,'全唐诗/poet.song.7000.json','["偶依溪上居，三見改時候。", "來書問蹤跡，行坐置懷袖。", "學道不加前，多慵還似舊。", "苦吟徹宵夜，閑眠消白晝。", "古屋荒莓苔，幽庭下猿狖。", "巧僞非吾好，直方自大授。", "侯門絕請謁，雅誥勤研究。", "悠悠皆面朋，誰能論去就。"]'),
('cf46d5da-44a0-4f56-89f4-dc1e581f7bb6','夏日薰風亭作','釋智圓','宋','宋诗','song-poetry','','[]','四野炎炎暑氣隆，危亭孤坐與誰同。',64,'全唐诗/poet.song.7000.json','["四野炎炎暑氣隆，危亭孤坐與誰同。", "湖光淡蕩涵殘照，鳥影參差沒遠空。", "消息浮生憑至理，破除煩暑賴清風。", "明時不敢言招隱，自樂林泉慕遠公。"]'),
('edbf8bee-abdc-4091-a68f-c8179ee948bb','初晴登疊翠亭偶成','釋智圓','宋','宋诗','song-poetry','','[]','杳杳遙空雨乍晴，閑拖山屐上山亭。',64,'全唐诗/poet.song.7000.json','["杳杳遙空雨乍晴，閑拖山屐上山亭。", "平湖風靜開菱鑒，疊嶂雲收列畫屏。", "已覺萬緣真是夢，豈因閑事妄勞形。", "可憐競利貪名者，擾擾人間醉未醒。"]'),
('0805dccc-9420-4626-9185-f145c79d1c45','李秀才以山齋早起詩見贈因次韻和酬','釋智圓','宋','宋诗','song-poetry','','[]','搜奇適異興何全，雅句分明敵惠連。',64,'全唐诗/poet.song.7000.json','["搜奇適異興何全，雅句分明敵惠連。", "丹桂平窺君有分，地塵閑去我無緣。", "陶情嶽雪時同望，解睡山茶夜共煎。", "靜語前塗俱有意，謝公紅藥遠公蓮。"]'),
('85e42951-f326-4bf0-a6d2-6bd080fb3711','對雪','釋智圓','宋','宋诗','song-poetry','','[]','冷結平湖絕棹過，紛紛盈目趣如何。',64,'全唐诗/poet.song.7000.json','["冷結平湖絕棹過，紛紛盈目趣如何。", "侯門歌舞看難足，編戶饑寒心厭多。", "旋滿閑庭誇玉砌，重欹幽樹鬬瓊柯。", "夜來孤坐書窗下，猶賴虛明自琢磨。"]'),
('8296ea64-dafb-4253-a993-ce2abaa0ae05','孤山詩三首  其一','釋智圓','宋','宋诗','song-poetry','','[]','樓閣壓危碧，山根疑有鼇。',48,'全唐诗/poet.song.7000.json','["樓閣壓危碧，山根疑有鼇。", "隔湖千嶂斷，出水一峰高。", "巖冷秋空月，林清雪夜猱。", "伊余絕羈束，長得恣遊遨。"]'),
('387b8c76-52ae-4e1e-9b0b-e513b1fcc47f','孤山詩三首  其二','釋智圓','宋','宋诗','song-poetry','','[]','四絕塵埃路，孤山景實孤。',48,'全唐诗/poet.song.7000.json','["四絕塵埃路，孤山景實孤。", "危巓侵迥漢，冷色浸平湖。", "古塔名支佛，新泉號僕夫。", "王維在何處，奇跡更堪圖。"]'),
('fc900144-e4f0-4e2e-85e1-fcaf5d3f7962','孤山詩三首  其三','釋智圓','宋','宋诗','song-poetry','','[]','仙島湖西見，湖西景有餘。',48,'全唐诗/poet.song.7000.json','["仙島湖西見，湖西景有餘。", "春融迎曉日，秋碧礙空虛。", "竹蔭高僧塔，雲迷處士居。", "史遷今若在，此處合藏書。"]'),
('744f7957-aa1c-4330-8a2f-a0f02d12fc35','酷熱','釋智圓','宋','宋诗','song-poetry','','[]','酷熱如小人，到處苦相侵。',48,'全唐诗/poet.song.7000.json','["酷熱如小人，到處苦相侵。", "清風如君子，時來寬我心。", "酷熱驅不去，清風留不住。", "此情無以訴，吟傍陰陰樹。"]'),
('af7b36b6-2c61-4f92-b13a-6b39e1f7d6ca','有客','釋智圓','宋','宋诗','song-poetry','','[]','有客有客，來扣我門。',60,'全唐诗/poet.song.7000.json','["有客有客，來扣我門。", "相見無言，自晝達昏。", "搘肘憑欄，俯仰乾坤。", "百年瞬息，得喪誰論。", "遠山青青，巨浸渾渾。", "忽然歸去，目擊道存。"]'),
('791829c5-4d4a-4642-9e4f-dd4014a16d7c','酬仁上人望湖山見寄次韻','釋智圓','宋','宋诗','song-poetry','','[]','平波映危碧，清景異塵中。',48,'全唐诗/poet.song.7000.json','["平波映危碧，清景異塵中。", "雪霽寒侵郭，秋澄冷照空。", "眠雲徒自樂，浮棹約誰同。", "幽趣何人識，搜吟愧遠公。"]'),
('b1b16c86-f29d-4365-a165-75daaaf23c95','和辯才訪仲微上人不遇','釋智圓','宋','宋诗','song-poetry','','[]','不見二十載，重尋事更違。',48,'全唐诗/poet.song.7000.json','["不見二十載，重尋事更違。", "門臨寒水閉，鳥向夕陽歸。", "吟恐成華髪，閑疑入翠微。", "登舟獨南去，乘興一何飛。"]'),
('7a62290f-5c87-4f7c-b88a-2d6adb3cf7dc','次韻酬明上人','釋智圓','宋','宋诗','song-poetry','','[]','養病孤山下，消搖任野情。',48,'全唐诗/poet.song.7000.json','["養病孤山下，消搖任野情。", "閑門浸寒水，高檻露荒城。", "砌月移杉影，巖泉隱磬聲。", "唯君許來此，相伴老餘生。"]'),
('5c16066f-1c74-427c-b218-a7885ab51881','寄同志','釋智圓','宋','宋诗','song-poetry','','[]','靜院無來客，相懷日又曛。',48,'全唐诗/poet.song.7000.json','["靜院無來客，相懷日又曛。", "數峰寒有雪，一榻靜眠雲。", "幾嘆淳風喪，寧容俗態羣。", "終期一相訪，對坐議新文。"]'),
('2d37e7ab-939a-49df-91b1-12e374fee45a','和聰上人悼梵天闍棃','釋智圓','宋','宋诗','song-poetry','','[]','講院悲風動素帷，搖松難更見吾師。',64,'全唐诗/poet.song.7000.json','["講院悲風動素帷，搖松難更見吾師。", "塵生舊榻休開卷，月上秋軒罷賦詩。", "真法自將傳後學，清名誰爲勒豐碑。", "橫經弟子懷高迹，共指龍華作後期。"]'),
('e19c8277-5be4-4ab4-84c9-322f4d2ed20d','孤山閑居次歡慶酬會稽仁姪見寄','釋智圓','宋','宋诗','song-poetry','','[]','山聳湖心住任緣，考槃茆舍閉深煙。',64,'全唐诗/poet.song.7000.json','["山聳湖心住任緣，考槃茆舍閉深煙。", "月澄秋水牽吟思，花滿春巖照困眠。", "觸石微雲閑致雨，鳴臯孤鶴靜聞天。", "會拋此景相尋去，渺渺滄江片席懸。"]'),
('cf66c508-8ccb-472d-bb07-aef12bb0021c','贈進士葉授','釋智圓','宋','宋诗','song-poetry','','[]','旅迹飄然與俗分，動時高價逐新文。',64,'全唐诗/poet.song.7000.json','["旅迹飄然與俗分，動時高價逐新文。", "寄眠僧舍扃秋雨，牽夢家山隔海雲。", "學慕丘軻方共語，道歸楊墨任離羣。", "名場好應同人舉，垂拱明堂有聖君。"]'),
('3d41212d-c6fd-4c60-a5ee-e2b7483b3db2','夏日寄諒律師','釋智圓','宋','宋诗','song-poetry','','[]','澄江杳杳映千峰，坐夏巖房一望中。',64,'全唐诗/poet.song.7000.json','["澄江杳杳映千峰，坐夏巖房一望中。", "晝講疏鐘清度越，夜吟殘月冷垂空。", "掃軒靜避階稜蘚，銷暑閑當竹罅風。", "顧我相懷未能去，水邊斜日照梧桐。"]'),
('79e05b3f-9f0e-4268-a013-482fd0eb6fd2','寄遠','釋智圓','宋','宋诗','song-poetry','','[]','車聲日日碾紅埃，何事良人獨未回。',65,'全唐诗/poet.song.7000.json','["車聲日日碾紅埃，何事良人獨未回。", "苔鎖洞房書久絕，月明深夜雁空來。", "寒侵竹葉難成醉，塵暗菱花更懶開。", "杳想法雲山不知處，夕陽頻上最高臺。"]'),
('6f980753-1346-4501-85f7-63e36265457e','寄文照大師','釋智圓','宋','宋诗','song-poetry','','[]','兩制音書數往來，城中棲隱遠塵埃。',64,'全唐诗/poet.song.7000.json','["兩制音書數往來，城中棲隱遠塵埃。", "吟齋夜靜開明月，講石秋深掃綠苔。", "出俗舊題留雪苑，臥雲幽興夢天台。", "林間抱疾懷高趣，翻笑湯休漫有才。"]'),
('dae85ddd-1c6b-493b-ae8f-d6ab646d4007','贈辯才大師','釋智圓','宋','宋诗','song-poetry','','[]','兩受皇恩萬慮休，浙陽高臥謝諸侯。',64,'全唐诗/poet.song.7000.json','["兩受皇恩萬慮休，浙陽高臥謝諸侯。", "定回幽室苔痕老，講徹閑庭樹影秋。", "天竺雲泉時掛夢，梁園風景懶重游。", "溪聲柏子將誰說，默倚禪牀自點頭。"]'),
('d45309c3-2fc1-4469-8da0-e74c0ed2c612','孤山閑居即事寄己師','釋智圓','宋','宋诗','song-poetry','','[]','年過不惑鬢成絲，偶到林間便卜居。',64,'全唐诗/poet.song.7000.json','["年過不惑鬢成絲，偶到林間便卜居。", "學道未忘山水癖，愛閑終與利名疏。", "夜涼顧閣來明月，風靜平湖瀁碧虛。", "回首權豪絕相識，野雲孤鶴自相於。"]'),
('469efba9-13e2-4b66-95ed-57899e01be8a','次韻酬聞聰上人春日書懷見寄','釋智圓','宋','宋诗','song-poetry','','[]','景色融融萬卉新，潛知青帝又東巡。',64,'全唐诗/poet.song.7000.json','["景色融融萬卉新，潛知青帝又東巡。", "陰崖竹樹猶欹雪，暖砌鶯花已覺春。", "吟苦漸驚華髪亂，身閑終忌俗流親。", "寥寥此意將誰說，回首禪門有故人。"]'),
('e14dcff1-e5c5-4f9d-a204-519bf8fca3cc','春日閑居即事寄元敏上人','釋智圓','宋','宋诗','song-poetry','','[]','門掩平湖避俗囂，靜觀風景識春朝。',64,'全唐诗/poet.song.7000.json','["門掩平湖避俗囂，靜觀風景識春朝。", "庭梅向日花全拆，岳樹連雲雪未消。", "少壯可驚年暗減，幽棲翻覺睡偏饒。", "相知賴有曹溪子，禪外時來慰寂寥。"]'),
('acce3170-c601-47f1-b0ab-5da2a535c18d','登樓感事寄天台友人','釋智圓','宋','宋诗','song-poetry','','[]','閑倚危欄思黯然，浮生誰共嘆流年。',64,'全唐诗/poet.song.7000.json','["閑倚危欄思黯然，浮生誰共嘆流年。", "愁催華髪生無極，心許青山未有緣。", "冷淡空江澄暮色，參差歸雁沒寒煙。", "吟餘更羨林間客，高臥深雲聽瀑泉。"]'),
('1160ea38-5e66-4884-af12-600c70008f6b','書通上人城居','釋智圓','宋','宋诗','song-poetry','','[]','禪房蕭灑閉重關，祖意明來萬事閑。',64,'全唐诗/poet.song.7000.json','["禪房蕭灑閉重關，祖意明來萬事閑。", "高臥有時消白日，靜吟無念憶青山。", "掃花晚砌留蒼蘚，剃髪秋池照病顔。", "堪笑林泉深隱者，不知幽趣在人間。"]'),
('010aed80-d711-4d6c-8030-ea4647514054','湖居即事寄仁姪','釋智圓','宋','宋诗','song-poetry','','[]','講退臨流獨倚筇，塵埃無處寄閑蹤。',64,'全唐诗/poet.song.7000.json','["講退臨流獨倚筇，塵埃無處寄閑蹤。", "青山歸去心長在，白髪生來事轉慵。", "門徑草深梅雨歇，像龕燈暗水煙濃。", "相知唯有搖松客，時辱音書慰病容。"]'),
('2dd6af76-523b-4be8-834c-9f7589afc91f','懷石壁舊居兼簡紹上人','釋智圓','宋','宋诗','song-poetry','','[]','壁立巖巒照冽泉，幾思幽景嘆流年。',64,'全唐诗/poet.song.7000.json','["壁立巖巒照冽泉，幾思幽景嘆流年。", "歸棲自合同仙迹，深隱誰云有洞天。", "修竹寒聲風乍動，古潭秋影月初圓。", "伊余亦擬依支遁，枕石眠雲碧嶂前。"]'),
('0b33b589-4661-441d-87fe-ad1fd41eb233','贈林逋處士','釋智圓','宋','宋诗','song-poetry','','[]','深居猿鳥共忘機，荀孟才華鶴氅衣。',64,'全唐诗/poet.song.7000.json','["深居猿鳥共忘機，荀孟才華鶴氅衣。", "滿砌落花春病起，一湖明月夜漁歸。", "風搖野水青蒲短，雨過閑園紫蕨肥。", "塵土滿床書萬卷，玄纁何日到松扉。"]'),
('03a281d8-56a8-4cf3-949f-801ce5fe48ff','梵天寺二首  其一','釋智圓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','路上中峰勢屈盤，塵埃蹤跡到終難。',64,'全唐诗/poet.song.7000.json','["路上中峰勢屈盤，塵埃蹤跡到終難。", "秋杉影射經窗冷，夜浪聲搖睡榻寒。", "雲過閑軒香篆潤，日移幽砌蘚痕乾。", "吟餘靜立憑欄久，極目長江水渺漫。"]'),
('c71e5ef3-6e5d-494e-83df-a65aa672d525','梵天寺二首  其二','釋智圓','宋','宋诗','song-poetry','','[]','梵宇清虛遠俗喧，登臨時得爽吟魂。',64,'全唐诗/poet.song.7000.json','["梵宇清虛遠俗喧，登臨時得爽吟魂。", "卷簾高雪明稽嶺，上閣秋濤出海門。", "羣木冷陰連古塔，疏鐘寒韻徹江村。", "城中泉石詩中景，閑對文公盡日論。"]'),
('5daf2559-b497-46d6-9590-434a34aa68fb','趙萬宗入道因寄','釋智圓','宋','宋诗','song-poetry','','[]','羔雁已聞徵不起，卻求披戴守貞居。',64,'全唐诗/poet.song.7000.json','["羔雁已聞徵不起，卻求披戴守貞居。", "月堂欹枕三清夢，秋榻生塵萬卷書。", "壇匝冷痕春蘚碧，鶴翹寒影雪杉疏。", "年來未得尋幽迹，閑夜何人聽步虛。"]'),
('a99d6de4-2cde-4cd7-b005-089913a4afdc','春日湖居書事寄子璿師','釋智圓','宋','宋诗','song-poetry','','[]','閑居作賦擬安仁，壯志潛消白髪新。',64,'全唐诗/poet.song.7000.json','["閑居作賦擬安仁，壯志潛消白髪新。", "煙浪靜牽來往夢，鶯花深慰寂寥身。", "野塘草綠湖村暮，石鼎茶香嶽寺春。", "終學支公買山住，白雲深處待爲鄰。"]'),
('b3c6e1bc-5b96-435c-9bd1-7d659653a2e0','酬正言上人','釋智圓','宋','宋诗','song-poetry','','[]','旅雁聲孤過舊林，相懷無處共論心。',64,'全唐诗/poet.song.7000.json','["旅雁聲孤過舊林，相懷無處共論心。", "眠雲未負他年約，看雪難忘盡日吟。", "江上信稀寒浪闊，竹邊房掩夕陽深。", "寂寥閑坐西窗下，空把餘情寄玉琴。"]'),
('05651c32-d2ce-42c0-9450-9e28ab371e84','贈清義律師','釋智圓','宋','宋诗','song-poetry','','[]','律藏精持世所稀，淡然高趣自忘機。',64,'全唐诗/poet.song.7000.json','["律藏精持世所稀，淡然高趣自忘機。", "禪開靜室蒼苔徧，飯起閑窗獨鳥歸。", "雪嶽夜鐘清度枕，水軒秋月冷侵衣。", "吟拿講罷無他事，人外時容扣竹扉。"]'),
('eb9a22dc-8001-4079-8c75-7a66200607c3','遊開化寺','釋智圓','宋','宋诗','song-poetry','','[]','地絕纖塵萬籟清，當門幽致畫難成。',64,'全唐诗/poet.song.7000.json','["地絕纖塵萬籟清，當門幽致畫難成。", "黛粧峰岫高低影，練卷波濤旦暮聲。", "侵竹古廊秋蘚合，倚雲禪閣夜燈明。", "上方別有幽棲處，樹石參差稱野情。"]'),
('7a1cafcb-7a1a-406c-9ebc-b0813835fc62','次韻酬子文師','釋智圓','宋','宋诗','song-poetry','','[]','門靜孤雲去復還，講餘他慮絕相關。',64,'全唐诗/poet.song.7000.json','["門靜孤雲去復還，講餘他慮絕相關。", "遺名懶住城中寺，招隱曾居海畔山。", "臥疾雪房苔色老，行禪秋徑樹陰閑。", "玄機共了心無事，相見寧愁鬢漸斑。"]'),
('3b3cd4a7-42fd-443e-ab39-99f6b973825d','南塔寺上方','釋智圓','宋','宋诗','song-poetry','','[]','絕頂深棲萬慮平，路盤危石雨苔青。',64,'全唐诗/poet.song.7000.json','["絕頂深棲萬慮平，路盤危石雨苔青。", "江涵迥漢供閑望，雪映幽窗卷舊經。", "磬擊曉霜禪乍起，枕搖秋浪夢初醒。", "爲鄰自有忘機者，月下時時扣竹扃。"]'),
('681d4feb-6b27-4915-a7fe-70956366b635','寄贈子正律師','釋智圓','宋','宋诗','song-poetry','','[]','威儀閑淡許誰同，苔徑依然絕履蹤。',64,'全唐诗/poet.song.7000.json','["威儀閑淡許誰同，苔徑依然絕履蹤。", "霜井濾泉浸曉色，雪房欹枕夢諸峰。", "寒生靜榻吟中月，冷答平湖講次鐘。", "盡日冥心憶高趣，三生行止道生松。"]'),
('d76d5826-2f2e-4162-b490-db709d7db328','憶南塔上方因寄慶昭師','釋智圓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','杉松森森一徑通，六年高院寄幽蹤。',64,'全唐诗/poet.song.7000.json','["杉松森森一徑通，六年高院寄幽蹤。", "涼移峭壁秋深月，冷映長江雪後峰。", "吟次夏雲晴影薄，講殘春樹翠陰濃。", "四時嘉景真堪愛，曾伴支公數倚筇。"]'),
('0e3186be-7218-4476-b148-5645c2a754bb','庭松','釋智圓','宋','宋诗','song-poetry','','[]','喬枝偃蓋勢凌雲，一植幽庭度機春。',64,'全唐诗/poet.song.7000.json','["喬枝偃蓋勢凌雲，一植幽庭度機春。", "榮落未曾同衆木，孤貞長自伴閑人。", "風生靜夜寒聲健，雪霽遙峰翠色新。", "蕭灑最宜禪定起，坐觀行繞遠埃塵。"]'),
('f6486025-7bbb-45df-8280-27d60500c4b6','寄曦照上人','釋智圓','宋','宋诗','song-poetry','','[]','塵外禪房掩渺瀰，高情終與俗流違。',64,'全唐诗/poet.song.7000.json','["塵外禪房掩渺瀰，高情終與俗流違。", "苦吟幾度成華髪，默坐連宵憶翠微。", "風带荷香飄靜榻，雨滋苔色汙閑扉。", "炎天幾阻相尋興，空倚危樓對落暉。"]'),
('7afd4b6b-790f-48ee-9d62-df8c44fb3a9d','寄題梵天聖果二寺兼簡昭梧二上人  其一','釋智圓','宋','宋诗','song-poetry','','[]','江色杳無極，渺渺接遙天。',36,'全唐诗/poet.song.7000.json','["江色杳無極，渺渺接遙天。", "歸帆带夕陽，去鳥沈寒煙。", "幽景不同觀，遐想成斯篇。"]'),
('71367f94-4760-4426-b749-5f36918c298a','寄題梵天聖果二寺兼簡昭梧二上人  其二','釋智圓','宋','宋诗','song-poetry','','[]','樓閣聳岧峣，參差極雲際。',36,'全唐诗/poet.song.7000.json','["樓閣聳岧峣，參差極雲際。", "高窗曉色先，晚景餘霞麗。", "寥寥羣動息，冥心遠塵世。"]'),
('81317a94-e63a-4b86-9e88-18ecba73177d','寄題梵天聖果二寺兼簡昭梧二上人  其三','釋智圓','宋','宋诗','song-poetry','','[]','冷淡杳難羣，幽趣唯吾識。',36,'全唐诗/poet.song.7000.json','["冷淡杳難羣，幽趣唯吾識。", "高情薄雲漢，清談潤金石。", "不學浮世人，奔名競雕飾。"]'),
('599aca47-28bf-4d76-b179-c8ea081b819c','寄題梵天聖果二寺兼簡昭梧二上人  其四','釋智圓','宋','宋诗','song-poetry','','[]','性靜百慮忘，軒閑萬象歸。',36,'全唐诗/poet.song.7000.json','["性靜百慮忘，軒閑萬象歸。", "空江答夜鐘，高嶠留殘暉。", "幽砌絕塵蹤，孤雲自依依。"]'),
('3d1b01ba-70a3-489e-9b0b-2b36dda4d3bf','寄題梵天聖果二寺兼簡昭梧二上人  其五','釋智圓','宋','宋诗','song-poetry','','[]','顧惡如探湯，觸物類虛舟。',36,'全唐诗/poet.song.7000.json','["顧惡如探湯，觸物類虛舟。", "他人莫己知，此道本吾求。", "獨坐時相懷，斜陽照危樓。"]'),
('3d62e36b-2504-4bef-a2cc-6d281b2a611e','寄題梵天聖果二寺兼簡昭梧二上人  其六','釋智圓','宋','宋诗','song-poetry','','[]','崔嵬高山側，觸石生片雲。',36,'全唐诗/poet.song.7000.json','["崔嵬高山側，觸石生片雲。", "自將風雨期，不與塵土羣。", "杳杳遊太虛，對此幾思君。"]'),
('058d61ad-15f3-468e-a322-4aa0452cb7c4','寄題梵天聖果二寺兼簡昭梧二上人  其七','釋智圓','宋','宋诗','song-poetry','','[]','高迹將誰親，幽棲白雲中。',36,'全唐诗/poet.song.7000.json','["高迹將誰親，幽棲白雲中。", "閑階吐蒼苔，古木生清風。", "時將西竺書，講義訓來蒙。"]'),
('16e24548-5825-49dc-8263-0b18c235c2c4','寄題梵天聖果二寺兼簡昭梧二上人  其八','釋智圓','宋','宋诗','song-poetry','','[]','靜躁各所好，是非安能辨。',36,'全唐诗/poet.song.7000.json','["靜躁各所好，是非安能辨。", "聲利如我仇，雲泉若相勉。", "寂寂深林中，芳蘭自堪搴。"]'),
('18c843c3-dec7-4281-a862-d613b4a8b3c8','寄題梵天聖果二寺兼簡昭梧二上人  其九','釋智圓','宋','宋诗','song-poetry','','[]','羣峰聳危碧，倒影沈空江。',36,'全唐诗/poet.song.7000.json','["羣峰聳危碧，倒影沈空江。", "清景生晚晴，冷色涵虛窗。", "消搖縱吟賞，能使吾心降。"]'),
('3586ee1d-d71a-4adf-884f-5fd65941892d','寄題梵天聖果二寺兼簡昭梧二上人  其一○','釋智圓','宋','宋诗','song-poetry','','[]','海日照吟軒，江風動庭樹。',36,'全唐诗/poet.song.7000.json','["海日照吟軒，江風動庭樹。", "此景樂閑情，何人識高趣。", "登樓獨南望，杳杳空煙霧。"]'),
('3c3878b5-91e8-4b1c-9806-67657f0c59bb','湖西雜感詩  其一','釋智圓','宋','宋诗','song-poetry','','[]','湖波冷淡絕纖塵，滿目雲山是四鄰。',32,'全唐诗/poet.song.7000.json','["湖波冷淡絕纖塵，滿目雲山是四鄰。", "一徑草深人不到，竹床蒲扇養天真。"]'),
('107b1996-26fc-4ebf-a362-08f9a8ea4f90','湖西雜感詩  其二','釋智圓','宋','宋诗','song-poetry','','[]','看雲靜放支公鶴，臨水閑觀惠子魚。',32,'全唐诗/poet.song.7000.json','["看雲靜放支公鶴，臨水閑觀惠子魚。", "窗下寂寥何所有，竺乾經卷仲尼書。"]'),
('3cdff70b-48c7-4986-be06-b1a5d8c817d2','湖西雜感詩  其三','釋智圓','宋','宋诗','song-poetry','','[]','閑庭庭畔植梧桐，上有新蟬噪晚風。',32,'全唐诗/poet.song.7000.json','["閑庭庭畔植梧桐，上有新蟬噪晚風。", "咽咽清音正堪聽，無端驚斷彼兒童。"]'),
('af069943-d2fa-4d3c-9b0c-af5aaa5e1fbc','湖西雜感詩  其四','釋智圓','宋','宋诗','song-poetry','','[]','移得煙溪竹數竿，閑庭栽處綠陰寒。',32,'全唐诗/poet.song.7000.json','["移得煙溪竹數竿，閑庭栽處綠陰寒。", "虛心高節真堪愛，不放常人暫入看。"]'),
('f8185dfb-7f78-4975-b45e-9e04a7a75ebf','湖西雜感詩  其五','釋智圓','宋','宋诗','song-poetry','','[]','鳳爲時瑞世傳名，及現郊村衆盡驚。',32,'全唐诗/poet.song.7000.json','["鳳爲時瑞世傳名，及現郊村衆盡驚。", "喚作怪禽宜彈殺，始知流俗重虛聲。"]'),
('6f3fd0c4-9276-4adc-a4db-05a1f4a82e69','湖西雜感詩  其六','釋智圓','宋','宋诗','song-poetry','','[]','直木風摧秋敗蘭，閑觀庭際可長嘆。',32,'全唐诗/poet.song.7000.json','["直木風摧秋敗蘭，閑觀庭際可長嘆。", "屈原溺水伍員死，孤潔由來獨立難。"]'),
('d0aae4ca-ebf8-476d-8553-19c9a598fca6','湖西雜感詩  其七','釋智圓','宋','宋诗','song-poetry','','[]','尼父立言敦禮樂，能仁垂訓勵慈悲。',32,'全唐诗/poet.song.7000.json','["尼父立言敦禮樂，能仁垂訓勵慈悲。", "堪嗟世路營營者，狡佞貪殘都不知。"]'),
('8e6ff2dd-dc02-46db-a867-f51eca9aa57c','湖西雜感詩  其八','釋智圓','宋','宋诗','song-poetry','','[]','不省浮生大患身，諂求終日走紅塵。',32,'全唐诗/poet.song.7000.json','["不省浮生大患身，諂求終日走紅塵。", "一朝死至名初沒，滿屋黄金屬別人。"]'),
('be78fcb7-9287-489c-b3b2-d88889ef8738','湖西雜感詩  其九','釋智圓','宋','宋诗','song-poetry','','[]','猛虎磨牙踞蔭林，幽幽一路晚煙深。',32,'全唐诗/poet.song.7000.json','["猛虎磨牙踞蔭林，幽幽一路晚煙深。", "行行君子休疑懼，此物由來食獸心。"]'),
('1fcc0065-bc75-4e34-8bfe-86b05386767d','湖西雜感詩  其一○','釋智圓','宋','宋诗','song-poetry','','[]','留心儉讓唐虞道，恣意貪求桀跖徒。',32,'全唐诗/poet.song.7000.json','["留心儉讓唐虞道，恣意貪求桀跖徒。", "閑坐思量茆屋下，夜深秋月照平湖。"]'),
('139a6e80-2594-422f-9b7c-dd91bc90df07','湖西雜感詩  其一一','釋智圓','宋','宋诗','song-poetry','','[]','蘭在深林亦自馨，豈因風雨阻雞鳴。',32,'全唐诗/poet.song.7000.json','["蘭在深林亦自馨，豈因風雨阻雞鳴。", "由來君子須謀道，不爲時人有重輕。"]'),
('08dda457-226d-4f97-b933-51883c34a1d5','湖西雜感詩  其一二','釋智圓','宋','宋诗','song-poetry','','[]','白犬宵行似有情，爲防暴客到天明。',32,'全唐诗/poet.song.7000.json','["白犬宵行似有情，爲防暴客到天明。", "近來守禦無功績，不吠人形只吠聲。"]'),
('68580f8a-f290-4011-85b0-990180c4ca03','湖西雜感詩  其一三','釋智圓','宋','宋诗','song-poetry','','[]','伯陽道德釋迦心，夫子文章盡可尋。',32,'全唐诗/poet.song.7000.json','["伯陽道德釋迦心，夫子文章盡可尋。", "飽食暖衣都不顧，可憐容易過光陰。"]'),
('e0ebfb4f-8cf4-4f9b-b360-d81f60896e8b','湖西雜感詩  其一四','釋智圓','宋','宋诗','song-poetry','','[]','雪晴山院景堪躋，玉樹瓊樓照碧溪。',32,'全唐诗/poet.song.7000.json','["雪晴山院景堪躋，玉樹瓊樓照碧溪。", "日暮忽驚銷爍盡，百年豪富事還齊。"]'),
('0f8e076f-4feb-48df-ac8c-0f201ddadc2a','湖西雜感詩  其一五','釋智圓','宋','宋诗','song-poetry','','[]','月照閑軒虧復盈，吉凶消長勢相傾。',32,'全唐诗/poet.song.7000.json','["月照閑軒虧復盈，吉凶消長勢相傾。", "須知人事同天道，寵辱由來盡可驚。"]'),
('34b9a543-4481-47e5-bc16-da58e12b9165','湖西雜感詩  其一六','釋智圓','宋','宋诗','song-poetry','','[]','草堂閑坐念編民，多尚浮虛少尚真。',32,'全唐诗/poet.song.7000.json','["草堂閑坐念編民，多尚浮虛少尚真。", "禮讓不修難致福，唯知燒紙祭淫神。"]'),
('8e8144a9-d400-4821-80bd-acdb6a208f66','湖西雜感詩  其一七','釋智圓','宋','宋诗','song-poetry','','[]','陰陽家說惑常民，孝道從茲盡失倫。',32,'全唐诗/poet.song.7000.json','["陰陽家說惑常民，孝道從茲盡失倫。", "廬墓三年誰肯也，競談岡勢益生人。"]'),
('2862950d-f7e2-4100-952c-69526e961c19','湖西雜感詩  其一八','釋智圓','宋','宋诗','song-poetry','','[]','福善禍淫言可信，吉凶由己語堪陳。',32,'全唐诗/poet.song.7000.json','["福善禍淫言可信，吉凶由己語堪陳。", "乖仁背義都無恥，只記臨行揀日辰。"]'),
('bec1153d-c334-43c8-8271-a02af27ea4dd','湖西雜感詩  其一九','釋智圓','宋','宋诗','song-poetry','','[]','靜思塵世事茫茫，策杖閑吟出草堂。',32,'全唐诗/poet.song.7000.json','["靜思塵世事茫茫，策杖閑吟出草堂。", "欲哈浮生那遠覓，芭蕉昨夜已經霜。"]'),
('2f983070-c77a-493d-9d13-36f60b477ec3','湖西雜感詩  其二○','釋智圓','宋','宋诗','song-poetry','','[]','鑿得新泉古砌頭，煮茶滋味異常流。',32,'全唐诗/poet.song.7000.json','["鑿得新泉古砌頭，煮茶滋味異常流。", "夜來閑看澄明性，天上無雲月正秋。"]'),
('737e48cd-9d33-49e2-99a5-2a1138973b23','寄華亭虛己師','釋智圓','宋','宋诗','song-poetry','','[]','懶答公卿信，高眠野興濃。',48,'全唐诗/poet.song.7000.json','["懶答公卿信，高眠野興濃。", "虛堂開夜月，孤枕度秋鐘。", "臨水成新作，看雲憶舊峰。", "林間仍抱疾，早晚遂相逢。"]'),
('b5a89e94-613c-4d0e-a667-a0c295e5a0b2','旅舍言懷','釋智圓','宋','宋诗','song-poetry','','[]','旅舍少相識，孤吟俗態分。',48,'全唐诗/poet.song.7000.json','["旅舍少相識，孤吟俗態分。", "客情生夜雨，歸夢入秋雲。", "砌冷螢頻過，窗幽雁忽聞。", "西峰泉石在，終去謝人羣。"]'),
('4f3055b9-6b15-409f-a53c-ac650287532c','上錢唐太守薛大諫','釋智圓','宋','宋诗','song-poetry','','[]','分符江郡遠，貴列七人間。',48,'全唐诗/poet.song.7000.json','["分符江郡遠，貴列七人間。", "文古淳風在，時清諫筆閑。", "樓高喧暮角，廳冷鏁秋山。", "聖代期調鼎，軒車即詔還。"]'),
('1cd88f89-091d-4a40-9e60-f423e3317f6b','贈守能師','釋智圓','宋','宋诗','song-poetry','','[]','高臥湖山畔，塵機任萬端。',48,'全唐诗/poet.song.7000.json','["高臥湖山畔，塵機任萬端。", "連雲吟閣靜，度水講鐘寒。", "幽戶碧嶂閉，新書雪夜刊。", "卻應趨競者，相笑隱林巒。"]'),
('9209cb30-e1ea-4ddd-bb23-1cd05905ede6','潮','釋智圓','宋','宋诗','song-poetry','','[]','羅剎江心起，晨昏信不差。',48,'全唐诗/poet.song.7000.json','["羅剎江心起，晨昏信不差。", "寒聲喧極浦，秋勢卷平沙。", "望立人心險，驚飛鳥影斜。", "來源爭可問，滄海況無涯。"]'),
('4f31da8b-46c3-441b-a1ac-2d404cad3e36','送夤上人歸道場山','釋智圓','宋','宋诗','song-poetry','','[]','行行攜錫別，幽景到山分。',48,'全唐诗/poet.song.7000.json','["行行攜錫別，幽景到山分。", "殘雪經春在，疏鐘度水聞。", "松深生晚次，潭靜照閑雲。", "巖閣重開講，清香入夜焚。"]'),
('0ec33989-f4ef-47aa-ba14-53dc6cfe906c','宿山院','釋智圓','宋','宋诗','song-poetry','','[]','一宿無塵境，相留靜話長。',48,'全唐诗/poet.song.7000.json','["一宿無塵境，相留靜話長。", "秋聲歸古木，月色滿空廊。", "嵐氣侵衣潤，溪泉漱齒涼。", "終期整缾錫，來此掩閑房。"]'),
('aa011fa3-8d28-43fb-af0d-5164104117be','贈簡上人','釋智圓','宋','宋诗','song-poetry','','[]','澹然人外趣，萬事已無求。',48,'全唐诗/poet.song.7000.json','["澹然人外趣，萬事已無求。", "花院春深講，雲山夏滿遊。", "汲泉苔井曉，鳴磬竹窗秋。", "別有幽期在，香燈老沃洲。"]'),
('36e90c76-37b5-439e-8ca9-0f3f06e9e2c6','苔','釋智圓','宋','宋诗','song-poetry','','[]','與僻偏饒分，蒼蒼稱靜吟。',48,'全唐诗/poet.song.7000.json','["與僻偏饒分，蒼蒼稱靜吟。", "度階經雨徧，峭壁度秋深。", "色冷分禽跡，痕幽入樹陰。", "衡門終歲在，車馬絕相侵。"]'),
('ae4fdaac-9fba-4fef-903b-c972d0b077ac','寄楚南師','釋智圓','宋','宋诗','song-poetry','','[]','昔年江上別，高迹杳難尋。',48,'全唐诗/poet.song.7000.json','["昔年江上別，高迹杳難尋。", "浮世人稀見，青山隱更深。", "琢詩窮有象，體道極無心。", "慚負眠雲約，西峰夕照陰。"]'),
('4abc91f4-6f1f-45db-801a-d352ed15aa7f','江亭晚望','釋智圓','宋','宋诗','song-poetry','','[]','江亭閑寫望，秋景正無窮。',48,'全唐诗/poet.song.7000.json','["江亭閑寫望，秋景正無窮。", "鳥沒寒雲外，帆歸暮色中。", "淡煙生極浦，敗葉墜涼風。", "迴道聞漁唱，人家隔葦叢。"]'),
('8f9c4adb-915c-453e-843f-7bb1b7be330a','登武林高峰','釋智圓','宋','宋诗','song-poetry','','[]','千尋堆冷碧，極頂絕塵蹤。',48,'全唐诗/poet.song.7000.json','["千尋堆冷碧，極頂絕塵蹤。", "雨霽聞清籟，雲開見別峰。", "落泉噴怪石，驚鳥入深松。", "吟罷憑欄久，遙天起暮鐘。"]'),
('34409c5e-83fd-47b4-8812-e6bfe427cba8','懷子仁師','釋智圓','宋','宋诗','song-poetry','','[]','寥寥塵迹遠，禪外動閑思。',48,'全唐诗/poet.song.7000.json','["寥寥塵迹遠，禪外動閑思。", "水國人歸後，秋軒月白時。", "鳴蛩藏壞壁，幽鳥立寒枝。", "獨坐誰相問，微吟鑷病髭。"]'),
('723c4f96-b700-4b37-a2fa-24cbc33f979f','書懷','釋智圓','宋','宋诗','song-poetry','','[]','一錫任西東，孤懷孰與同。',48,'全唐诗/poet.song.7000.json','["一錫任西東，孤懷孰與同。", "吟髭潛變白，人事旋成空。", "秋閣閑看月，寒窗臥聽鴻。", "時將寂寥意，深夜寄絲桐。"]'),
('5404c1ba-0520-4819-bb04-5c5dd2592839','寄棲白師','釋智圓','宋','宋诗','song-poetry','','[]','深隱空林下，清幽絕外緣。',48,'全唐诗/poet.song.7000.json','["深隱空林下，清幽絕外緣。", "雨窗對嶽信，苔井濾秋泉。", "門靜來沙鳥，庭閑噪晚蟬。", "憑欄獨相憶，殘日下遙天。"]'),
('a68feca3-e186-4d77-a0d4-5522a4a5fce2','贈郝逸人','釋智圓','宋','宋诗','song-poetry','','[]','故國伊川遠，深居碧嶂前。',48,'全唐诗/poet.song.7000.json','["故國伊川遠，深居碧嶂前。", "伴吟唯有鶴，高趣別無仙。", "嶽信閑慵答，丹經秘不傳。", "杖藜時訪我，終日話南禪。"]'),
('8cdceb81-d52f-4c3b-b415-6ea4481862de','遊靈隱山','釋智圓','宋','宋诗','song-poetry','','[]','峭壁侵霄極，靈蹤不厭尋。',48,'全唐诗/poet.song.7000.json','["峭壁侵霄極，靈蹤不厭尋。", "閑思曾有夢，歸隱豈無心。", "絕壁煙霞罷，幽巖洞穴深。", "那堪思慧理，殘日白猿吟。"]'),
('170e0450-7f14-4405-b59a-3297930738fb','謝擇梧律師惠竹杖','釋智圓','宋','宋诗','song-poetry','','[]','剪自幽巖側，高僧忽見遺。',48,'全唐诗/poet.song.7000.json','["剪自幽巖側，高僧忽見遺。", "看雲欹盡日，書雪握多時。", "節冷蟲微蠹，根閑蘚暗滋。", "舊山泉石在，歸去賴扶持。"]'),
('0c00c73c-fc2f-4f70-bd79-e9ca7332e459','梵天寺閑居書事','釋智圓','宋','宋诗','song-poetry','','[]','松杉圍靜室，蹤跡遠人羣。',48,'全唐诗/poet.song.7000.json','["松杉圍靜室，蹤跡遠人羣。", "抱疾添華髪，看山羨白雲。", "苔痕經雨長，蟬韻带風聞。", "獨坐無來客，西軒日又曛。"]'),
('e394a922-0069-443c-adfc-61e786f9e1d8','鍊丹井','釋智圓','宋','宋诗','song-poetry','','[]','仙去遺蹤在，泠泠翠嶽邊。',48,'全唐诗/poet.song.7000.json','["仙去遺蹤在，泠泠翠嶽邊。", "泠光涵碧甃，暗脈洩寒泉。", "月映冰壺淺，秋澄古鑑圓。", "羽人居止近，閑汲灌芝田。"]'),
('d7dc2d5d-cf73-4551-9441-3ef5a8b7fe60','冷泉亭','釋智圓','宋','宋诗','song-poetry','','[]','亭幽無俗狀，清景滌煩襟。',48,'全唐诗/poet.song.7000.json','["亭幽無俗狀，清景滌煩襟。", "砌壓寒流淺，簷分積翠深。", "晚花閑照影，古木冷垂陰。", "憑檻不能去，澄澄發靜吟。"]'),
('4b02cdfe-2e39-44a7-84d4-77300e4dab16','贈僧','釋智圓','宋','宋诗','song-poetry','','[]','諸祖參尋徧，消搖髪未華。',48,'全唐诗/poet.song.7000.json','["諸祖參尋徧，消搖髪未華。", "舊房扃海外，孤迹寄天涯。", "琢句秋窗月，觀空晚砌華。", "時來說高趣，終去隱煙霞。"]'),
('f99b9cef-1b92-4ad4-8973-050e6decbafc','湖居秋日病起','釋智圓','宋','宋诗','song-poetry','','[]','舊識稀相訪，寥寥掩壞房。',72,'全唐诗/poet.song.7000.json','["舊識稀相訪，寥寥掩壞房。", "鼎深殘藥在，頷瘦白髭長。", "塵點沾書篋，苔痕汙石床。", "簷幽蟲織網，砌冷菊含香。", "靜思憐深夜，清羸怯晚涼。", "雲峰歸未得，閑坐詠滄浪。"]'),
('e2273be0-b559-4fa4-adc1-016c5f6d25d3','贈夷中師','釋智圓','宋','宋诗','song-poetry','','[]','澹泊背時態，翛然塵外心。',48,'全唐诗/poet.song.7000.json','["澹泊背時態，翛然塵外心。", "靜吟霜月盡，歸夢海雲深。", "室冷苔生榻，窗閑鳥覷琴。", "幽棲共得趣，乘興幾相尋。"]'),
('97e8b097-8fed-4eed-868a-cc2f5dfe0536','寄圓長老','釋智圓','宋','宋诗','song-poetry','','[]','澹慮棲幽境，閑將水石鄰。',48,'全唐诗/poet.song.7000.json','["澹慮棲幽境，閑將水石鄰。", "信衣傳往祖，禪語示來人。", "晚屋茶煙細，晴軒嶽翠勻。", "相懷獨南望，林木又經春。"]'),
('ece72be1-983b-43bf-9cf0-c9d600791294','同友人宿山院','釋智圓','宋','宋诗','song-poetry','','[]','共依清境宿，話道復論文。',48,'全唐诗/poet.song.7000.json','["共依清境宿，話道復論文。", "潭月秋深見，山鐘夜後聞。", "蟲聲沉古砌，螢影沒殘雲。", "會約長棲此，爐香樹下焚。"]'),
('b27e6c19-4a2d-41a9-b27d-acdc1ff72edc','贈清曉師','釋智圓','宋','宋诗','song-poetry','','[]','道勝塵機息，講餘林葉枯。',48,'全唐诗/poet.song.7000.json','["道勝塵機息，講餘林葉枯。", "清名高臥遠，黑髪苦吟無。", "庭靜秋雲澹，窗閑夜月孤。", "時聞適幽興，上閣望平湖。"]'),
('fb48bd31-d97d-4dc3-9682-5422df1dd9c6','寄德聰師','釋智圓','宋','宋诗','song-poetry','','[]','古院稽山下，幽棲厭客尋。',48,'全唐诗/poet.song.7000.json','["古院稽山下，幽棲厭客尋。", "機心禪外盡，詩思病來深。", "缾水寒澌結，杉風晚磬沉。", "他時若招隱，香火繼東林。"]'),
('84cf08ac-4f14-424d-a078-c6422f088eb8','上方院','釋智圓','宋','宋诗','song-poetry','','[]','禪扉開絕頂，海色映層巒。',48,'全唐诗/poet.song.7000.json','["禪扉開絕頂，海色映層巒。", "剎影浸寥泬，鐘聲度渺漫。", "荒苔幽徑滑，冬雪暮窗寒。", "吟罷慵回首，遲遲獨憑欄。"]'),
('75b2cf21-7812-4037-810b-848a49273b9b','登樓懷遵易','釋智圓','宋','宋诗','song-poetry','','[]','閑景杳無極，憑欄思若何。',48,'全唐诗/poet.song.7000.json','["閑景杳無極，憑欄思若何。", "鳥行沈遠嶽，秋色滿滄波。", "來信經年絕，新愁向晚多。", "依依自吟望，舊約負煙蘿。"]'),
('931acec7-0cef-4c0e-8fde-6b3399a890de','贈詩僧保暹師','釋智圓','宋','宋诗','song-poetry','','[]','吟檻漾寒水，平湖煙景閑。',48,'全唐诗/poet.song.7000.json','["吟檻漾寒水，平湖煙景閑。", "無人識高趣，盡日對空山。", "晚樹春禽語，晴窗夜月還。", "新編皆雅正，不待仲尼刪。"]'),
('847376d2-cf57-45cc-a7d6-6330a23ad984','寄石城行光長老','釋智圓','宋','宋诗','song-poetry','','[]','幽棲塵想絕，巖閣倚杉松。',48,'全唐诗/poet.song.7000.json','["幽棲塵想絕，巖閣倚杉松。", "吟思禪中盡，霜髭病後濃。", "溪閑澄夜月，山靜答秋鐘。", "寂寞懷高趣，殘陽獨倚筇。"]'),
('8cce8410-e1d8-45aa-abf8-8e7ab2ee3390','寄仁姪','釋智圓','宋','宋诗','song-poetry','','[]','庭木西風動，閑軒落葉稠。',48,'全唐诗/poet.song.7000.json','["庭木西風動，閑軒落葉稠。", "夢迴霜月曉，信斷海山秋。", "道性歸無念，孤吟已絕愁。", "況疏林下約，煙水路悠悠。"]'),
('02d2d7d5-41f9-47c3-929c-349907d1ca23','山行','釋智圓','宋','宋诗','song-poetry','','[]','策杖乘閑興，山深人迹稀。',48,'全唐诗/poet.song.7000.json','["策杖乘閑興，山深人迹稀。", "斷橋摧宿雨，高樹掛殘暉。", "巖靜雲孤起，潭空鳥獨飛。", "前峰有蘭若，吟賞自忘歸。"]'),
('6934e335-82d0-4e74-b394-721f7d4a72d7','秋日感事','釋智圓','宋','宋诗','song-poetry','','[]','滿眼皆相識，論心自不同。',48,'全唐诗/poet.song.7000.json','["滿眼皆相識，論心自不同。", "閑門扃夕照，敗葉落西風。", "往事全成夢，浮生漸覺空。", "搘頤獨無語，四壁響秋蟲。"]'),
('9ffd8c37-e604-4a79-be49-b8726a093368','湖上晚望寄友人','釋智圓','宋','宋诗','song-poetry','','[]','不得天涯信，相思對景濃。',48,'全唐诗/poet.song.7000.json','["不得天涯信，相思對景濃。", "驚飇吹落葉，殘日在遙峰。", "照水魚村火，沈煙野寺鐘。", "幽懷向誰說，靜立自搘筇。"]'),
('a19dbbdf-77fd-436b-9cc0-1ac4349b9381','贈聞聰師','釋智圓','宋','宋诗','song-poetry','','[]','淡然塵慮絕，禪外苦風騷。',48,'全唐诗/poet.song.7000.json','["淡然塵慮絕，禪外苦風騷。", "性覺眠雲僻，名因背俗高。", "水煙蒸紙帳，寒髪澀銅刀。", "幾宿江江寺，閑吟聽夜濤。"]'),
('14791da8-d8ef-42ab-8e3b-b6ae6d871eb9','送僧歸饒陽','釋智圓','宋','宋诗','song-poetry','','[]','執手離亭暮，言歸思不禁。',48,'全唐诗/poet.song.7000.json','["執手離亭暮，言歸思不禁。", "故鄉千里外，爲客十年心。", "帆影寒江靜，猿啼雪嶠深。", "饒陽泉石在，講退自堪吟。"]'),
('b3175d9c-8566-4a50-b9bf-0e6f5bbdbf45','悼廣鈞師','釋智圓','宋','宋诗','song-poetry','','[]','北僧傳示滅，高迹更難尋。',48,'全唐诗/poet.song.7000.json','["北僧傳示滅，高迹更難尋。", "故國房空在，新墳草已深。", "雲泉違舊約，風月罷論心。", "默坐看遺偈，西窗月又沈。"]'),
('2a7a0144-f4ea-4bed-9351-c44aa7136611','次韻酬鄰僧晝上人','釋智圓','宋','宋诗','song-poetry','','[]','居止閑相近，臨流野色分。',48,'全唐诗/poet.song.7000.json','["居止閑相近，臨流野色分。", "深秋山共見，清夜磬交聞。", "靜榻移明月，疏簾卷暮雲。", "相於別有趣，冷淡況同羣。"]'),
('e95fc778-8b28-49f5-9e11-1bd8c0e5b235','旅中別趙璞','釋智圓','宋','宋诗','song-poetry','','[]','策馬將登路，星河曙色分。',48,'全唐诗/poet.song.7000.json','["策馬將登路，星河曙色分。", "殘燈照離席，來雁咽寒雲。", "鄉遠書難到，吟狂酒易醺。", "堪嗟經濟術，未得致明君。"]'),
('b41c030c-993f-4587-ab4e-10edabfecace','旅中即事寄友生','釋智圓','宋','宋诗','song-poetry','','[]','欹枕不成夢，寒蟲叫壁陰。',48,'全唐诗/poet.song.7000.json','["欹枕不成夢，寒蟲叫壁陰。", "高梧深夜雨，遠客故鄉心。", "分與浮名背，年將白髪侵。", "終須約宗炳，結社向東林。"]'),
('72aea448-4605-49da-9af6-34c70cfe8885','秋晚客舍寄故山友僧','釋智圓','宋','宋诗','song-poetry','','[]','隱几不成寢，何人慰寂寥。',48,'全唐诗/poet.song.7000.json','["隱几不成寢，何人慰寂寥。", "空階鳴蟋蟀，寒雨滴芭蕉。", "靜語窗燈暗，歸心海寺遙。", "唯應釋慧遠，蓮社爲相招。"]'),
('7dd660ba-94f6-4f42-a69e-5b55628d777f','寄輦下譯經正覺大師','釋智圓','宋','宋诗','song-poetry','','[]','水國無歸夢，年來帝澤深。',48,'全唐诗/poet.song.7000.json','["水國無歸夢，年來帝澤深。", "梵書翻宋語，道論變吳音。", "靜室清香凝，閑庭古樹陰。", "玉華前事在，高跡許誰尋。"]'),
('663613ff-72ac-439d-8b1a-b048719b3611','寄潤姪法師','釋智圓','宋','宋诗','song-poetry','','[]','庭木凝秋色，依依廢苦吟。',48,'全唐诗/poet.song.7000.json','["庭木凝秋色，依依廢苦吟。", "來書江上絕，幽夢雨中深。", "水鳥閑窺硯，窗燈冷照琴。", "誰矢此時興，華髪暗相侵。"]'),
('e0c8cfdf-6a16-4815-813c-94742e7c72d9','贈白蓮社主圓凈大師','釋智圓','宋','宋诗','song-poetry','','[]','社客盡卿相，早堂雲樹間。',48,'全唐诗/poet.song.7000.json','["社客盡卿相，早堂雲樹間。", "景分廬嶽秀，人類遠公閑。", "夜定開明月，秋吟對暮山。", "唯應謝康樂，時得扣松關。"]'),
('4181ea2c-037e-4190-a15d-05248beb7a72','春晚言懷寄聰上人','釋智圓','宋','宋诗','song-poetry','','[]','晚樹歸禽亂，翛然古院空。',48,'全唐诗/poet.song.7000.json','["晚樹歸禽亂，翛然古院空。", "清談遠君子，幽興寄絲桐。", "短髪全成雪，殘花半逐風。", "終期結真侶，歸老亂雲中。"]'),
('240a0040-1260-45e1-81c9-a5ed6bb9acde','留題因師院石楠花','釋智圓','宋','宋诗','song-poetry','','[]','陽和資萬木，獨此異羣花。',48,'全唐诗/poet.song.7000.json','["陽和資萬木，獨此異羣花。", "映草驚殘燒，臨窗認曉霞。", "色雖因雨減，勢不逐風斜。", "幸賴栽培力，繁枝鬬日華。"]'),
('5db61685-9e8e-46bf-8490-b4fb4fb0b656','寄省悟師','釋智圓','宋','宋诗','song-poetry','','[]','平湖波渺渺，蹤跡杳難尋。',48,'全唐诗/poet.song.7000.json','["平湖波渺渺，蹤跡杳難尋。", "城裏無時到，雲邊閉戶深。", "寒燈明古像，晚磬出疏林。", "寂寞懷高趣，西軒日易沈。"]'),
('2c2dbceb-81e0-4093-915f-28e7d8bbe6b0','留題聞氏林亭小山','釋智圓','宋','宋诗','song-poetry','','[]','簷前狀奇險，咫尺見清幽。',48,'全唐诗/poet.song.7000.json','["簷前狀奇險，咫尺見清幽。", "鳥下疑靈鷲，僧過認沃洲。", "危遮虛檻月，冷奪遠峰秋。", "始信紅塵裏，豪家有勝遊。"]'),
('a12f8fcf-f118-42a0-a58d-d9b06b19accd','宿仲係上人房','釋智圓','宋','宋诗','song-poetry','','[]','偶從支遁約，深夜宿閑房。',48,'全唐诗/poet.song.7000.json','["偶從支遁約，深夜宿閑房。", "窗靜燈遺燼，庭寒樹有霜。", "禪心論的的，塵事省茫茫。", "又說天台去，林間掃石床。"]'),
('a6ac1687-749c-427d-bd72-1210767003da','題聰上人林亭','釋智圓','宋','宋诗','song-poetry','','[]','四面遠塵迹，吟過稱野情。',48,'全唐诗/poet.song.7000.json','["四面遠塵迹，吟過稱野情。", "階閑秋菓落，池冷月華生。", "倚竹蟬聲斷，開琴鶴夢驚。", "卻來還有約，未可厭逢迎。"]'),
('d4fcf86c-afbe-44e4-9316-1aaa1a7a5d07','書久上人城中幽齋','釋智圓','宋','宋诗','song-poetry','','[]','杉竹匝吟徑，軒窗更絕塵。',48,'全唐诗/poet.song.7000.json','["杉竹匝吟徑，軒窗更絕塵。", "清風生後夜，幽景徧諸鄰。", "磬斷棲禽夢，香凝出定身。", "城中有高趣，寧羨賴留人。"]'),
('52fde4cf-c9a2-4e89-bfff-0a08e72f5d38','江上作','釋智圓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','往事那堪問，長江空渺然。',48,'全唐诗/poet.song.7000.json','["往事那堪問，長江空渺然。", "孤城閉殘日，荒隴積寒煙。", "沙漲中洲闊，潮衝古各偏。", "莫疑陵谷事，即目是桑田。"]'),
('2bf5de3e-fee2-430a-976e-e3d4fb1ecc52','懷保暹師','釋智圓','宋','宋诗','song-poetry','','[]','高迹知何處，相懷早晚休。',48,'全唐诗/poet.song.7000.json','["高迹知何處，相懷早晚休。", "苦吟空對月，閉戶更禁秋。", "砌隙寒蟲切，林稍下葉稠。", "音書杳難寄，天闊水悠悠。"]'),
('b0dbc41a-fb81-41a3-986e-9ca720f8cb72','贈宣密大師不出院','釋智圓','宋','宋诗','song-poetry','','[]','侯門休請謁，香火務真修。',48,'全唐诗/poet.song.7000.json','["侯門休請謁，香火務真修。", "古院扃蒼蘚，他山空舊遊。", "出禪庭月曉，開卷竹窗秋。", "已得棲幽趣，何須買沃洲。"]'),
('fd7a0fa7-3cb8-4ca6-af5a-4dbab2aa8f79','懷中姪','釋智圓','宋','宋诗','song-poetry','','[]','一從林下別，倏忽又經年。',48,'全唐诗/poet.song.7000.json','["一從林下別，倏忽又經年。", "舊約山空在，相懷月屢圓。", "郡鐘宵斷夢，江樹晚沈煙。", "書札憑誰寄，波濤況渺然。"]'),
('9f75b8ef-a8e7-4ad0-a39b-b8807a3f1448','宿道場山寺','釋智圓','宋','宋诗','song-poetry','','[]','絕頂秋氣清，危欄憑樹杪。',48,'全唐诗/poet.song.7000.json','["絕頂秋氣清，危欄憑樹杪。", "仰窺清漢近，下視羣峰小。", "空池生夜月，風枝鳴宿鳥。", "吟坐不成寐，疏鐘起將曉。"]'),
('4476fec8-c777-4405-8d88-6f33c1a522af','送遇貞師歸四明山','釋智圓','宋','宋诗','song-poetry','','[]','吟餘江上別，一錫寄扁舟。',48,'全唐诗/poet.song.7000.json','["吟餘江上別，一錫寄扁舟。", "遠度浮殘照，千峰指舊遊。", "疏鐘沈杳靄，羣木落高秋。", "莫負重來約，禪心本自由。"]'),
('72c7b5d8-f90b-42cf-9669-91d978fca7d6','秋夕寄友僧','釋智圓','宋','宋诗','song-poetry','','[]','白雲高臥者，滯疾阻相尋。',48,'全唐诗/poet.song.7000.json','["白雲高臥者，滯疾阻相尋。", "信斷滄洲闊，房扃翠嶽深。", "寒蟲藏壞壁，庭樹滴殘霖。", "早晚同閑話，孤燈照苦吟。"]'),
('e234ece8-8724-4240-b15a-ded6386f4707','陳宮','釋智圓','宋','宋诗','song-poetry','','[]','龍盤虎踞景堪尋，王氣消亡信禍淫。',32,'全唐诗/poet.song.7000.json','["龍盤虎踞景堪尋，王氣消亡信禍淫。", "結綺臨春何處是，數聲啼鳥暮煙深。"]'),
('ee9ea842-c1d6-4020-84af-ea33ec01b10a','春日別同志','釋智圓','宋','宋诗','song-poetry','','[]','路歧南北與東西，竚立遲遲惜解攜。',32,'全唐诗/poet.song.7000.json','["路歧南北與東西，竚立遲遲惜解攜。", "忍向離亭折楊柳，晚花零落杜鵑啼。"]'),
('f456d5c4-1fe5-4810-ab32-33eb8c1ac1bb','夏日湖上寄太白長老','釋智圓','宋','宋诗','song-poetry','','[]','風撼芙蕖入座香，水軒閑坐趣何長。',32,'全唐诗/poet.song.7000.json','["風撼芙蕖入座香，水軒閑坐趣何長。", "相懷不是人間景，隔岸歸禽噪晚涼。"]'),
('18ddd58a-662f-454c-b904-ba495a3e6840','西湖','釋智圓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清带月華涵竹戶，冷澄秋色照禪衣。',32,'全唐诗/poet.song.7000.json','["清带月華涵竹戶，冷澄秋色照禪衣。", "滔滔潤物知多少，極目寒波瀁落暉。"]'),
('04e33d93-a874-4d9a-8801-37e87f4223ad','送禪者','釋智圓','宋','宋诗','song-poetry','','[]','祖意曾明萬事閑，誰云方外與人間。',32,'全唐诗/poet.song.7000.json','["祖意曾明萬事閑，誰云方外與人間。", "卷衣江上秋來別，處處禪心朵朵山。"]'),
('6ad6f3b6-807a-42be-afac-e02a684e04b6','古意','釋智圓','宋','宋诗','song-poetry','','[]','登山伐樵柯忽折，臨井汲泉綆仍絕。',32,'全唐诗/poet.song.7000.json','["登山伐樵柯忽折，臨井汲泉綆仍絕。", "音信不來無處說，朔風飄飄滿天雪。"]'),
('071b7e2d-484e-4e67-9537-3814180d0160','雲','釋智圓','宋','宋诗','song-poetry','','[]','冷照碧潭閑不極，靜當青漢影彌分。',32,'全唐诗/poet.song.7000.json','["冷照碧潭閑不極，靜當青漢影彌分。", "卷舒終合爲霖雨，不向陽臺惑楚君。"]'),
('01eabee3-2118-444d-90dd-adf35c4a3185','苔錢三首  其一','釋智圓','宋','宋诗','song-poetry','','[]','夷甫不言非爾類，魯襃爲論偶同名。',32,'全唐诗/poet.song.7000.json','["夷甫不言非爾類，魯襃爲論偶同名。", "秋來自滿虛閑地，不用良工鼓鑄成。"]'),
('e30d7208-7091-4fc7-be41-23e2bbf865db','苔錢三首  其二','釋智圓','宋','宋诗','song-poetry','','[]','求多未必增貪競，委積唯堪貰寂寥。',32,'全唐诗/poet.song.7000.json','["求多未必增貪競，委積唯堪貰寂寥。", "顔子黔婁舊居畔，亂鋪平地伴逍遙。"]'),
('c8ac301a-f14d-4483-a65f-d4b2a1a59fb4','苔錢三首  其三','釋智圓','宋','宋诗','song-poetry','','[]','鑪冶只應憑陋巷，富饒應不是豪家。',32,'全唐诗/poet.song.7000.json','["鑪冶只應憑陋巷，富饒應不是豪家。", "晚來雨歇茆堂外，散在閑庭買落花。"]'),
('f0570e25-fb42-4f83-b19c-0dd86666ff38','自遣三首  其一','釋智圓','宋','宋诗','song-poetry','','[]','古屋苔荒病重乍瘳，前村林木覺先秋。',33,'全唐诗/poet.song.7000.json','["古屋苔荒病重乍瘳，前村林木覺先秋。", "野塘日暮搘筇立，雲自無依水自流。"]'),
('0ec8f503-9356-4d10-bee2-7a1c022ab430','自遣三首  其二','釋智圓','宋','宋诗','song-poetry','','[]','講退時時學苦吟，人間聲利已無心。',32,'全唐诗/poet.song.7000.json','["講退時時學苦吟，人間聲利已無心。", "水邊占得清閑景，雨霽遙峰夜月深。"]'),
('552e76b3-401c-4280-a5c5-782b9ec42fae','自遣三首  其三','釋智圓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不惑年猶欠四年，道情高趣恥前賢。',32,'全唐诗/poet.song.7000.json','["不惑年猶欠四年，道情高趣恥前賢。", "清風明月知多少，漫學廬山種白蓮。"]'),
('d050b13e-8cb8-4d32-85e2-4f224bb1a2a3','送僧','釋智圓','宋','宋诗','song-poetry','','[]','萬緣難繫自由身，道性何妨學世人。',32,'全唐诗/poet.song.7000.json','["萬緣難繫自由身，道性何妨學世人。", "擬向東山贈離別，長堤楊柳未成春。"]'),
('38a144a3-7352-4e17-b38a-df129ec0a6c2','庭竹','釋智圓','宋','宋诗','song-poetry','','[]','移去羣花種此君，滿庭寒翠更無塵。',32,'全唐诗/poet.song.7000.json','["移去羣花種此君，滿庭寒翠更無塵。", "暑天閑繞煩襟盡，猶有清風借四鄰。"]'),
('6d504f9d-4404-48d5-817f-95308e718d23','雞','釋智圓','宋','宋诗','song-poetry','','[]','簷前棲息傍蒿叢，風雨司晨爾有功。',31,'全唐诗/poet.song.7000.json','["簷前棲息傍蒿叢，風雨司晨爾有功。", "鸚鵡無能憑佞舌，侯門翻養金籠。"]'),
('295a8265-c2c0-43b3-817f-34b8d1a7f75e','送僧之金陵','釋智圓','宋','宋诗','song-poetry','','[]','金錫孤攜問去程，萋萋原草暮煙平。',32,'全唐诗/poet.song.7000.json','["金錫孤攜問去程，萋萋原草暮煙平。", "六朝舊跡秦淮畔，應感興亡聽水聲。"]'),
('7214a54a-b695-4acc-844e-dbb2a6dd99c9','出道場山途中作','釋智圓','宋','宋诗','song-poetry','','[]','獨下層巒景物秋，依依雲木似相留。',32,'全唐诗/poet.song.7000.json','["獨下層巒景物秋，依依雲木似相留。", "孤舟曉汎平波去，更爲青山一轉頭。"]'),
('de88de59-0ac7-4e3d-9274-2f618433ad8d','將之霅溪寄別擇梧師','釋智圓','宋','宋诗','song-poetry','','[]','憶得涼宵宿上方，靜吟閑話趣何長。',32,'全唐诗/poet.song.7000.json','["憶得涼宵宿上方，靜吟閑話趣何長。", "別來音信無由寄，目斷遙天雁一行。"]'),
('55cbc8eb-6f53-4b0a-a1ff-32a4bdc5e9a1','次韻酬梵天闍梨','釋智圓','宋','宋诗','song-poetry','','[]','數峰殘雪對閑門，世態悠悠莫可論。',32,'全唐诗/poet.song.7000.json','["數峰殘雪對閑門，世態悠悠莫可論。", "靜室禪餘忽相憶，劃灰孤坐到黄昏。"]'),
('ebd1e775-7921-4798-b570-f6d969cb10fc','溪居即事寄梵天闍梨','釋智圓','宋','宋诗','song-poetry','','[]','松竹森森獨掩扉，塵中誰復愛忘機。',32,'全唐诗/poet.song.7000.json','["松竹森森獨掩扉，塵中誰復愛忘機。", "蒼苔滿砌無人到，猶感幽禽夜夜歸。"]'),
('7a98cd46-466e-4e63-895f-6212d9e676ba','武康溪居即事寄寶印大師四首  其一','釋智圓','宋','宋诗','song-poetry','','[]','偶來溪上縱閑吟，泉石深藏便有心。',32,'全唐诗/poet.song.7000.json','["偶來溪上縱閑吟，泉石深藏便有心。", "莫擬他年訪幽迹，白雲青嶂更難尋。"]'),
('4be5c7a3-2b44-4a01-b597-53b185a27948','武康溪居即事寄寶印大師四首  其二','釋智圓','宋','宋诗','song-poetry','','[]','月下猿聲水畔山，臥聽吟望只宜閑。',32,'全唐诗/poet.song.7000.json','["月下猿聲水畔山，臥聽吟望只宜閑。", "柴門不掩無來客，時有精靈暫往還。"]'),
('3f700db8-56f4-42b4-a90d-98e8e168ce12','武康溪居即事寄寶印大師四首  其三','釋智圓','宋','宋诗','song-poetry','','[]','世路驅驅又白頭，爭如閑臥絕他求。',32,'全唐诗/poet.song.7000.json','["世路驅驅又白頭，爭如閑臥絕他求。", "門前荒隴依依在，碑折松枯盡列侯。"]'),
('7a15fbc9-4c44-47b1-81ac-d0c4b6a3e4e2','武康溪居即事寄寶印大師四首  其四','釋智圓','宋','宋诗','song-poetry','','[]','禪外相懷雪乍晴，音書早晚到柴扃。',32,'全唐诗/poet.song.7000.json','["禪外相懷雪乍晴，音書早晚到柴扃。", "殘陽獨倚危樓望，極目山光數點青。"]'),
('b6831592-2ff4-439c-998d-7d1df08afa2e','瑪瑙院居戲題三首  其一','釋智圓','宋','宋诗','song-poetry','','[]','水邊閑臥萬緣休，言欲無瑕行欲修。',32,'全唐诗/poet.song.7000.json','["水邊閑臥萬緣休，言欲無瑕行欲修。", "草屋衡門任窮困，屠龍終自勝屠牛。"]'),
('b2f18cb4-3557-4dd3-94d2-c5ffafbcb556','瑪瑙院居戲題三首  其二','釋智圓','宋','宋诗','song-poetry','','[]','湖光淡淡涵幽戶，苔色依依滿破廊。',32,'全唐诗/poet.song.7000.json','["湖光淡淡涵幽戶，苔色依依滿破廊。", "寂寞便同夫子廟，更無流俗入焚香。"]'),
('c9601a43-d26c-46d4-a39f-69485dd6a02e','瑪瑙院居戲題三首  其三','釋智圓','宋','宋诗','song-poetry','','[]','白傅湖西瑪瑙坡，軒窗蕭灑瀁煙波。',32,'全唐诗/poet.song.7000.json','["白傅湖西瑪瑙坡，軒窗蕭灑瀁煙波。", "講餘終日焚香坐，毀譽榮枯奈我何。"]'),
('a51ec520-e7d5-42ca-a9f8-27ebc32e7ece','予近卜居孤山之下友人元敏以四絕見嘲遂依韻和酬  其一','釋智圓','宋','宋诗','song-poetry','','[]','窮居已躡黔婁迹，孤島徒稱瑪瑙坡。',32,'全唐诗/poet.song.7000.json','["窮居已躡黔婁迹，孤島徒稱瑪瑙坡。", "糗飯蔾羹且閑樂，更無車馬暫經過。"]'),
('14b2a9b7-70f5-4f2c-8a5e-0976d2bb0ff6','予近卜居孤山之下友人元敏以四絕見嘲遂依韻和酬  其二','釋智圓','宋','宋诗','song-poetry','','[]','所棲幽致異人寰，野艇秋歸碧浪間。',32,'全唐诗/poet.song.7000.json','["所棲幽致異人寰，野艇秋歸碧浪間。", "殘日淡煙凝望處，參差樓閣認孤山。"]'),
('1e46bd40-7489-4e84-b6e1-4847bb402691','予近卜居孤山之下友人元敏以四絕見嘲遂依韻和酬  其三','釋智圓','宋','宋诗','song-poetry','','[]','煙波雲木映閑扉，養病深棲是所宜。',32,'全唐诗/poet.song.7000.json','["煙波雲木映閑扉，養病深棲是所宜。", "便欲上生尋內院，卻因泉石住多時。"]'),
('9c5d12e2-3c50-49ad-8765-291fe78956cc','予近卜居孤山之下友人元敏以四絕見嘲遂依韻和酬  其四','釋智圓','宋','宋诗','song-poetry','','[]','虛堂入夏講殘經，不擊鐘聲擊鼓聲。',32,'全唐诗/poet.song.7000.json','["虛堂入夏講殘經，不擊鐘聲擊鼓聲。", "林下唯君問幽趣，紀陽儀式近方成。"]'),
('0844ba29-273f-44d9-9df0-1e554e30307d','庭鶴','釋智圓','宋','宋诗','song-poetry','','[]','支遁放君真有意，衛公憐汝太無端。',32,'全唐诗/poet.song.7000.json','["支遁放君真有意，衛公憐汝太無端。", "司晨守禦那堪用，殷頂霜毛祇好看。"]'),
('77fd8842-e311-4ecb-8594-9b342fc672ef','寄天台守能上人','釋智圓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','台嶺林泉勝十洲，忘機長往更無愁。',64,'全唐诗/poet.song.7000.json','["台嶺林泉勝十洲，忘機長往更無愁。", "考槃高趣何人識，招隱新題幾處留。", "深夜定迴華頂月，經年書斷海門秋。", "誰知抱疾西湖上，南望雲山想勝游。"]'),
('e8d741f1-07c6-481d-adc9-203d10be3017','寄所知','釋智圓','宋','宋诗','song-poetry','','[]','寵辱不關念，揚名日更新。',120,'全唐诗/poet.song.7000.json','["寵辱不關念，揚名日更新。", "但憐君道在，寧顧謫官頻。", "故國拋天外，全家寄水濱。", "堂空巢少燕，門冷謁無人。", "直氣終干斗，剛腸肯泣麟。", "逍遙輕嗣立，乾沒笑安仁。", "愛生長思闕，尋幽且養神。", "伴閑初種竹，出使舊埋輪。", "佞古終期斷，民冤必爲伸。", "他年修史傳，誰可繼清塵。"]'),
('20536add-5a50-4106-9bd9-076cb34c13f4','題石壁山紹上人觀風亭','釋智圓','宋','宋诗','song-poetry','','[]','界江千萬山，石壁惟清幽。',96,'全唐诗/poet.song.7000.json','["界江千萬山，石壁惟清幽。", "中有忘機人，超然樂巖丘。", "倉亭號觀風，嘉景自成收。", "羣峰呈晚碧，長溪瀉寒流。", "視聽足怡情，萬事安能求。", "嘗言徂暑天，登時疑清秋。", "雲容既冷淡，松韻還颼飀。", "擾擾九衢塵，誰知高靜游。"]'),
('38d5b5db-f6f7-4412-b832-1f7e060f8143','昭君辭','釋智圓','宋','宋诗','song-poetry','','[]','昭君停車淚暫止，爲把功名奏天子。',32,'全唐诗/poet.song.7000.json','["昭君停車淚暫止，爲把功名奏天子。", "靜得胡塵跗妾身，漢家文武合羞死。"]'),
('c3e5a146-5e41-4965-bcff-b6258e8a0f1e','老將','釋智圓','宋','宋诗','song-poetry','','[]','畫堂升降子孫扶，白髪毿毿膽尚麤。',32,'全唐诗/poet.song.7000.json','["畫堂升降子孫扶，白髪毿毿膽尚麤。", "不省時清身已老，逢人猶說斬單于。"]'),
