('6a627761-3cf2-4f15-9637-0c0d512a301e','放猿','釋智圓','宋','宋诗','song-poetry','','[]','放汝孤猿任自由，萬山雲樹正含秋。',32,'全唐诗/poet.song.7000.json','["放汝孤猿任自由，萬山雲樹正含秋。", "不知今夜啼明月，又使何人淚暗流。"]'),
('52759cff-e7fc-4b46-a51d-dd04de9ca0d4','湖上望月二首  其一','釋智圓','宋','宋诗','song-poetry','','[]','秋水澄澄樹絕風，冰輪苒苒上遙空。',32,'全唐诗/poet.song.7000.json','["秋水澄澄樹絕風，冰輪苒苒上遙空。", "閑思今夜供吟景，冷色清光幾處同。"]'),
('4d39d21f-22c1-4b6f-bd74-60098fa3e481','湖上望月二首  其二','釋智圓','宋','宋诗','song-poetry','','[]','寒光皎皎映平湖，水色天形兩不殊。',32,'全唐诗/poet.song.7000.json','["寒光皎皎映平湖，水色天形兩不殊。", "學道未能同罔象，也於深處見圓珠。"]'),
('cdb0ade3-0971-432c-baa5-aefef4f3412f','詠亡有禪師山齋養獼猴','釋智圓','宋','宋诗','song-poetry','','[]','閑庭樹樹菓垂霜，聽法猶憐入草堂。',32,'全唐诗/poet.song.7000.json','["閑庭樹樹菓垂霜，聽法猶憐入草堂。", "異類豈能知禮節，每來相對坐禪床。"]'),
('db1ee500-b135-4304-8fcf-5cec96d787a4','贈廣上人','釋智圓','宋','宋诗','song-poetry','','[]','魏闕林泉趣本同，隨緣來往興何窮。',32,'全唐诗/poet.song.7000.json','["魏闕林泉趣本同，隨緣來往興何窮。", "閑宵訪我茆堂宿，湖水無波月照空。"]'),
('0ea61f8f-a642-4102-81b8-a129953f823a','正月晦日作','釋智圓','宋','宋诗','song-poetry','','[]','春晴殘日照平川，老幼相攜古岸邊。',32,'全唐诗/poet.song.7000.json','["春晴殘日照平川，老幼相攜古岸邊。", "富貴在天誰肯信，臨流爭放送窮舟。"]'),
('4de97cda-1e02-481c-b2f9-fed82b7c13db','讀羅隱詩集','釋智圓','宋','宋诗','song-poetry','','[]','非非是是正人倫，月夜花朝幾損神。',32,'全唐诗/poet.song.7000.json','["非非是是正人倫，月夜花朝幾損神。", "薄俗不知懲勸旨，翻嫌羅隱一生嗔。"]'),
('28dd65d1-d1ce-4087-9bee-d3ed45e485b2','落花','釋智圓','宋','宋诗','song-poetry','','[]','花開花落盡由風，數日榮衰事不同。',32,'全唐诗/poet.song.7000.json','["花開花落盡由風，數日榮衰事不同。", "庭下晚來猶可翫，綠苔芳草綴殘紅。"]'),
('e99ec388-c0bc-4dea-8f11-cd0e0134682e','織婦','釋智圓','宋','宋诗','song-poetry','','[]','九月風高未授衣，燈前軋軋夜鳴機。',32,'全唐诗/poet.song.7000.json','["九月風高未授衣，燈前軋軋夜鳴機。", "困來不覺支頤睡，鼠齧絲頭四散飛。"]'),
('392fa8ea-a1c8-4399-800a-6e86ef75c1e2','柳','釋智圓','宋','宋诗','song-poetry','','[]','融融春色伴花榮，濃翠參差雨乍晴。',64,'全唐诗/poet.song.7000.json','["融融春色伴花榮，濃翠參差雨乍晴。", "低拂冷煙元亮宅，靜籠明月亞夫營。", "葉浮晚水愁眉細，絮落春衣雪片輕。", "莫上隋堤思往事，萬株蕭索傍河聲。"]'),
('100f2bc8-a652-4906-9441-25b83f7a3423','牡丹','釋智圓','宋','宋诗','song-poetry','','[]','栽培寧暇問耕桑，紅白相鮮映畫堂。',64,'全唐诗/poet.song.7000.json','["栽培寧暇問耕桑，紅白相鮮映畫堂。", "淚濕濃粧含曉露，火燔寒玉照斜陽。", "黄金剩買心無厭，綺席閑觀興更狂。", "誰向風前悟零落，百年榮盛事非長。"]'),
('04ab4272-1225-4e5b-ba08-6d39fc140071','雁','釋智圓','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','歲歲隨陽整羽翰，翱翔還見過雲端。',64,'全唐诗/poet.song.7000.json','["歲歲隨陽整羽翰，翱翔還見過雲端。", "哀音斷續霜風緊，羣影參差夜月殘。", "鵰鶚已逃榆塞險，煙波初下洞庭寬。", "行人萬里思歸切，送目遙空寄信難。"]'),
('19725163-a4be-4986-89a5-19c34a085fc4','浙江晚望','釋智圓','宋','宋诗','song-poetry','','[]','景象依依滿目前，倚筇閑望思凄然。',64,'全唐诗/poet.song.7000.json','["景象依依滿目前，倚筇閑望思凄然。", "隔雲清磬山傍寺，照水孤燈渡口船。", "蕩漭落潮平古岸，參差歸雁沒遙天。", "錢王霸業今何在，牢落荒城積野煙。"]'),
('b6b0bc4c-9469-4820-92a2-1dee862e4428','寄雪竇長老','釋智圓','宋','宋诗','song-poetry','','[]','絕頂久潛隱，心閑道更真。',48,'全唐诗/poet.song.7000.json','["絕頂久潛隱，心閑道更真。", "山深林下雪，堂靜晝無人。", "雲抱看經石，禽接入定身。", "敢言他世約，安養願相親。"]'),
('67015163-cb26-482c-91d9-41d3e080cff7','君復處士棲大師夙有翫月泛湖之約予以臥病致爽前期因爲此章聊以道意','釋智圓','宋','宋诗','song-poetry','','[]','涼風吹衆木，羸病轉加前。',48,'全唐诗/poet.song.7000.json','["涼風吹衆木，羸病轉加前。", "伏枕誰相問，中秋月又圓。", "清光浮遠嶠，冷色混平川。", "不得同支許，乘舟樂浩然。"]'),
('d185d3e3-9e7a-46db-9995-2bf8f2884bb2','寄西山智道人','釋智圓','宋','宋诗','song-poetry','','[]','凈業修持久，攀緣念已摧。',48,'全唐诗/poet.song.7000.json','["凈業修持久，攀緣念已摧。", "冰潭殘月在，古岸夜禪回。", "像燭微留燄，爐香冷變灰。", "時逢舊參侶，閑坐話黄梅。"]'),
('f0e05ecb-0aa5-41f2-901b-95b8610cc06a','寄慧雲大師','釋智圓','宋','宋诗','song-poetry','','[]','繁華辭帝輦，岑寂巒山林。',48,'全唐诗/poet.song.7000.json','["繁華辭帝輦，岑寂巒山林。", "志向浮名淡，房扃古寺深。", "詩窗來皓月，齋磬下幽禽。", "終約逢新雪，閑過話靜心。"]'),
('aa53368e-f944-4763-b731-7deb55188ca2','寄海慧大師','釋智圓','宋','宋诗','song-poetry','','[]','雲門卜深隱，誰復繼高蹤。',48,'全唐诗/poet.song.7000.json','["雲門卜深隱，誰復繼高蹤。", "舊寺拋雙闕，新題詠十峰。", "禪開杉徑月，講候雪樓鐘。", "莫怪相尋晚，嵇康性本慵。"]'),
('c1b60dff-4d75-4955-bd15-1732e0e3207d','洞霄宮','釋智圓','宋','宋诗','song-poetry','','[]','蕭灑絕塵跡，虛廊畫列仙。',48,'全唐诗/poet.song.7000.json','["蕭灑絕塵跡，虛廊畫列仙。", "洞靈潛徹海，山峭欲奔天。", "松古巢高鶴，庭閑湧異泉。", "長生如有術，誰復嘆流年。"]'),
('004e7d20-05c8-4cf7-8ab0-fa54596595f1','久病','釋智圓','宋','宋诗','song-poetry','','[]','五月茆堂臥，窮秋疾未除。',48,'全唐诗/poet.song.7000.json','["五月茆堂臥，窮秋疾未除。", "喬林葉盡落，舊識分皆疏。", "講室縈蛛網，書床長蠹魚。", "醫王有妙藥，飲了萬緣虛。"]'),
('e17b96c2-6bb3-42a6-9bf3-c7a5e00fdd60','山堂落成招林處士','釋智圓','宋','宋诗','song-poetry','','[]','搆廈當高巘，登臨稱遯仙。',48,'全唐诗/poet.song.7000.json','["搆廈當高巘，登臨稱遯仙。", "澄波寒浸郭，疊翠冷搘天。", "野艇浮殘照，僧樓襪淡煙。", "此中無俗物，自可會清賢。"]'),
('27400cdd-9670-4117-b2ac-6c6b0e0f0c80','九月望夜招處士林君泛湖翫月','釋智圓','宋','宋诗','song-poetry','','[]','病負中秋約，殘秋月自新。',48,'全唐诗/poet.song.7000.json','["病負中秋約，殘秋月自新。", "寒波沈皓魄，碧落輾冰輪。", "風靜砧聲絕，煙收嶽影均。", "何妨此夕翫，況是不羈人。"]'),
('38a67882-b5c5-4f93-aacf-7d88119d1a97','病起','釋智圓','宋','宋诗','song-poetry','','[]','秋盡積雨歇，幽憂病漸安。',48,'全唐诗/poet.song.7000.json','["秋盡積雨歇，幽憂病漸安。", "眼疼嫌字小，身瘦覺衣寬。", "倚杖防苔滑，開爐怯夜寒。", "浮生能幾日，長作水漚觀。"]'),
('4e45caa7-51bd-4974-86db-f5899bac197e','賦得送人自闕下還吳','釋智圓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','蓴羹鱸膾美，張翰忽思歸。',48,'全唐诗/poet.song.7000.json','["蓴羹鱸膾美，張翰忽思歸。", "煙水東南闊，風帆旦夕飛。", "靜吟新月正，閑望舊山微。", "獨羨長江上，遺名掩竹扉。"]'),
('aea5d7df-ace0-428c-a475-49c3652a1a76','贈駱偃','釋智圓','宋','宋诗','song-poetry','','[]','才高淹下位，聖代尚遺賢。',48,'全唐诗/poet.song.7000.json','["才高淹下位，聖代尚遺賢。", "賈誼方流涕，楊雄正草玄。", "開琴逢皓月，試茗選清泉。", "篋有文編在，時容後學傳。"]'),
('87e2291e-5f97-49c5-b010-686de9b0375b','病中雨夜懷同志','釋智圓','宋','宋诗','song-poetry','','[]','杉竹競霪霪，天時正積陰。',48,'全唐诗/poet.song.7000.json','["杉竹競霪霪，天時正積陰。", "背窗秋燭暗，欹枕夜堂深。", "月被重雲蔽，螢依濕氣沉。", "無憀不成寐，況復想知音。"]'),
('1371c8ff-d9cc-46f6-a7b0-848dc3658ec3','游風水洞僧院','釋智圓','宋','宋诗','song-poetry','','[]','風水分雙洞，幽奇類沃洲。',48,'全唐诗/poet.song.7000.json','["風水分雙洞，幽奇類沃洲。", "猿吟清徹夜，山色冷宜秋。", "雲擁階前石，鐘殘竹畔樓。", "賢哉白太守，五馬舊曾遊。"]'),
('eddb24ad-2d07-4b40-8303-aae904a7a6a9','白髪','釋智圓','宋','宋诗','song-poetry','','[]','華髪如春卉，森森易滿頭。',48,'全唐诗/poet.song.7000.json','["華髪如春卉，森森易滿頭。", "栽培全仗老，澆灌半憑愁。", "世態誰能避，仙方莫漫求。", "迴觀短折者，欲見更無由。"]'),
('63fa446c-9d61-4b1c-87e3-171f9983292e','夜懷張逸人','釋智圓','宋','宋诗','song-poetry','','[]','默坐懷幽趣，誰知動鬰陶。',48,'全唐诗/poet.song.7000.json','["默坐懷幽趣，誰知動鬰陶。", "窗虛殘月在，天靜少微高。", "書去言難盡，眠來夢亦勞。", "終期冒風雪，乘興泛輕舠。"]'),
('3206b6c3-b233-4fc1-8dde-b3a561256933','贈頭陀僧','釋智圓','宋','宋诗','song-poetry','','[]','上行唯知足，時人豈易同。',48,'全唐诗/poet.song.7000.json','["上行唯知足，時人豈易同。", "一身依樹下，萬慮盡禪中。", "乞食村飄雪，降眠月墜空。", "應悲浮世上，煩惱事無窮。"]'),
('c141a704-3479-40d9-9d01-be6a07e60e8c','懷石壁山寺','釋智圓','宋','宋诗','song-poetry','','[]','梵宮藏積翠，往歲屢遊遨。',48,'全唐诗/poet.song.7000.json','["梵宮藏積翠，往歲屢遊遨。", "月上寒溪靜，雲收峭壁高。", "幽階封藥草，古樹宿猿猱。", "終待攜瓶錫，閑棲解鬰陶。"]'),
('eeba9174-d5b6-43e4-8d1f-bd40981430a1','與友人夜話','釋智圓','宋','宋诗','song-poetry','','[]','對坐當清夜，茆堂野水西。',48,'全唐诗/poet.song.7000.json','["對坐當清夜，茆堂野水西。", "破窗秋燭冷，高木老猿啼。", "跡與孤雲並，身將一夢齊。", "幽懷言未已，明月落前溪。"]'),
('89a664ad-bc2a-4f0c-a801-de04be7e928c','漢武帝','釋智圓','宋','宋诗','song-poetry','','[]','酷矣秦皇滅，荒哉漢武還。',48,'全唐诗/poet.song.7000.json','["酷矣秦皇滅，荒哉漢武還。", "將軍封五利，神藥訪三山。", "重色爲金屋，窮兵過玉關。", "豈知堯舜道，千古在人間。"]'),
('59ff903f-df27-48cb-b03c-a973130470be','送進士萬知古','釋智圓','宋','宋诗','song-poetry','','[]','經明行修徒爾爲，一名屢點春官闈。',112,'全唐诗/poet.song.7000.json','["經明行修徒爾爲，一名屢點春官闈。", "時之不利非戰罪，歸山且著老萊衣。", "清時貧賤誠堪恥，侏儒太飽朔方饑。", "男兒會有及親祿，安能泉石久低眉。", "束書依舊西入闕，壯心潛與青雲期。", "秋風嫋嫋孤魂斷，古道迢迢去馬遲。", "驥稱其德不稱力，神駿唯應伯樂知。"]'),
('a2287041-e2c8-48f5-9f72-276eb2477897','寄隱者','釋智圓','宋','宋诗','song-poetry','','[]','散髪空林下，人間事不知。',48,'全唐诗/poet.song.7000.json','["散髪空林下，人間事不知。", "風高蕙帳冷，天遠鶴書遲。", "瓶盡花朝酒，扃殘寒夜棋。", "無由訪幽趣，蹤跡阻江湄。"]'),
('0a80a4e2-cb00-48ff-a317-a4acae3b9d39','贈誦經僧','釋智圓','宋','宋诗','song-poetry','','[]','寂淡無餘念，泠泠誦佛言。',48,'全唐诗/poet.song.7000.json','["寂淡無餘念，泠泠誦佛言。", "清香飄靜夜，明月冷閑軒。", "幽壑來精怪，霜林息斷猿。", "堪嗟浮世裏，塵事競暄暄。"]'),
('8b3b5712-bd33-481f-8b80-8d5e739747df','寄梵天上方政姪','釋智圓','宋','宋诗','song-poetry','','[]','一講更無事，翛然自不羣。',48,'全唐诗/poet.song.7000.json','["一講更無事，翛然自不羣。", "閑情江上月，孤迹檻前雲。", "徑冷秋苔合，杉寒宿鳥分。", "濤聲旦暮近，應向出禪聞。"]'),
('cd1a3d88-bb25-471e-aadf-9cb7981f71e1','久病有感因示後學','釋智圓','宋','宋诗','song-poetry','','[]','羸病身未死，輕安人屢亡。',48,'全唐诗/poet.song.7000.json','["羸病身未死，輕安人屢亡。", "穹旻不可問，浮世轉加傷。", "三十共嗟短，百年同好長。", "未能齊一夢，何以事空王。"]'),
('c9c41671-5db9-404c-9659-079c0b51945e','山中聞知己及第','釋智圓','宋','宋诗','song-poetry','','[]','交知心莫逆，出處任相違。',48,'全唐诗/poet.song.7000.json','["交知心莫逆，出處任相違。", "月裏方攀桂，山中自採薇。", "致君期有術，遯世貴無機。", "華髪他年事，雲泉亦可歸。"]'),
('fa7039f7-8e84-4f52-8d0a-cb57a8dfd463','寄江上僧','釋智圓','宋','宋诗','song-poetry','','[]','江寺期終老，清香講次焚。',48,'全唐诗/poet.song.7000.json','["江寺期終老，清香講次焚。", "月憐秋後見，潮愛夜深聞。", "古木青陰合，殘雲靜片分。", "相懷未能去，來雁又成羣。"]'),
('8ad8d6c8-0cbe-410d-8562-ab3148f5799d','送人歸舊隱','釋智圓','宋','宋诗','song-poetry','','[]','要地慵投刺，剛腸恥折腰。',48,'全唐诗/poet.song.7000.json','["要地慵投刺，剛腸恥折腰。", "舊山歸興切，殘日去程遙。", "大野明殘燒，空江響落潮。", "到時雲樹下，靜聽厭懸瓢。"]'),
('ecbc8c0a-f613-4047-a70b-b92421b90759','砌下老梅','釋智圓','宋','宋诗','song-poetry','','[]','傍砌根全露，凝煙竹半遮。',48,'全唐诗/poet.song.7000.json','["傍砌根全露，凝煙竹半遮。", "臘深空冒雪，春老始開花。", "止渴功應少，和羹味亦嘉。", "行人憐怪狀，上漢採爲槎。"]'),
('ddc835c8-5c80-4d8a-a9bb-dbf46973b3e9','寄余秀才','釋智圓','宋','宋诗','song-poetry','','[]','去秋曾訪我，一別又經年。',48,'全唐诗/poet.song.7000.json','["去秋曾訪我，一別又經年。", "落日無來信，西風滿耳蟬。", "頭應添素髪，詩合有新編。", "未可輕丹桂，蹉跎老海邊。"]'),
('283f360f-c89d-4072-a0d3-01ac96d524fa','經通慧僧錄影堂','釋智圓','宋','宋诗','song-poetry','','[]','寂爾歸真界，人間化已成。',48,'全唐诗/poet.song.7000.json','["寂爾歸真界，人間化已成。", "兩朝欽至業，四海仰高名。", "舊跡存花社，遺編滿帝京。", "徘徊想前事，庭樹跪鴉鳴。"]'),
('d3d83044-8dc3-4f81-862e-9fcc27156818','深居','釋智圓','宋','宋诗','song-poetry','','[]','牢落誰知趣，深居野興饒。',51,'全唐诗/poet.song.7000.json','["牢落誰知趣，深居野興饒。", "固窮期道在，寡全國政協鄙時澆。", "徑靜苔長綠，山寒雪未消。", "殘陽荷輕策，閑望傍村橋。"]'),
('14a5f4c3-dd2d-47a6-9673-5c59581a841f','書事','釋智圓','宋','宋诗','song-poetry','','[]','年過不惑便衰殘，消息浮生萬事閑。',32,'全唐诗/poet.song.7000.json','["年過不惑便衰殘，消息浮生萬事閑。", "慚愧眼前無俗物，舉頭終日見雲山。"]'),
('a33db62f-b2d8-4fd9-8177-b97b320df395','將入石壁山作','釋智圓','宋','宋诗','song-poetry','','[]','慧遠風流廬嶽隱，支公高尚沃洲棲。',32,'全唐诗/poet.song.7000.json','["慧遠風流廬嶽隱，支公高尚沃洲棲。", "閑思石壁堪長往，擬躡浮雲上石梯。"]'),
('e6a7cd1d-2ff4-4847-893a-6747a40d4e80','瑪瑙坡即事','釋智圓','宋','宋诗','song-poetry','','[]','瑪瑙坡前住，清幽絕世緣。',48,'全唐诗/poet.song.7000.json','["瑪瑙坡前住，清幽絕世緣。", "湖澄秋夜月，山碧晚晴天。", "了性方成佛，燒丹漫學仙。", "會逢溫伯雪，目擊道還全。"]'),
('72e7f663-98f5-4c01-b80d-367bf05773cc','自嘲','釋智圓','宋','宋诗','song-poetry','','[]','門徑任苔荒，長年寢一床。',48,'全唐诗/poet.song.7000.json','["門徑任苔荒，長年寢一床。", "病中消白日，詩裏發清狂。", "窗暗雲遮月，林明葉墜霜。", "百年能幾日，兩鬢已蒼蒼。"]'),
('ab90a568-78b8-400e-b823-3cf633f22fce','草堂書懷','釋智圓','宋','宋诗','song-poetry','','[]','浮華念久絕，閑臥愛茆堂。',48,'全唐诗/poet.song.7000.json','["浮華念久絕，閑臥愛茆堂。", "門外滄洲闊，閑中白日長。", "庭寒頻墜果，爐暖忽飄香。", "寂寂無他事，誰知世路忙。"]'),
('fb52fd33-046e-4e09-a81d-c1f645c146d1','中秋待月值雨','釋智圓','宋','宋诗','song-poetry','','[]','一歲期今夕，高空雨忽零。',48,'全唐诗/poet.song.7000.json','["一歲期今夕，高空雨忽零。", "虛窗沈素影，疏竹動秋聲。", "已被雲陰閉，徒懷永夜明。", "徘徊倚山閣，誰見此時情。"]'),
('a48bf611-a851-4510-ba63-529b7b1e9a6e','少年行','釋智圓','宋','宋诗','song-poetry','','[]','兒奴屢背約，辱我漢天子。',48,'全唐诗/poet.song.7000.json','["兒奴屢背約，辱我漢天子。", "瞋目而語難，五陵年少子。", "舉手提三尺，報國在一死。", "匹馬立奇勳，壯哉傅介子。"]'),
('a64ae2bf-bc82-4875-9eaf-f4c2aa36489b','偶成','釋智圓','宋','宋诗','song-poetry','','[]','世態如輪轉，勞生豈定期。',48,'全唐诗/poet.song.7000.json','["世態如輪轉，勞生豈定期。", "否終還受泰，樂極又生悲。", "商代尊伊尹，秦庭戮李斯。", "未能知幻化，安得證無爲。"]'),
('a88ec494-de36-42f6-94c4-3d9eb898659d','失鶴','釋智圓','宋','宋诗','song-poetry','','[]','隻鶴忽飛去，清音更不聞。',48,'全唐诗/poet.song.7000.json','["隻鶴忽飛去，清音更不聞。", "遠應尋鳳侶，閑恐避雞羣。", "岸靜休臨水，庭空罷舞雲。", "唯餘舊蹤跡，篆字印苔紋。"]'),
('db341063-72e5-4e38-9c76-0c2a1177ee65','送中姪','釋智圓','宋','宋诗','song-poetry','','[]','四明乃舊隱，岑寂宅神仙。',60,'全唐诗/poet.song.7000.json','["四明乃舊隱，岑寂宅神仙。", "寒松糅紫霞，幽巖落飛泉。", "經秋動歸心，荷策登江船。", "澄波漾殘暉，羣峰插晴天。", "窈窈空林下，片石待安禪。"]'),
('7456e43c-e666-48d1-965f-c81972a105df','書山中道士壁','釋智圓','宋','宋诗','song-poetry','','[]','松下消搖自扣扉，相留終日話真機。',64,'全唐诗/poet.song.7000.json','["松下消搖自扣扉，相留終日話真機。", "煙藏花島青牛臥，客散仙房獨鶴歸。", "丹井泉澄天影小，玉壇風冷磬聲微。", "乘閑擬學沖霄術，九土茫茫得者稀。"]'),
('ec629641-e934-4baf-b963-2f4b554ed417','山居偶成','釋智圓','宋','宋诗','song-poetry','','[]','世上諠譁耳不聞，煙蘿深處絕人羣。',64,'全唐诗/poet.song.7000.json','["世上諠譁耳不聞，煙蘿深處絕人羣。", "歲寒弗改憐高柏，舒卷無機愛白雲。", "閑採藥苗醫故疾，旋編紅葉寫新文。", "有人來問居山意，寂寂茆堂日又曛。"]'),
('1a7ec4a2-73ec-4cfe-9cf1-0742432ef44b','湖上秋日','釋智圓','宋','宋诗','song-poetry','','[]','南山雨初霽，東岸夕陽明。',96,'全唐诗/poet.song.7000.json','["南山雨初霽，東岸夕陽明。", "搘笻立回塘，頓覺耳目清。", "臯鶴知秋意，唳風三四聲。", "紅蓼弄秋色，紛紛滿前汀。", "柳徑孤煙白，漁村野水平。", "興盡獨自歸，寥寥掩柴扃。", "新月爲吾上，庭蟬爲吾鳴。", "吾生本無事，對此堪怡情。"]'),
('75e34286-6fdb-4423-8e24-5e2b027cfd60','喻賣松者','釋智圓','宋','宋诗','song-poetry','','[]','莫嫌人不買，人亦愛蒼翠。',60,'全唐诗/poet.song.7000.json','["莫嫌人不買，人亦愛蒼翠。", "卻是歲寒根，難種塵埃地。", "且歸栽澗底，映水成嘉致。", "他年苟合拱，採取不我棄。", "天子建明堂，此爲棟梁備。"]'),
('4da3660d-b321-4d0c-9e9c-c82652c3dd10','秋病','釋智圓','宋','宋诗','song-poetry','','[]','買藥囊無金，伏枕頭有霜。',24,'全唐诗/poet.song.7000.json','["買藥囊無金，伏枕頭有霜。", "夜深不得睡，隙月射秋床。"]'),
('14402811-16e1-499d-9c5f-c52d9aa33cf3','偶作','釋智圓','宋','宋诗','song-poetry','','[]','急急西落日，浩浩東去波。',180,'全唐诗/poet.song.7000.json','["急急西落日，浩浩東去波。", "日落波不停，浮生能幾何。", "青雲身未上，白髮頭已多。", "金印未佩腰，道路成蹉跎。", "一朝忽得志，頓忘貧賤事。", "八珍食方丈，華轂駕天駟。", "民瘼無術醫，貪狠有心恣。", "無何觸天網，禍淫諒不爽。", "餘殃及子孫，豈只身長往。", "寄語求名士，得志莫如此。", "不善宜先知，行道慎莫止。", "仁恕及蒼生，忠貞輔天子。", "好爵終自縻，盛烈垂千祀。", "西日與東流，任彼催寒暑。", "須知君子人，身死名不死。"]');
